fn load_recent_probe_focus_evidence(
    conn: &Connection,
    since_ms: i64,
    limit: usize,
    rows: &mut Vec<FocusEvidenceRow>,
) -> Result<(), String> {
    if !table_exists(conn, "continue_evidence_probes")? {
        return Ok(());
    }
    let mut stmt = conn
        .prepare(
            "SELECT id, completed_at_ms, app_name, app_bundle_id, window_title,
                    browser_url, document_path, privacy_status,
                    accessibility_text_char_count, window_count,
                    privacy_blocked, warnings_json
             FROM continue_evidence_probes
             WHERE completed_at_ms >= ?1
             ORDER BY completed_at_ms DESC, id DESC
             LIMIT ?2",
        )
        .map_err(to_string)?;
    let mapped = stmt
        .query_map(params![since_ms, limit as i64], |row| {
            let privacy_blocked = row.get::<_, i64>(10)? != 0;
            let warnings_json: String = row.get(11)?;
            let mut quality_warnings = parse_string_array(&warnings_json);
            if privacy_blocked {
                push_string_once(&mut quality_warnings, "continue_probe:privacy_blocked");
            }
            Ok(FocusEvidenceRow {
                evidence_id: row.get(0)?,
                evidence_kind: "evidence_probe".to_string(),
                observed_at_ms: row.get(1)?,
                app_name: if privacy_blocked { None } else { row.get(2)? },
                bundle_id: if privacy_blocked { None } else { row.get(3)? },
                window_title: if privacy_blocked { None } else { row.get(4)? },
                browser_url: if privacy_blocked { None } else { row.get(5)? },
                document_path: if privacy_blocked { None } else { row.get(6)? },
                trigger_type: Some("observe_before_decide".to_string()),
                event_type: Some("evidence_probe".to_string()),
                transition_label: None,
                has_active_window: !privacy_blocked
                    && (row.get::<_, Option<String>>(2)?.is_some()
                        || row.get::<_, Option<String>>(4)?.is_some()),
                has_screenshot: false,
                has_ax: row.get::<_, i64>(8)? > 0,
                has_ocr: false,
                has_content_units: false,
                privacy_status: row.get(7)?,
                artifact_id: None,
                artifact_kind: None,
                quality_warnings,
            })
        })
        .map_err(to_string)?;
    for row in mapped {
        rows.push(row.map_err(to_string)?);
    }
    Ok(())
}

fn resolved_surface_from_group(
    group: &[FocusEvidenceRow],
    now_ms: i64,
    latest_non_self_at_ms: Option<i64>,
    latest_heavy_frame_at_ms: Option<i64>,
    latest_event_at_ms: Option<i64>,
) -> ResolvedCurrentSurface {
    let latest = group
        .iter()
        .max_by_key(|row| row.observed_at_ms)
        .expect("surface group must not be empty");
    let best = group
        .iter()
        .max_by(|left, right| {
            focus_row_score(left, now_ms)
                .partial_cmp(&focus_row_score(right, now_ms))
                .unwrap_or(std::cmp::Ordering::Equal)
        })
        .unwrap_or(latest);
    let mut evidence_ids = group
        .iter()
        .map(|row| row.evidence_id.clone())
        .collect::<Vec<_>>();
    evidence_ids.sort();
    evidence_ids.dedup();
    let mut evidence_kinds = group
        .iter()
        .map(|row| row.evidence_kind.clone())
        .collect::<Vec<_>>();
    evidence_kinds.sort();
    evidence_kinds.dedup();
    let mut warnings = group
        .iter()
        .flat_map(|row| row.quality_warnings.clone())
        .collect::<Vec<_>>();
    warnings.sort();
    warnings.dedup();
    let is_self = group.iter().any(|row| {
        is_smalltalk_self_surface(
            row.app_name.as_deref(),
            row.bundle_id.as_deref(),
            row.window_title.as_deref(),
            row.browser_url.as_deref(),
            row.document_path.as_deref(),
        )
    });
    let is_debug = group.iter().any(|row| {
        is_generated_debug_surface(
            row.app_name.as_deref(),
            row.window_title.as_deref(),
            row.browser_url.as_deref(),
            row.document_path.as_deref(),
        )
    });
    if is_self {
        push_string_once(&mut warnings, "current_surface:self_surface_demoted");
    }
    if is_debug {
        push_string_once(
            &mut warnings,
            "current_surface:generated_debug_surface_demoted",
        );
    }
    if evidence_kinds.iter().any(|kind| kind == "ui_event")
        && !evidence_kinds.iter().any(|kind| kind == "frame")
    {
        push_string_once(&mut warnings, "current_surface:event_backed_no_screenshot");
    }
    if latest.browser_url.is_none() && latest.document_path.is_none() {
        push_string_once(&mut warnings, "current_surface:no_direct_url_or_path");
    }
    if latest
        .privacy_status
        .as_deref()
        .is_some_and(|status| privacy_status_is_limited(status))
    {
        push_string_once(&mut warnings, "current_surface:privacy_limited");
    }

    let mut score = focus_row_score(best, now_ms);
    if is_self || is_debug {
        score = (score * 0.20).min(0.24);
    }
    let evidence_quality = if score >= 0.72 {
        "strong"
    } else if score >= 0.48 {
        "medium"
    } else if score > 0.0 {
        "thin"
    } else {
        "unknown"
    }
    .to_string();
    let openability = if latest.browser_url.is_some() || latest.document_path.is_some() {
        "openable"
    } else if evidence_kinds.iter().any(|kind| kind == "frame") || latest.artifact_id.is_some() {
        "frame_fallback"
    } else if latest
        .privacy_status
        .as_deref()
        .is_some_and(|status| privacy_status_is_limited(status))
    {
        "blocked"
    } else {
        "unknown"
    }
    .to_string();
    let reason = if is_self {
        "demoted_smalltalk_self_surface"
    } else if is_debug {
        "demoted_generated_debug_surface"
    } else if evidence_kinds.iter().any(|kind| kind == "ui_event") {
        "selected_recent_event_backed_surface"
    } else if evidence_kinds.iter().any(|kind| kind == "frame") {
        "selected_recent_frame_backed_surface"
    } else {
        "selected_best_available_focus_evidence"
    }
    .to_string();

    ResolvedCurrentSurface {
        surface_id: surface_identity_key(latest),
        artifact_id: latest.artifact_id.clone(),
        app_name: latest.app_name.clone(),
        bundle_id: latest.bundle_id.clone(),
        window_title: latest.window_title.clone(),
        artifact_kind: latest
            .artifact_kind
            .clone()
            .unwrap_or_else(|| artifact_kind_from_focus_row(latest)),
        browser_url: latest.browser_url.clone(),
        document_path: latest.document_path.clone(),
        evidence_ids,
        evidence_kinds,
        observed_at_ms: latest.observed_at_ms,
        latest_non_self_at_ms,
        latest_heavy_frame_at_ms,
        latest_event_at_ms,
        is_self_surface: is_self,
        is_generated_debug_surface: is_debug,
        focus_confidence: round_score(score),
        evidence_quality,
        openability,
        reason,
        warnings,
    }
}

fn no_clear_current_surface(now_ms: i64) -> ResolvedCurrentSurface {
    ResolvedCurrentSurface {
        surface_id: "no-clear-current-surface".to_string(),
        artifact_id: None,
        app_name: None,
        bundle_id: None,
        window_title: None,
        artifact_kind: "unknown".to_string(),
        browser_url: None,
        document_path: None,
        evidence_ids: Vec::new(),
        evidence_kinds: Vec::new(),
        observed_at_ms: now_ms,
        latest_non_self_at_ms: None,
        latest_heavy_frame_at_ms: None,
        latest_event_at_ms: None,
        is_self_surface: false,
        is_generated_debug_surface: false,
        focus_confidence: 0.0,
        evidence_quality: "unknown".to_string(),
        openability: "unknown".to_string(),
        reason: "no_recent_non_self_focus_evidence".to_string(),
        warnings: vec!["current_surface:no_clear_non_self_surface".to_string()],
    }
}

fn focus_row_score(row: &FocusEvidenceRow, now_ms: i64) -> f64 {
    let age_ms = now_ms.saturating_sub(row.observed_at_ms);
    let recency_score = if age_ms <= 2 * 60 * 1000 {
        1.0
    } else if age_ms <= 10 * 60 * 1000 {
        0.75
    } else if age_ms <= 20 * 60 * 1000 {
        0.45
    } else {
        0.18
    };
    let frontmost_or_active_score = if row.has_active_window { 1.0 } else { 0.25 };
    let durable_identity_score = if row.browser_url.is_some() || row.document_path.is_some() {
        1.0
    } else if row.artifact_id.is_some() {
        0.75
    } else if row.bundle_id.is_some() && row.window_title.is_some() {
        0.55
    } else {
        0.25
    };
    let action_signal_score = if row.evidence_kind == "typing_burst" {
        0.95
    } else if row.evidence_kind == "ui_event" {
        row.event_type
            .as_deref()
            .map(high_value_focus_event_score)
            .unwrap_or(0.35)
    } else if row.trigger_type.is_some() || row.transition_label.is_some() {
        0.65
    } else {
        0.35
    };
    let evidence_richness_score = [
        row.has_screenshot,
        row.has_ax,
        row.has_ocr,
        row.has_content_units,
    ]
    .iter()
    .filter(|flag| **flag)
    .count() as f64
        / 4.0;
    let openability_score = if row.browser_url.is_some() || row.document_path.is_some() {
        1.0
    } else if row.artifact_id.is_some() || row.has_screenshot {
        0.45
    } else {
        0.20
    };
    let privacy_safety_score = if row
        .privacy_status
        .as_deref()
        .is_some_and(|status| privacy_status_is_limited(status))
    {
        0.05
    } else {
        1.0
    };
    let mut score = recency_score * 0.30
        + frontmost_or_active_score * 0.20
        + durable_identity_score * 0.15
        + action_signal_score * 0.15
        + evidence_richness_score * 0.10
        + openability_score * 0.05
        + privacy_safety_score * 0.05;
    if is_smalltalk_self_surface(
        row.app_name.as_deref(),
        row.bundle_id.as_deref(),
        row.window_title.as_deref(),
        row.browser_url.as_deref(),
        row.document_path.as_deref(),
    ) || is_generated_debug_surface(
        row.app_name.as_deref(),
        row.window_title.as_deref(),
        row.browser_url.as_deref(),
        row.document_path.as_deref(),
    ) {
        score *= 0.20;
    }
    round_score(score)
}

fn high_value_focus_event_score(event_type: &str) -> f64 {
    let lower = event_type.to_lowercase();
    if contains_any(
        &lower,
        &[
            "key_down:character",
            "key_down:enter",
            "key_down:shortcut",
            "mouse_down",
            "click",
            "app_switch",
            "window_focus",
            "entered_input",
            "continuing_same_task",
        ],
    ) {
        0.90
    } else if contains_any(&lower, &["scroll", "mouse_move"]) {
        0.35
    } else {
        0.55
    }
}

fn focus_summary_from_resolved_surface(
    surface: &ResolvedCurrentSurface,
) -> Option<ContinueFocusSummary> {
    if surface.surface_id == "no-clear-current-surface"
        || surface.is_self_surface
        || surface.is_generated_debug_surface
    {
        return None;
    }
    Some(ContinueFocusSummary {
        frame_id: surface
            .evidence_ids
            .iter()
            .find(|id| id.parse::<i64>().is_ok())
            .cloned()
            .or_else(|| surface.evidence_ids.first().cloned())
            .unwrap_or_else(|| surface.surface_id.clone()),
        artifact_id: surface.artifact_id.clone(),
        artifact_kind: Some(surface.artifact_kind.clone()),
        app_name: surface.app_name.clone(),
        window_title: surface.window_title.clone(),
        title: surface.window_title.clone(),
        browser_url: surface.browser_url.clone(),
        document_path: surface.document_path.clone(),
        captured_at_ms: surface.observed_at_ms,
    })
}

fn build_evidence_freshness_ledger(
    selected_candidate: Option<&ScoredContinueCandidate>,
    current_surface: &ResolvedCurrentSurface,
    now_ms: i64,
) -> EvidenceFreshnessLedger {
    let selected_candidate_evidence_ms = selected_candidate.map(|candidate| {
        candidate
            .target_artifact
            .as_ref()
            .map(|target| target.last_seen_timestamp)
            .unwrap_or_default()
            .max(
                candidate
                    .last_meaningful_action
                    .as_ref()
                    .map(|action| action.created_at_ms)
                    .unwrap_or_default(),
            )
    });
    let selected_candidate_age_ms =
        selected_candidate_evidence_ms.map(|ts| now_ms.saturating_sub(ts));
    let latest_non_self = current_surface.latest_non_self_at_ms;
    let has_newer_non_self_than_selected = latest_non_self
        .zip(selected_candidate_evidence_ms)
        .is_some_and(|(latest, selected)| latest > selected);
    let selected_target_lacks_direct_opener = selected_candidate
        .and_then(|candidate| candidate.target_artifact.as_ref())
        .is_some_and(|target| {
            target.openability == "frame_fallback"
                && target.browser_url.is_none()
                && target.document_path.is_none()
        });
    let stale_selected_target = has_newer_non_self_than_selected
        && selected_target_lacks_direct_opener
        && selected_candidate_age_ms.is_some_and(|age| age > 10 * 60 * 1000);
    let mut warnings = current_surface.warnings.clone();
    if has_newer_non_self_than_selected {
        push_string_once(
            &mut warnings,
            "evidence_freshness:newer_non_self_evidence_than_selected_target",
        );
    }
    if stale_selected_target {
        push_string_once(
            &mut warnings,
            "evidence_freshness:stale_frame_fallback_selected_target",
        );
    }
    let latest_any = [
        Some(current_surface.observed_at_ms),
        current_surface.latest_heavy_frame_at_ms,
        current_surface.latest_event_at_ms,
        latest_non_self,
    ]
    .into_iter()
    .flatten()
    .max();
    let latest_fresh_openable_ms = if current_surface.openability == "openable"
        && !current_surface.is_self_surface
        && !current_surface.is_generated_debug_surface
    {
        Some(current_surface.observed_at_ms)
    } else {
        None
    };
    let decision_watermark_ms = [latest_any, selected_candidate_evidence_ms, Some(now_ms)]
        .into_iter()
        .flatten()
        .max()
        .unwrap_or(now_ms);
    let freshness_reason = if stale_selected_target {
        "selected_target_stale_against_newer_non_self_evidence"
    } else if has_newer_non_self_than_selected {
        "newer_non_self_evidence_recorded"
    } else {
        "selected_target_not_stale_against_current_surface"
    }
    .to_string();

    EvidenceFreshnessLedger {
        decision_watermark_ms,
        latest_any_evidence_ms: latest_any,
        latest_non_self_evidence_ms: latest_non_self,
        latest_heavy_frame_ms: current_surface.latest_heavy_frame_at_ms,
        latest_event_ms: current_surface.latest_event_at_ms,
        latest_fresh_openable_ms,
        selected_candidate_evidence_ms,
        selected_candidate_age_ms,
        has_newer_non_self_than_selected,
        stale_selected_target,
        freshness_reason,
        warnings,
    }
}

fn derive_active_current_work_unresolved(
    current_focus: Option<&ContinueFocusSummary>,
    current_surface: &ResolvedCurrentSurface,
    app_activity: &ContinueAppActivityIntelligence,
    current_artifact: Option<&ScorerArtifact>,
    event_backed_links: Option<&EventBackedCurrentWorkLinks>,
    now_ms: i64,
) -> Option<ActiveCurrentWorkUnresolved> {
    if current_surface.surface_id == "no-clear-current-surface"
        || current_surface.is_self_surface
        || current_surface.is_generated_debug_surface
        || is_smalltalk_self_surface(
            current_surface.app_name.as_deref(),
            current_surface.bundle_id.as_deref(),
            current_surface.window_title.as_deref(),
            current_surface.browser_url.as_deref(),
            current_surface.document_path.as_deref(),
        )
    {
        return None;
    }
    if now_ms.saturating_sub(current_surface.observed_at_ms) > CURRENT_FOCUS_RECENT_WINDOW_MS {
        return None;
    }

    let activity = activity_classification_for_current_surface(current_surface, app_activity);
    let event_backed = current_surface.evidence_kinds.iter().any(|kind| {
        matches!(
            kind.as_str(),
            "ui_event" | "typing_burst" | "window_snapshot" | "current_surface"
        )
    });
    let has_meaningful_activity = event_backed
        || activity.is_some_and(|classification| {
            classification.continuation_role == "needs_fresh_capture"
                || matches!(
                    classification.activity_intent.as_str(),
                    "editing" | "composing" | "running_command" | "reviewing_output"
                )
                || classification.work_value_score >= 0.55
        });
    let weak_domain = is_known_weak_current_work_domain(
        current_surface.app_name.as_deref(),
        current_surface.bundle_id.as_deref(),
        current_surface.window_title.as_deref(),
    );
    if !has_meaningful_activity && !weak_domain {
        return None;
    }

    let has_openable_target = surface_has_openable_target(current_surface, current_artifact);
    let identity_confidence =
        active_current_work_identity_confidence(current_surface, current_artifact, event_backed);
    if has_openable_target && identity_confidence >= 0.70 {
        return None;
    }

    let has_fresh_heavy_frame = current_surface.latest_heavy_frame_at_ms.is_some_and(|ts| {
        current_surface.observed_at_ms.saturating_sub(ts) <= STALE_TARGET_MIN_DELTA_MS
    });
    let has_human_readable_title = current_surface
        .window_title
        .as_deref()
        .is_some_and(human_readable_surface_title);
    let mut missing_evidence = Vec::new();
    if current_surface.artifact_id.is_none() && current_artifact.is_none() {
        push_string_once(
            &mut missing_evidence,
            "missing_current_work_target_identity",
        );
    }
    if !has_openable_target {
        push_string_once(
            &mut missing_evidence,
            "missing_current_work_openable_target",
        );
    }
    if !has_fresh_heavy_frame {
        push_string_once(
            &mut missing_evidence,
            "missing_fresh_heavy_frame_for_current_focus",
        );
    }
    if !has_human_readable_title {
        push_string_once(&mut missing_evidence, "missing_current_work_visible_text");
    }
    if weak_domain && current_surface.artifact_id.is_none() && !has_openable_target {
        push_string_once(
            &mut missing_evidence,
            "missing_current_work_thread_or_document_id",
        );
    }

    let mut warnings = Vec::new();
    if event_backed && !has_fresh_heavy_frame {
        push_string_once(
            &mut warnings,
            "active_current_work_unresolved:event_backed_only",
        );
    }
    if !has_openable_target {
        push_string_once(&mut warnings, "active_current_work_unresolved:not_openable");
    }
    if weak_domain {
        push_string_once(&mut warnings, "active_current_work_unresolved:weak_domain");
    }
    if !has_human_readable_title || current_surface.evidence_quality == "thin" {
        push_string_once(
            &mut warnings,
            "active_current_work_unresolved:thin_accessibility",
        );
    }

    let frame_id = current_focus
        .map(|focus| focus.frame_id.clone())
        .or_else(|| {
            current_surface
                .evidence_ids
                .iter()
                .find(|id| id.parse::<i64>().is_ok())
                .cloned()
        });
    let mut event_ids = current_surface
        .evidence_ids
        .iter()
        .filter(|id| Some((*id).as_str()) != frame_id.as_deref())
        .take(12)
        .cloned()
        .collect::<Vec<_>>();
    event_ids.sort();
    event_ids.dedup();

    Some(ActiveCurrentWorkUnresolved {
        id: format!(
            "active-current-work-unresolved-{}",
            stable_hash(
                format!(
                    "{}:{}:{}:{}",
                    current_surface.surface_id,
                    current_surface.observed_at_ms,
                    current_surface.artifact_id.as_deref().unwrap_or("none"),
                    activity
                        .map(|classification| classification.id.as_str())
                        .unwrap_or("none")
                )
                .as_bytes()
            )
        ),
        observed_at_ms: current_surface.observed_at_ms,
        app_name: current_surface.app_name.clone(),
        bundle_id: current_surface.bundle_id.clone(),
        window_title: current_surface.window_title.clone(),
        artifact_id: current_surface
            .artifact_id
            .clone()
            .or_else(|| current_artifact.map(|artifact| artifact.id.clone()))
            .or_else(|| event_backed_links.map(|links| links.artifact_id.clone())),
        observation_id: event_backed_links.and_then(|links| links.observation_id.clone()),
        frame_id,
        event_ids,
        task_action_ids: event_backed_links
            .map(|links| links.task_action_ids.clone())
            .unwrap_or_default(),
        event_backed,
        has_fresh_heavy_frame,
        has_human_readable_title,
        has_openable_target,
        evidence_quality: active_current_work_evidence_quality(
            current_surface,
            current_artifact,
            event_backed,
            has_human_readable_title,
        ),
        identity_confidence,
        activity_hint: activity.map(|classification| classification.activity_intent.clone()),
        unresolved_reason: if has_openable_target {
            "current_work_identity_not_strong_enough".to_string()
        } else {
            "fresh_current_work_not_openable".to_string()
        },
        missing_evidence,
        warnings,
    })
}

fn activity_classification_for_current_surface<'a>(
    current_surface: &ResolvedCurrentSurface,
    app_activity: &'a ContinueAppActivityIntelligence,
) -> Option<&'a ContinueActivityClassification> {
    app_activity
        .classifications
        .iter()
        .filter(|classification| {
            classification
                .artifact_id
                .as_deref()
                .zip(current_surface.artifact_id.as_deref())
                .is_some_and(|(left, right)| left == right)
                || app_activity.segments.iter().any(|segment| {
                    segment.id == classification.segment_id
                        && segment.features.current_surface_match
                })
        })
        .max_by(activity_classification_rank)
}

fn surface_has_openable_target(
    current_surface: &ResolvedCurrentSurface,
    current_artifact: Option<&ScorerArtifact>,
) -> bool {
    current_surface.openability == "openable"
        || current_surface.browser_url.is_some()
        || current_surface.document_path.is_some()
        || current_artifact.is_some_and(candidate_target_is_directly_openable)
}

fn active_current_work_identity_confidence(
    current_surface: &ResolvedCurrentSurface,
    current_artifact: Option<&ScorerArtifact>,
    event_backed: bool,
) -> f64 {
    if current_surface.is_self_surface || current_surface.is_generated_debug_surface {
        return 0.0;
    }
    let confidence = if current_surface.browser_url.is_some()
        || current_surface.document_path.is_some()
        || current_artifact.is_some_and(|artifact| {
            artifact.browser_url.is_some()
                || artifact.document_path.is_some()
                || artifact.openability == "openable"
                || artifact.evidence_quality == "strong"
        }) {
        0.78
    } else if current_surface.artifact_id.is_some()
        || current_surface.latest_heavy_frame_at_ms.is_some()
    {
        0.65
    } else if event_backed
        && (current_surface.app_name.is_some() || current_surface.bundle_id.is_some())
        && current_surface.window_title.is_some()
    {
        0.45
    } else if event_backed {
        0.35
    } else {
        0.0
    };
    if current_surface.browser_url.is_none() && current_surface.document_path.is_none() {
        round_score(f64::min(confidence, 0.65))
    } else {
        round_score(confidence)
    }
}

fn active_current_work_evidence_quality(
    current_surface: &ResolvedCurrentSurface,
    current_artifact: Option<&ScorerArtifact>,
    event_backed: bool,
    has_human_readable_title: bool,
) -> String {
    if current_surface.app_name.is_none() && current_surface.bundle_id.is_none() {
        return "unknown".to_string();
    }
    if current_artifact.is_some()
        && has_human_readable_title
        && event_backed
        && current_surface.latest_heavy_frame_at_ms.is_some()
    {
        "medium".to_string()
    } else if event_backed || has_human_readable_title {
        "thin".to_string()
    } else {
        "unknown".to_string()
    }
}

fn human_readable_surface_title(title: &str) -> bool {
    let trimmed = title.trim();
    if trimmed.len() < 3 {
        return false;
    }
    let lower = trimmed.to_ascii_lowercase();
    !contains_any(
        &lower,
        &[
            "unknown", "untitled", "private", "redacted", "window", "no title",
        ],
    )
}

fn is_known_weak_current_work_domain(
    app_name: Option<&str>,
    bundle_id: Option<&str>,
    window_title: Option<&str>,
) -> bool {
    let haystack = [app_name, bundle_id, window_title]
        .into_iter()
        .flatten()
        .collect::<Vec<_>>()
        .join(" ")
        .to_ascii_lowercase();
    contains_any(
        &haystack,
        &[
            "codex",
            "com.openai.codex",
            "claude code",
            "cursor",
            "visual studio code",
            "vscode",
            "com.microsoft.vscode",
            "xcode",
            "intellij",
            "jetbrains",
            "terminal",
            "iterm",
            "warp",
            "agent",
        ],
    )
}

fn active_current_work_for_model(
    fact: &ActiveCurrentWorkUnresolved,
    now_ms: i64,
) -> ActiveCurrentWorkUnresolvedForModel {
    ActiveCurrentWorkUnresolvedForModel {
        present: true,
        observed_age_ms: now_ms.saturating_sub(fact.observed_at_ms),
        app_name: fact.app_name.clone(),
        artifact_id_present: fact.artifact_id.is_some(),
        observation_id_present: fact.observation_id.is_some(),
        task_action_count: fact.task_action_ids.len(),
        event_backed: fact.event_backed,
        has_fresh_heavy_frame: fact.has_fresh_heavy_frame,
        has_human_readable_title: fact.has_human_readable_title,
        has_openable_target: fact.has_openable_target,
        evidence_quality: fact.evidence_quality.clone(),
        identity_confidence: fact.identity_confidence,
        activity_hint: fact.activity_hint.clone(),
        unresolved_reason: fact.unresolved_reason.clone(),
        missing_evidence: fact.missing_evidence.iter().take(8).cloned().collect(),
        warnings: fact.warnings.iter().take(8).cloned().collect(),
    }
}

fn p0_quality_signals_for_decision(
    active_current_work_unresolved: Option<&ActiveCurrentWorkUnresolved>,
    stale_target_suppression: &StaleTargetSuppressionAudit,
    selected_workstream: Option<&ScorerWorkstream>,
    candidates: &[ScoredContinueCandidate],
    public_return_candidate: Option<&ScoredContinueCandidate>,
    continue_output_mode: &ContinueOutputMode,
    validation_status: &str,
    missing_evidence: &[String],
    warnings: &[String],
) -> P0QualitySignals {
    let fresh_current_work_candidate_id = candidates
        .iter()
        .find(|candidate| candidate.candidate_kind == "continue_current_work")
        .map(|candidate| candidate.id.clone());
    let fresh_current_work_artifact_id = active_current_work_unresolved
        .and_then(|fact| fact.artifact_id.clone())
        .or_else(|| {
            fresh_current_work_candidate_id
                .as_ref()
                .and_then(|candidate_id| {
                    candidates
                        .iter()
                        .find(|candidate| &candidate.id == candidate_id)
                        .and_then(|candidate| {
                            candidate
                                .target_artifact
                                .as_ref()
                                .map(|artifact| artifact.id.clone())
                        })
                })
        });
    let selected_target_older_than_current_focus = stale_target_suppression
        .delta_ms
        .is_some_and(|delta| delta >= STALE_TARGET_MIN_DELTA_MS);
    let return_target_openable = public_return_candidate
        .and_then(candidate_public_target_artifact)
        .is_some_and(candidate_target_is_directly_openable);
    let support_branch_promoted = public_return_candidate
        .and_then(|candidate| {
            let target_id =
                candidate_public_target_artifact(candidate).map(|target| target.id.as_str())?;
            let workstream = selected_workstream
                .filter(|workstream| workstream.id == candidate.workstream_id)
                .or_else(|| {
                    selected_workstream
                        .filter(|workstream| workstream.id == candidate.workstream_id)
                });
            workstream.and_then(|workstream| durable_role_for_target(workstream, target_id))
        })
        .is_some_and(|role| matches!(role, "branch" | "support_source"));
    let thin_mode_truthful = !return_target_openable
        && (matches!(
            continue_output_mode,
            ContinueOutputMode::ThinContinue | ContinueOutputMode::NoClearContinuation
        ) || validation_status == "thin_evidence"
            || warnings
                .iter()
                .any(|warning| warning == "stale_return_target_suppressed:newer_current_focus"));
    let thin_mode_truthful = if return_target_openable {
        true
    } else {
        thin_mode_truthful
    };
    let mut missing_current_work_evidence = active_current_work_unresolved
        .map(|fact| fact.missing_evidence.clone())
        .unwrap_or_default();
    for item in missing_evidence {
        if item.starts_with("missing_current_work") || item.contains("fresh_heavy_frame") {
            push_string_once(&mut missing_current_work_evidence, item);
        }
    }
    missing_current_work_evidence.sort();
    missing_current_work_evidence.dedup();

    P0QualitySignals {
        fresh_current_work_present: active_current_work_unresolved.is_some()
            || fresh_current_work_candidate_id.is_some(),
        fresh_current_work_artifact_id,
        fresh_current_work_candidate_id,
        selected_target_older_than_current_focus,
        stale_target_suppressed: stale_target_suppression.suppressed,
        support_branch_promoted,
        return_target_openable,
        thin_mode_truthful,
        missing_current_work_evidence,
    }
}

fn evaluate_stale_target_suppression(
    ctx: &StaleTargetSuppressionContext<'_>,
) -> StaleTargetSuppressionAudit {
    let current_focus_timestamp_ms = ctx
        .current_focus
        .map(|focus| focus.captured_at_ms)
        .or(Some(ctx.current_surface.observed_at_ms));
    let selected_target_timestamp_ms = ctx
        .selected
        .map(selected_candidate_target_evidence_timestamp);
    let delta_ms = current_focus_timestamp_ms
        .zip(selected_target_timestamp_ms)
        .map(|(focus_ts, target_ts)| focus_ts.saturating_sub(target_ts));
    let selected_target_artifact_id = ctx
        .selected
        .and_then(candidate_public_target_artifact)
        .map(|artifact| artifact.id.clone());
    let latest_non_self_after_target_ms = ctx
        .freshness_ledger
        .latest_non_self_evidence_ms
        .zip(selected_target_timestamp_ms)
        .and_then(|(latest, target_ts)| (latest > target_ts).then_some(latest));
    let confidence_after = round_score(f64::min(ctx.confidence, 0.45));
    let mut audit = StaleTargetSuppressionAudit {
        evaluated: true,
        suppressed: false,
        reason: "not_evaluated".to_string(),
        current_focus_timestamp_ms,
        selected_target_timestamp_ms,
        delta_ms,
        current_focus_artifact_id: ctx
            .current_focus
            .and_then(|focus| focus.artifact_id.clone())
            .or_else(|| ctx.current_surface.artifact_id.clone()),
        selected_target_artifact_id,
        latest_non_self_evidence_after_target_ms: latest_non_self_after_target_ms,
        confidence_before: round_score(ctx.confidence),
        confidence_after: round_score(ctx.confidence),
    };

    let Some(candidate) = ctx.selected else {
        audit.reason = "no_selected_candidate".to_string();
        return audit;
    };
    let Some(target) = candidate_public_target_artifact(candidate) else {
        audit.reason = "selected_candidate_has_no_public_target".to_string();
        return audit;
    };
    let Some(focus_ts) = current_focus_timestamp_ms else {
        audit.reason = "no_current_focus_timestamp".to_string();
        return audit;
    };
    let Some(target_ts) = selected_target_timestamp_ms else {
        audit.reason = "no_selected_target_timestamp".to_string();
        return audit;
    };
    if ctx.current_surface.is_self_surface
        || ctx.current_surface.is_generated_debug_surface
        || is_smalltalk_self_surface(
            ctx.current_focus
                .and_then(|focus| focus.app_name.as_deref()),
            None,
            ctx.current_focus
                .and_then(|focus| focus.window_title.as_deref()),
            ctx.current_focus
                .and_then(|focus| focus.browser_url.as_deref()),
            ctx.current_focus
                .and_then(|focus| focus.document_path.as_deref()),
        )
    {
        audit.reason = "current_focus_is_self_or_debug".to_string();
        return audit;
    }
    let Some(active_current_work) = ctx.active_current_work_unresolved else {
        audit.reason = "no_active_current_work_unresolved".to_string();
        return audit;
    };
    if active_current_work.has_openable_target && active_current_work.identity_confidence >= 0.70 {
        audit.reason = "active_current_work_already_openable".to_string();
        return audit;
    }
    if ctx.requested_at_ms.saturating_sub(focus_ts) > CURRENT_FOCUS_RECENT_WINDOW_MS {
        audit.reason = "current_focus_not_recent".to_string();
        return audit;
    }
    if focus_ts.saturating_sub(target_ts) < STALE_TARGET_MIN_DELTA_MS {
        audit.reason = "selected_target_not_materially_older".to_string();
        return audit;
    }
    if !ctx.freshness_ledger.has_newer_non_self_than_selected
        || latest_non_self_after_target_ms.is_none()
    {
        audit.reason = "no_newer_non_self_evidence_after_target".to_string();
        return audit;
    }
    if !candidate_target_is_directly_openable(target) {
        audit.reason = "selected_target_not_directly_openable".to_string();
        return audit;
    }
    if !current_surface_differs_from_selected_target(ctx, target) {
        audit.reason = "current_focus_matches_selected_target".to_string();
        return audit;
    }
    if !active_current_work_has_meaningful_signal(active_current_work) {
        audit.reason = "active_current_work_not_meaningful".to_string();
        return audit;
    }
    if selected_target_has_fresh_reconfirmation(candidate, ctx.selected_workstream, focus_ts) {
        audit.reason = "selected_target_has_fresh_reconfirmation".to_string();
        return audit;
    }
    if !final_decision_evidence_is_thin(
        ctx.confidence,
        ctx.validation_status,
        ctx.continue_output_mode,
        ctx.warnings,
    ) {
        audit.reason = "decision_confidence_strong_enough".to_string();
        return audit;
    }

    audit.suppressed = true;
    audit.reason = "newer_current_focus".to_string();
    audit.confidence_after = confidence_after;
    audit
}

fn candidate_public_target_artifact(
    candidate: &ScoredContinueCandidate,
) -> Option<&ScorerArtifact> {
    candidate
        .resume_work_target
        .as_ref()
        .or(candidate.target_artifact.as_ref())
}

fn selected_candidate_target_evidence_timestamp(candidate: &ScoredContinueCandidate) -> i64 {
    let target_ids = [
        candidate
            .target_artifact
            .as_ref()
            .map(|target| target.id.as_str()),
        candidate
            .resume_work_target
            .as_ref()
            .map(|target| target.id.as_str()),
    ];
    let action_timestamp = candidate
        .last_meaningful_action
        .as_ref()
        .and_then(|action| {
            target_ids
                .iter()
                .flatten()
                .any(|target_id| {
                    action.artifact_id.as_deref() == Some(*target_id)
                        || action.secondary_artifact_id.as_deref() == Some(*target_id)
                })
                .then_some(action.created_at_ms)
        });
    [
        candidate
            .target_artifact
            .as_ref()
            .map(|target| target.last_seen_timestamp),
        candidate
            .resume_work_target
            .as_ref()
            .map(|target| target.last_seen_timestamp),
        action_timestamp,
    ]
    .into_iter()
    .flatten()
    .max()
    .unwrap_or_default()
}

fn candidate_target_is_directly_openable(target: &ScorerArtifact) -> bool {
    target.browser_url.is_some()
        || target.document_path.is_some()
        || target.openability == "openable"
}

fn current_surface_differs_from_selected_target(
    ctx: &StaleTargetSuppressionContext<'_>,
    target: &ScorerArtifact,
) -> bool {
    if ctx
        .current_focus
        .and_then(|focus| focus.artifact_id.as_deref())
        .or(ctx.current_surface.artifact_id.as_deref())
        .is_some_and(|focus_id| focus_id == target.id)
    {
        return false;
    }
    if ctx
        .current_focus
        .and_then(|focus| focus.artifact_id.as_deref())
        .or(ctx.current_surface.artifact_id.as_deref())
        .is_some()
    {
        return true;
    }
    let current_text = normalized_surface_text([
        ctx.current_focus
            .and_then(|focus| focus.app_name.as_deref()),
        ctx.current_focus
            .and_then(|focus| focus.window_title.as_deref()),
        ctx.current_focus.and_then(|focus| focus.title.as_deref()),
        ctx.current_focus
            .and_then(|focus| focus.browser_url.as_deref()),
        ctx.current_focus
            .and_then(|focus| focus.document_path.as_deref()),
        ctx.current_surface.app_name.as_deref(),
        ctx.current_surface.window_title.as_deref(),
        ctx.current_surface.browser_url.as_deref(),
        ctx.current_surface.document_path.as_deref(),
    ]);
    let target_text = normalized_surface_text([
        Some(target.artifact_kind.as_str()),
        target.display_title.as_deref(),
        target.browser_url.as_deref(),
        target.document_path.as_deref(),
    ]);
    if current_text.is_empty() || target_text.is_empty() {
        return false;
    }
    !surface_texts_match(&current_text, &target_text)
}

fn normalized_surface_text<'a>(values: impl IntoIterator<Item = Option<&'a str>>) -> String {
    values
        .into_iter()
        .flatten()
        .map(|value| value.to_ascii_lowercase())
        .collect::<Vec<_>>()
        .join(" ")
        .split_whitespace()
        .collect::<Vec<_>>()
        .join(" ")
}

fn surface_texts_match(left: &str, right: &str) -> bool {
    if left == right {
        return true;
    }
    let compact_match =
        |needle: &str, haystack: &str| needle.len() >= 8 && haystack.contains(needle);
    compact_match(left, right) || compact_match(right, left)
}

fn selected_target_has_fresh_reconfirmation(
    candidate: &ScoredContinueCandidate,
    selected_workstream: Option<&ScorerWorkstream>,
    current_focus_timestamp_ms: i64,
) -> bool {
    selected_candidate_target_evidence_timestamp(candidate) >= current_focus_timestamp_ms
        || selected_workstream.is_some_and(|workstream| {
            has_explicit_current_focus_return_evidence(candidate, workstream)
        })
        || candidate_is_completed_progress(candidate)
        || candidate.feedback_prior_score >= 0.35
}

fn final_decision_evidence_is_thin(
    confidence: f64,
    validation_status: &str,
    continue_output_mode: &ContinueOutputMode,
    warnings: &[String],
) -> bool {
    confidence < 0.60
        || !matches!(continue_output_mode, ContinueOutputMode::StrongContinue)
        || matches!(
            validation_status,
            "thin_evidence" | "fallback" | "rejected" | "soft_recovered"
        )
        || warnings.iter().any(|warning| {
            warning == "current_focus_differs_from_return_target"
                || warning == "current_focus_mismatch"
                || warning.starts_with("thin_evidence")
                || warning.starts_with("micro_inference_validation_failed:")
                || warning.starts_with("micro_inference_failed:")
                || warning.contains("need_more_evidence")
                || warning.contains("newer_non_self_evidence_than_selected_target")
        })
}

fn current_surface_for_model(
    surface: &ResolvedCurrentSurface,
    now_ms: i64,
) -> Option<CurrentSurfaceForModel> {
    if surface.surface_id == "no-clear-current-surface" || surface.is_self_surface {
        return None;
    }
    Some(CurrentSurfaceForModel {
        artifact_kind: surface.artifact_kind.clone(),
        title: surface.window_title.as_deref().map(safe_model_label),
        evidence_kind: if surface.evidence_kinds.iter().any(|kind| kind == "ui_event") {
            "event_backed".to_string()
        } else if surface.evidence_kinds.iter().any(|kind| kind == "frame") {
            "frame_backed".to_string()
        } else {
            "mixed".to_string()
        },
        has_direct_url: surface.browser_url.is_some(),
        has_direct_path: surface.document_path.is_some(),
        observed_age_ms: now_ms.saturating_sub(surface.observed_at_ms),
        evidence_quality: surface.evidence_quality.clone(),
        openability: surface.openability.clone(),
        warnings: surface.warnings.iter().take(8).cloned().collect(),
    })
}

fn model_safe_current_focus(focus: Option<&ContinueFocusSummary>) -> Option<ContinueFocusSummary> {
    focus.cloned().map(|mut focus| {
        focus.title = focus.title.as_deref().map(safe_model_label);
        focus.window_title = focus.window_title.as_deref().map(safe_model_label);
        focus.browser_url = None;
        focus.document_path = None;
        focus
    })
}

fn frame_has_rows(conn: &Connection, table: &str, frame_id: &str) -> Result<bool, String> {
    if !table_exists(conn, table)? {
        return Ok(false);
    }
    let count: i64 = conn
        .query_row(
            &format!("SELECT COUNT(*) FROM {} WHERE frame_id = ?1", table),
            params![frame_id],
            |row| row.get(0),
        )
        .map_err(to_string)?;
    Ok(count > 0)
}

fn load_frame_quality_warning_types(
    conn: &Connection,
    frame_id: &str,
) -> Result<Vec<String>, String> {
    if !table_exists(conn, "frame_quality_warnings")? {
        return Ok(Vec::new());
    }
    let mut stmt = conn
        .prepare(
            "SELECT warning_type
             FROM frame_quality_warnings
             WHERE frame_id = ?1
             ORDER BY created_at_ms DESC, id DESC
             LIMIT 12",
        )
        .map_err(to_string)?;
    let mapped = stmt
        .query_map(params![frame_id], |row| row.get::<_, String>(0))
        .map_err(to_string)?;
    let mut warnings = Vec::new();
    for warning in mapped {
        warnings.push(warning.map_err(to_string)?);
    }
    Ok(warnings)
}

fn is_smalltalk_self_surface(
    app_name: Option<&str>,
    bundle_id: Option<&str>,
    window_title: Option<&str>,
    browser_url: Option<&str>,
    document_path: Option<&str>,
) -> bool {
    let surface = format!(
        "{} {} {} {} {}",
        app_name.unwrap_or(""),
        bundle_id.unwrap_or(""),
        window_title.unwrap_or(""),
        browser_url.unwrap_or(""),
        document_path.unwrap_or("")
    )
    .to_lowercase();
    contains_any(
        &surface,
        &[
            "smalltalk continue",
            "com.smalltalk.app",
            "usesmalltalk",
            "tauri dev",
            "localhost:1420",
        ],
    ) || app_name.is_some_and(|value| value.trim().eq_ignore_ascii_case("smalltalk"))
}

fn is_generated_debug_surface(
    app_name: Option<&str>,
    window_title: Option<&str>,
    browser_url: Option<&str>,
    document_path: Option<&str>,
) -> bool {
    let surface = format!(
        "{} {} {} {}",
        app_name.unwrap_or(""),
        window_title.unwrap_or(""),
        browser_url.unwrap_or(""),
        document_path.unwrap_or("")
    )
    .to_lowercase();
    contains_any(
        &surface,
        &[
            "continue_outputs",
            "resume_query_exports",
            "cloud_resume_exports",
            "safe-ai-exports",
            "output/session-",
            "target/debug",
            "audit_manifest",
            "audit manifest",
            "sqlite_snapshot",
            "final_decision.json",
            "candidate_pack.json",
            "micro_inference_request.json",
            "continue_audit",
        ],
    )
}

fn is_user_work_surface(row: &FocusEvidenceRow) -> bool {
    if is_smalltalk_self_surface(
        row.app_name.as_deref(),
        row.bundle_id.as_deref(),
        row.window_title.as_deref(),
        row.browser_url.as_deref(),
        row.document_path.as_deref(),
    ) || is_generated_debug_surface(
        row.app_name.as_deref(),
        row.window_title.as_deref(),
        row.browser_url.as_deref(),
        row.document_path.as_deref(),
    ) || row
        .privacy_status
        .as_deref()
        .is_some_and(privacy_status_is_limited)
    {
        return false;
    }
    matches!(
        artifact_kind_from_focus_row(row).as_str(),
        "browser_tab"
            | "chat_conversation"
            | "code_editor"
            | "terminal"
            | "pdf"
            | "messaging"
            | "notes_doc"
            | "finder"
    )
}

fn surface_identity_key(row: &FocusEvidenceRow) -> String {
    if let Some(url) = row
        .browser_url
        .as_deref()
        .filter(|value| !value.trim().is_empty())
    {
        return format!("url:{}", stable_hash(url.as_bytes()));
    }
    if let Some(path) = row
        .document_path
        .as_deref()
        .filter(|value| !value.trim().is_empty())
    {
        return format!("path:{}", stable_hash(path.as_bytes()));
    }
    if let Some(artifact_id) = row.artifact_id.as_deref() {
        return format!("artifact:{}", artifact_id);
    }
    let bundle = row.bundle_id.as_deref().unwrap_or("");
    let title = row.window_title.as_deref().unwrap_or("");
    if !bundle.is_empty() || !title.is_empty() {
        return format!(
            "window:{}",
            stable_hash(format!("{}:{}", bundle, title).as_bytes())
        );
    }
    let app = row.app_name.as_deref().unwrap_or("");
    format!(
        "surface:{}",
        stable_hash(format!("{}:{}:{}", app, title, row.evidence_id).as_bytes())
    )
}

fn artifact_kind_from_focus_row(row: &FocusEvidenceRow) -> String {
    if let Some(kind) = row.artifact_kind.as_deref() {
        return kind.to_string();
    }
    let surface = format!(
        "{} {} {} {} {}",
        row.app_name.as_deref().unwrap_or(""),
        row.bundle_id.as_deref().unwrap_or(""),
        row.window_title.as_deref().unwrap_or(""),
        row.browser_url.as_deref().unwrap_or(""),
        row.document_path.as_deref().unwrap_or("")
    )
    .to_lowercase();
    if row.browser_url.is_some()
        || contains_any(&surface, &["chrome", "safari", "arc", "helium", "browser"])
    {
        "browser_tab".to_string()
    } else if contains_any(
        &surface,
        &["cursor", "visual studio code", "vscode", "xcode"],
    ) {
        "code_editor".to_string()
    } else if contains_any(&surface, &["terminal", "iterm", "warp"]) {
        "terminal".to_string()
    } else if contains_any(&surface, &["slack", "discord", "messages", "whatsapp"]) {
        "messaging".to_string()
    } else if row
        .document_path
        .as_deref()
        .is_some_and(|path| path.to_lowercase().ends_with(".pdf"))
        || contains_any(&surface, &["preview", ".pdf"])
    {
        "pdf".to_string()
    } else if contains_any(&surface, &["finder"]) {
        "finder".to_string()
    } else if contains_any(&surface, &["notes", "notion", "docs"]) {
        "notes_doc".to_string()
    } else {
        "unknown".to_string()
    }
}

fn privacy_status_is_limited(status: &str) -> bool {
    contains_any(
        status,
        &["private", "blocked", "excluded", "sensitive", "redacted"],
    )
}

fn continue_cache_bypass_reasons(
    conn: &Connection,
    session_id: Option<&str>,
    current_watermark: &ContinueEvidenceWatermark,
    micro_inference_requested: bool,
) -> Result<Vec<String>, String> {
    if !table_exists(conn, "continue_decisions")? {
        return Ok(Vec::new());
    }
    let candidate = conn
        .query_row(
            "SELECT d.id, d.requested_at_ms
             FROM continue_decisions d
             LEFT JOIN frames f ON CAST(f.id AS TEXT) = d.current_focus_frame_id
             WHERE d.evidence_watermark_hash = ?1
               AND (?2 IS NULL OR f.session_id = ?2 OR d.current_focus_frame_id IS NULL)
               AND COALESCE(d.latest_boundary_revision, 0) = ?3
               AND COALESCE(d.micro_inference_requested, 0) = ?4
             ORDER BY d.requested_at_ms DESC
             LIMIT 1",
            params![
                current_watermark.hash,
                session_id,
                current_watermark.latest_boundary_revision.unwrap_or(0),
                if micro_inference_requested {
                    1_i64
                } else {
                    0_i64
                }
            ],
            |row| Ok((row.get::<_, String>(0)?, row.get::<_, i64>(1)?)),
        )
        .optional()
        .map_err(to_string)?;
    let Some((decision_id, requested_at_ms)) = candidate else {
        return Ok(Vec::new());
    };

    let mut reasons = Vec::new();
    let latest_feedback_ms = latest_continue_feedback_watermark_ms(conn)?;
    if latest_feedback_ms.is_some_and(|timestamp| timestamp > requested_at_ms) {
        reasons.push("feedback_newer_than_cached_decision".to_string());
    }

    if pending_open_feedback_exists_for_decision(conn, &decision_id, requested_at_ms)? {
        reasons.push("continue_open_pending_feedback".to_string());
    }

    let latest_boundary_revision = current_watermark.latest_boundary_revision.unwrap_or(0);
    let newer_boundary = conn
        .query_row(
            "SELECT EXISTS(
               SELECT 1 FROM continue_boundary_revisions
               WHERE revision > ?1
             )",
            params![latest_boundary_revision],
            |row| row.get::<_, i64>(0),
        )
        .optional()
        .map_err(to_string)?
        .unwrap_or(0)
        != 0;
    if newer_boundary {
        reasons.push("feedback_policy_version_changed".to_string());
    }

    Ok(reasons)
}

pub fn latest_continue_feedback_watermark_ms(conn: &Connection) -> Result<Option<i64>, String> {
    max_i64_if_present(conn, "continue_feedback_events", "timestamp_ms")
}

pub fn latest_continue_open_watermark_ms(conn: &Connection) -> Result<Option<i64>, String> {
    max_i64_if_present(conn, "continue_decision_open_events", "opened_at_ms")
}

pub fn latest_feedback_or_open_watermark_ms(conn: &Connection) -> Result<Option<i64>, String> {
    Ok(
        match (
            latest_continue_feedback_watermark_ms(conn)?,
            latest_continue_open_watermark_ms(conn)?,
        ) {
            (Some(feedback), Some(open)) => Some(feedback.max(open)),
            (Some(feedback), None) => Some(feedback),
            (None, Some(open)) => Some(open),
            (None, None) => None,
        },
    )
}

fn pending_open_feedback_exists_for_decision(
    conn: &Connection,
    decision_id: &str,
    requested_at_ms: i64,
) -> Result<bool, String> {
    if !table_exists(conn, "continue_decision_open_events")? {
        return Ok(false);
    }
    let now_ms = current_time_millis();
    conn.query_row(
        "SELECT EXISTS(
           SELECT 1
           FROM continue_decision_open_events oe
           WHERE oe.decision_id = ?1
             AND oe.opened_at_ms > ?2
             AND oe.opened_at_ms <= ?3
             AND NOT EXISTS (
               SELECT 1 FROM continue_feedback_events fe WHERE fe.decision_id = oe.decision_id
             )
         )",
        params![
            decision_id,
            requested_at_ms,
            now_ms.saturating_sub(FEEDBACK_INFERENCE_MIN_AGE_MS),
        ],
        |row| row.get::<_, i64>(0),
    )
    .map(|value| value != 0)
    .map_err(to_string)
}

fn fresh_cached_continue_decision(
    conn: &Connection,
    session_id: Option<&str>,
    current_watermark: &ContinueEvidenceWatermark,
    micro_inference_requested: bool,
) -> Result<Option<CachedContinueDecisionMeta>, String> {
    if !table_exists(conn, "continue_decisions")? {
        return Ok(None);
    }
    let mut stmt = conn
        .prepare(
            "SELECT d.id, d.source, d.model, d.response_id, d.next_action,
                    d.confidence, d.warnings, d.validation_status,
                    d.validation_notes, d.decision_reason, d.handoff_headline,
                    d.handoff_return_line, d.handoff_current_focus_line,
                    d.handoff_last_state_line, d.handoff_next_action,
                    d.handoff_why_this, d.handoff_missing_evidence_line,
                    d.handoff_confidence_label, d.handoff_user_visible_uncertainty,
                    d.continue_output_mode, d.continue_decision_quality_json,
                    d.evidence_pack_v2_used, d.micro_inference_result_kind,
                    d.evidence_watermark_hash, d.latest_boundary_revision,
                    d.micro_inference_requested, d.micro_inference_attempted
             FROM continue_decisions d
             LEFT JOIN continue_candidates c ON c.id = d.selected_candidate_id
             LEFT JOIN frames f ON CAST(f.id AS TEXT) = d.current_focus_frame_id
             WHERE d.evidence_watermark_hash = ?1
               AND (?2 IS NULL OR f.session_id = ?2 OR d.current_focus_frame_id IS NULL)
               AND COALESCE(d.latest_boundary_revision, 0) = ?3
               AND COALESCE(d.micro_inference_requested, 0) = ?4
               AND NOT (
                 d.source = 'local_fallback'
                 AND d.validation_status = 'fallback'
                 AND (
                   COALESCE(d.continue_output_mode, '') <> 'strong_continue'
                   OR COALESCE(d.warnings, '') LIKE '%thin_evidence%'
                   OR COALESCE(d.warnings, '') LIKE '%current_focus_mismatch%'
                   OR COALESCE(d.warnings, '') LIKE '%current_focus_differs_from_return_target%'
                   OR COALESCE(d.warnings, '') LIKE '%score_capped:%'
                   OR COALESCE(d.warnings, '') LIKE '%selection_demoted:%'
                   OR COALESCE(d.warnings, '') LIKE '%local_fallback_gate:%'
                   OR COALESCE(d.warnings, '') LIKE '%micro_inference_validation_failed:%'
                 )
               )
               AND NOT EXISTS (
                 SELECT 1
                 FROM continue_boundary_revisions br
                 WHERE br.revision > COALESCE(d.latest_boundary_revision, 0)
               )
               AND NOT EXISTS (
                 SELECT 1
                 FROM continue_feedback_events fe
                 WHERE fe.timestamp_ms > d.requested_at_ms
               )
               AND NOT EXISTS (
                 SELECT 1
                 FROM continue_feedback_events fe
                 WHERE fe.timestamp_ms > d.requested_at_ms
                   AND COALESCE(
                     fe.is_negative_signal,
                     CASE
                       WHEN fe.event_kind IN ('rejected', 'ignored', 'corrected', 'ignored_workstream', 'artifact_only_evidence')
                       THEN 1 ELSE 0
                     END
                   ) = 1
                   AND (
                     (d.selected_candidate_id IS NOT NULL AND fe.selected_candidate_id = d.selected_candidate_id)
                     OR (d.selected_workstream_id IS NOT NULL AND fe.workstream_id = d.selected_workstream_id)
                     OR (d.return_target_artifact_id IS NOT NULL AND (
                       fe.target_artifact_id = d.return_target_artifact_id
                       OR fe.resume_work_target_artifact_id = d.return_target_artifact_id
                     ))
                     OR (c.target_artifact_id IS NOT NULL AND (
                       fe.target_artifact_id = c.target_artifact_id
                       OR fe.resume_work_target_artifact_id = c.target_artifact_id
                     ))
                   )
               )
               AND NOT EXISTS (
                 SELECT 1
                 FROM continue_decision_open_events oe
                 WHERE oe.decision_id = d.id
                   AND oe.opened_at_ms > d.requested_at_ms
                   AND oe.opened_at_ms <= ?5
                   AND NOT EXISTS (
                     SELECT 1
                     FROM continue_feedback_events fe
                     WHERE fe.decision_id = d.id
                   )
               )
               AND NOT EXISTS (
                 SELECT 1
                 FROM continue_breadcrumbs b
                 WHERE b.workstream_id = d.selected_workstream_id
                   AND b.created_at_ms > d.requested_at_ms
               )
             ORDER BY d.requested_at_ms DESC
             LIMIT 1",
        )
        .map_err(to_string)?;
    stmt.query_row(
        params![
            current_watermark.hash,
            session_id,
            current_watermark.latest_boundary_revision.unwrap_or(0),
            if micro_inference_requested {
                1_i64
            } else {
                0_i64
            },
            current_time_millis().saturating_sub(FEEDBACK_INFERENCE_MIN_AGE_MS),
        ],
        |row| {
            let warnings: Option<String> = row.get(6)?;
            let validation_notes: Option<String> = row.get(8)?;
            let quality_json: Option<String> = row.get(20)?;
            let quality_gate = quality_json
                .as_deref()
                .and_then(|value| serde_json::from_str::<ContinueDecisionQualityGate>(value).ok());
            Ok(CachedContinueDecisionMeta {
                decision_id: row.get(0)?,
                source: row.get(1)?,
                model: row.get(2)?,
                response_id: row.get(3)?,
                next_action: row.get(4)?,
                handoff: cached_handoff_from_row(row)?,
                confidence: row.get(5)?,
                warnings: split_semicolon_list(warnings.as_deref()),
                validation_status: row.get(7)?,
                validation_failures: split_semicolon_list(validation_notes.as_deref()),
                decision_reason: row.get(9)?,
                continue_output_mode: row
                    .get::<_, Option<String>>(19)?
                    .unwrap_or_else(|| "thin_continue".to_string()),
                quality_gate,
                evidence_pack_v2_used: row.get::<_, Option<i64>>(21)?.unwrap_or(0) != 0,
                micro_inference_result_kind: row.get(22)?,
                evidence_watermark_hash: row.get(23)?,
                latest_boundary_revision: row.get(24)?,
                micro_inference_requested: row.get::<_, Option<i64>>(25)?.unwrap_or(0) != 0,
                micro_inference_attempted: row.get::<_, Option<i64>>(26)?.unwrap_or(0) != 0,
            })
        },
    )
    .optional()
    .map_err(to_string)
}

fn build_continue_evidence_watermark(
    conn: &Connection,
    session_id: Option<&str>,
) -> Result<ContinueEvidenceWatermark, String> {
    let (latest_frame_id, latest_frame_at_ms) = latest_frame_marker(conn, session_id)?;
    let (latest_ui_event_id, latest_ui_event_at_ms) = latest_ui_event_marker(conn, session_id)?;
    let (latest_cache_ui_event_id, latest_cache_ui_event_at_ms) =
        latest_meaningful_ui_event_marker(conn, session_id)?;
    let (latest_artifact_observation_id, latest_artifact_observation_at_ms) =
        latest_string_marker(conn, "continue_artifact_observations", "id", "timestamp_ms")?;
    let (latest_typing_burst_id, latest_typing_burst_at_ms) = latest_scoped_string_marker(
        conn,
        "typing_bursts",
        "id",
        "ended_at_ms",
        "session_id",
        session_id,
    )?;
    let (latest_window_snapshot_id, latest_window_snapshot_at_ms) =
        latest_string_marker(conn, "window_snapshots", "id", "ts_ms")?;
    let (latest_app_context_id, latest_app_context_at_ms) =
        latest_app_context_marker(conn, session_id)?;
    let (latest_semantic_moment_id, latest_semantic_moment_at_ms) =
        latest_string_marker(conn, "continue_semantic_moments", "id", "ended_at_ms")?;
    let (latest_task_action_id, latest_task_action_at_ms) =
        latest_string_marker(conn, "continue_task_actions", "id", "created_at_ms")?;
    let latest_workstream_revision =
        max_i64_if_present(conn, "continue_workstreams", "last_active_timestamp_ms")?;
    let latest_open_loop_revision =
        max_i64_if_present(conn, "continue_open_loops", "last_updated_at_ms")?;
    let latest_boundary_revision =
        max_i64_if_present(conn, "continue_boundary_revisions", "revision")?;
    let latest_memory_cell_at_ms =
        max_i64_if_present(conn, "continue_memory_cells", "updated_at_ms")?;
    let latest_memory_edge_at_ms =
        max_i64_if_present(conn, "continue_memory_edges", "updated_at_ms")?;
    let (latest_evidence_probe_id, latest_evidence_probe_at_ms) =
        latest_string_marker(conn, "continue_evidence_probes", "id", "completed_at_ms")?;
    let (latest_app_activity_segment_id, latest_app_activity_segment_at_ms) =
        latest_string_marker(conn, "continue_app_activity_segments", "id", "ended_at_ms")?;
    let (latest_activity_classification_id, latest_activity_classification_at_ms) =
        latest_string_marker(
            conn,
            "continue_activity_classifications",
            "id",
            "updated_at_ms",
        )?;
    let hash_seed = serde_json::json!({
        "continue_schema_version": CONTINUE_SCHEMA_VERSION,
        "p8_router_version": 1,
        "latest_frame_id": latest_frame_id,
        "latest_frame_at_ms": latest_frame_at_ms,
        "latest_cache_ui_event_id": latest_cache_ui_event_id,
        "latest_cache_ui_event_at_ms": latest_cache_ui_event_at_ms,
        "latest_artifact_observation_id": latest_artifact_observation_id,
        "latest_artifact_observation_at_ms": latest_artifact_observation_at_ms,
        "latest_typing_burst_id": latest_typing_burst_id,
        "latest_typing_burst_at_ms": latest_typing_burst_at_ms,
        "latest_window_snapshot_id": latest_window_snapshot_id,
        "latest_window_snapshot_at_ms": latest_window_snapshot_at_ms,
        "latest_app_context_id": latest_app_context_id,
        "latest_app_context_at_ms": latest_app_context_at_ms,
        "latest_semantic_moment_id": latest_semantic_moment_id,
        "latest_semantic_moment_at_ms": latest_semantic_moment_at_ms,
        "latest_task_action_id": latest_task_action_id,
        "latest_task_action_at_ms": latest_task_action_at_ms,
        "latest_workstream_revision": latest_workstream_revision,
        "latest_open_loop_revision": latest_open_loop_revision,
        "latest_boundary_revision": latest_boundary_revision,
        "latest_memory_cell_at_ms": latest_memory_cell_at_ms,
        "latest_memory_edge_at_ms": latest_memory_edge_at_ms,
        "latest_evidence_probe_id": latest_evidence_probe_id,
        "latest_evidence_probe_at_ms": latest_evidence_probe_at_ms,
        "latest_app_activity_segment_id": latest_app_activity_segment_id,
        "latest_app_activity_segment_at_ms": latest_app_activity_segment_at_ms,
        "latest_activity_classification_id": latest_activity_classification_id,
        "latest_activity_classification_at_ms": latest_activity_classification_at_ms,
    });
    let hash = stable_hash(hash_seed.to_string().as_bytes());
    Ok(ContinueEvidenceWatermark {
        latest_frame_id,
        latest_frame_at_ms,
        latest_ui_event_id,
        latest_ui_event_at_ms,
        latest_artifact_observation_id,
        latest_artifact_observation_at_ms,
        latest_typing_burst_id,
        latest_typing_burst_at_ms,
        latest_window_snapshot_id,
        latest_window_snapshot_at_ms,
        latest_app_context_id,
        latest_app_context_at_ms,
        latest_semantic_moment_id,
        latest_semantic_moment_at_ms,
        latest_task_action_id,
        latest_task_action_at_ms,
        latest_workstream_revision,
        latest_open_loop_revision,
        latest_boundary_revision,
        latest_memory_cell_at_ms,
        latest_memory_edge_at_ms,
        latest_evidence_probe_id,
        latest_evidence_probe_at_ms,
        latest_app_activity_segment_id,
        latest_app_activity_segment_at_ms,
        latest_activity_classification_id,
        latest_activity_classification_at_ms,
        hash,
    })
}

fn latest_frame_marker(
    conn: &Connection,
    session_id: Option<&str>,
) -> Result<(Option<i64>, Option<i64>), String> {
    if !table_exists(conn, "frames")? {
        return Ok((None, None));
    }
    let sql = match session_id {
        Some(_) => {
            "SELECT id, captured_at
             FROM frames
             WHERE session_id = ?1
             ORDER BY captured_at DESC, id DESC
             LIMIT 1"
        }
        None => {
            "SELECT id, captured_at
             FROM frames
             ORDER BY captured_at DESC, id DESC
             LIMIT 1"
        }
    };
    let mut stmt = conn.prepare(sql).map_err(to_string)?;
    let value = if let Some(session_id) = session_id {
        stmt.query_row(params![session_id], |row| Ok((row.get(0)?, row.get(1)?)))
            .optional()
    } else {
        stmt.query_row([], |row| Ok((row.get(0)?, row.get(1)?)))
            .optional()
    };
    value
        .map_err(to_string)
        .map(|value| value.unwrap_or((None, None)))
}

