fn latest_meaningful_ui_event_marker(
    conn: &Connection,
    session_id: Option<&str>,
) -> Result<(Option<String>, Option<i64>), String> {
    if !table_exists(conn, "ui_events")? {
        return Ok((None, None));
    }
    let has_app_name = column_exists(conn, "ui_events", "app_name")?;
    let has_bundle_id = column_exists(conn, "ui_events", "app_bundle_id")?;
    let has_window_title = column_exists(conn, "ui_events", "window_title")?;
    let sql = match session_id {
        Some(_) => {
            "SELECT id, ts_ms, event_type, key_category, app_name, app_bundle_id, window_title
             FROM ui_events
             WHERE session_id = ?1
             ORDER BY ts_ms DESC, id DESC
             LIMIT 80"
        }
        None => {
            "SELECT id, ts_ms, event_type, key_category, app_name, app_bundle_id, window_title
             FROM ui_events
             ORDER BY ts_ms DESC, id DESC
             LIMIT 80"
        }
    };
    let mut stmt = conn.prepare(sql).map_err(to_string)?;
    let map_row = |row: &Row<'_>| {
        Ok((
            row.get::<_, String>(0)?,
            row.get::<_, i64>(1)?,
            row.get::<_, String>(2)?,
            row.get::<_, Option<String>>(3)?,
            if has_app_name {
                row.get::<_, Option<String>>(4)?
            } else {
                None
            },
            if has_bundle_id {
                row.get::<_, Option<String>>(5)?
            } else {
                None
            },
            if has_window_title {
                row.get::<_, Option<String>>(6)?
            } else {
                None
            },
        ))
    };
    let rows = if let Some(session_id) = session_id {
        stmt.query_map(params![session_id], map_row)
            .map_err(to_string)?
            .collect::<Result<Vec<_>, _>>()
            .map_err(to_string)?
    } else {
        stmt.query_map([], map_row)
            .map_err(to_string)?
            .collect::<Result<Vec<_>, _>>()
            .map_err(to_string)?
    };
    for row in rows {
        let (id, ts_ms, event_type, key_category, app_name, bundle_id, window_title) = row;
        let event_label = key_category
            .map(|category| format!("{}:{}", event_type, category))
            .unwrap_or(event_type);
        if high_value_focus_event_score(&event_label) >= 0.55
            && !is_smalltalk_self_surface(
                app_name.as_deref(),
                bundle_id.as_deref(),
                window_title.as_deref(),
                None,
                None,
            )
            && !is_generated_debug_surface(app_name.as_deref(), window_title.as_deref(), None, None)
        {
            return Ok((Some(id), Some(ts_ms)));
        }
    }
    Ok((None, None))
}

fn latest_string_marker(
    conn: &Connection,
    table: &str,
    id_column: &str,
    ts_column: &str,
) -> Result<(Option<String>, Option<i64>), String> {
    if !table_exists(conn, table)? {
        return Ok((None, None));
    }
    conn.query_row(
        &format!(
            "SELECT {}, {} FROM {} ORDER BY {} DESC, {} DESC LIMIT 1",
            id_column, ts_column, table, ts_column, id_column
        ),
        [],
        |row| Ok((row.get(0)?, row.get(1)?)),
    )
    .optional()
    .map_err(to_string)
    .map(|value| value.unwrap_or((None, None)))
}

