fn load_trace_missing_evidence(
    conn: &Connection,
    candidate_id: Option<&str>,
) -> Result<Vec<String>, String> {
    let Some(candidate_id) = candidate_id else {
        return Ok(vec!["no_candidate_generated".to_string()]);
    };
    if !table_exists(conn, "continue_candidates")? {
        return Ok(Vec::new());
    }
    let missing: Option<String> = conn
        .query_row(
            "SELECT missing_evidence FROM continue_candidates WHERE id = ?1",
            params![candidate_id],
            |row| row.get(0),
        )
        .optional()
        .map_err(to_string)?
        .flatten();
    Ok(split_semicolon_list(missing.as_deref()))
}

fn redacted_trace_snippet(value: &str, max_chars: usize) -> Option<String> {
    let mut redacted = value
        .split_whitespace()
        .take(32)
        .collect::<Vec<_>>()
        .join(" ");
    if redacted.is_empty() {
        return None;
    }
    for marker in ["sk-", "secret", "token", "password", "clipboard"] {
        if redacted.to_ascii_lowercase().contains(marker) {
            redacted = "[redacted sensitive text]".to_string();
            break;
        }
    }
    if redacted.chars().count() > max_chars {
        redacted = redacted.chars().take(max_chars).collect::<String>();
    }
    clean_handoff_line(redacted, max_chars)
}

fn load_recent_continue_workstream(
    conn: &Connection,
    workstream_id: &str,
) -> Result<Option<RecentContinueWorkstream>, String> {
    let mut stmt = conn
        .prepare(
            "SELECT w.id, w.state, w.title_candidate, w.primary_artifact_id,
                    a.display_title, w.created_at_ms, w.last_active_timestamp_ms,
                    w.suspended_timestamp_ms, w.confidence, w.unresolved_signal, w.source
             FROM continue_workstreams w
             LEFT JOIN continue_artifacts a ON a.id = w.primary_artifact_id
             WHERE w.id = ?1
             LIMIT 1",
        )
        .map_err(to_string)?;
    let mut workstream = stmt
        .query_row(params![workstream_id], |row| {
            Ok(RecentContinueWorkstream {
                id: row.get(0)?,
                state: row.get(1)?,
                title_candidate: row.get(2)?,
                primary_artifact_id: row.get(3)?,
                primary_artifact_title: row.get(4)?,
                created_at_ms: row.get(5)?,
                last_active_timestamp_ms: row.get(6)?,
                suspended_timestamp_ms: row.get(7)?,
                confidence: row.get(8)?,
                unresolved_signal: row.get(9)?,
                source: row.get(10)?,
                episodes: Vec::new(),
                artifacts: Vec::new(),
            })
        })
        .optional()
        .map_err(to_string)?;
    if let Some(workstream) = workstream.as_mut() {
        workstream.episodes = recent_workstream_episodes(conn, &workstream.id)?;
        workstream.artifacts = recent_workstream_artifacts(conn, &workstream.id)?;
    }
    Ok(workstream)
}

