fn load_continue_workstream_candidate_details(
    conn: &Connection,
    workstream_id: &str,
) -> Result<Vec<ContinueWorkstreamCandidateDetail>, String> {
    let mut stmt = conn
        .prepare(
            "SELECT c.id, c.workstream_id, c.target_artifact_id, a.display_title,
                    a.artifact_kind, a.openability, c.candidate_kind,
                    c.last_meaningful_action_id, c.evidence_frame_id, c.supporting_episode_id,
                    c.score, c.actionability_score, c.primary_target_score,
                    c.unresolved_score, c.branch_origin_score, c.evidence_quality_score,
                    c.recency_score, c.openability_score, c.privacy_safety_score,
                    c.memory_support_score, c.memory_contradiction_score,
                    c.feedback_prior_score, c.retrieval_confidence_score,
                    c.work_value_score, c.resume_likelihood_score,
                    c.divergence_score, c.diagnostic_score,
                    c.objective_relation_score, c.interaction_depth_score,
                    c.evidence_sufficiency_score,
                    c.reason, c.missing_evidence, c.created_at_ms
             FROM continue_candidates c
             LEFT JOIN continue_artifacts a ON a.id = c.target_artifact_id
             WHERE c.workstream_id = ?1
             ORDER BY c.created_at_ms DESC, c.score DESC
             LIMIT 12",
        )
        .map_err(to_string)?;
    let rows = stmt
        .query_map(params![workstream_id], |row| {
            let score: f64 = row.get(10)?;
            let missing_evidence = row
                .get::<_, Option<String>>(31)?
                .map(|value| {
                    value
                        .split(';')
                        .filter_map(|part| non_empty(part.to_string()))
                        .collect::<Vec<_>>()
                })
                .unwrap_or_default();
            Ok(ContinueWorkstreamCandidateDetail {
                candidate_id: row.get(0)?,
                workstream_id: row.get(1)?,
                target_artifact_id: row.get(2)?,
                target_title: row.get(3)?,
                target_kind: row.get(4)?,
                target_openability: row.get(5)?,
                candidate_kind: row.get(6)?,
                last_meaningful_action_id: row.get(7)?,
                evidence_frame_id: row.get(8)?,
                supporting_episode_id: row.get(9)?,
                score: round_score(score),
                confidence_label: confidence_label(score).to_string(),
                reason: row.get(30)?,
                missing_evidence,
                components: ContinueScoreComponents {
                    actionability: round_score(row.get(11)?),
                    primary_target: round_score(row.get(12)?),
                    unresolved_state: round_score(row.get(13)?),
                    branch_origin: round_score(row.get(14)?),
                    evidence_quality: round_score(row.get(15)?),
                    recency: round_score(row.get(16)?),
                    fresh_current_work: 0.0,
                    openability: round_score(row.get(17)?),
                    privacy_safety: round_score(row.get(18)?),
                    memory_support: round_score(row.get(19)?),
                    memory_contradiction: round_score(row.get(20)?),
                    feedback_prior: round_signed_score(row.get(21)?),
                    retrieval_confidence: round_score(row.get(22)?),
                    work_value: round_score(row.get(23)?),
                    resume_likelihood: round_score(row.get(24)?),
                    divergence: round_score(row.get(25)?),
                    diagnostic: round_score(row.get(26)?),
                    objective_relation: round_score(row.get(27)?),
                    interaction_depth: round_score(row.get(28)?),
                    evidence_sufficiency: round_score(row.get(29)?),
                },
                created_at_ms: row.get(32)?,
            })
        })
        .map_err(to_string)?;
    rows.collect::<Result<Vec<_>, _>>().map_err(to_string)
}

fn load_continue_decision_summary(
    conn: &Connection,
    workstream_id: &str,
    decision_id: Option<&str>,
) -> Result<Option<ContinueDecisionSummary>, String> {
    let (sql, bind_value) = if let Some(decision_id) = decision_id {
        (
            "SELECT id, requested_at_ms, source, selected_candidate_id,
                    return_target_artifact_id, confidence, decision_reason,
                    next_action, warnings, validation_status
             FROM continue_decisions
             WHERE id = ?1
             LIMIT 1",
            decision_id,
        )
    } else {
        (
            "SELECT id, requested_at_ms, source, selected_candidate_id,
                    return_target_artifact_id, confidence, decision_reason,
                    next_action, warnings, validation_status
             FROM continue_decisions
             WHERE selected_workstream_id = ?1
             ORDER BY requested_at_ms DESC
             LIMIT 1",
            workstream_id,
        )
    };
    conn.query_row(sql, params![bind_value], |row| {
        let warnings = row
            .get::<_, Option<String>>(8)?
            .map(|value| {
                value
                    .split(';')
                    .filter_map(|part| non_empty(part.to_string()))
                    .collect::<Vec<_>>()
            })
            .unwrap_or_default();
        Ok(ContinueDecisionSummary {
            decision_id: row.get(0)?,
            requested_at_ms: row.get(1)?,
            source: row.get(2)?,
            selected_candidate_id: row.get(3)?,
            return_target_artifact_id: row.get(4)?,
            confidence: round_score(row.get(5)?),
            decision_reason: row.get(6)?,
            next_action: row.get(7)?,
            warnings,
            validation_status: row.get(9)?,
        })
    })
    .optional()
    .map_err(to_string)
}

fn load_continue_feedback_events(
    conn: &Connection,
    decision_id: Option<&str>,
    workstream_id: Option<&str>,
) -> Result<Vec<ContinueFeedbackEventResult>, String> {
    let mut stmt = conn
        .prepare(
            "SELECT id, decision_id, selected_candidate_id, workstream_id, event_kind,
                    observed_frame_id, target_artifact_id, chosen_artifact_id,
                    target_artifact_stable_key, resume_work_target_artifact_id,
                    timestamp_ms, confidence, reason, note, source
             FROM continue_feedback_events
             WHERE (?1 IS NOT NULL AND decision_id = ?1)
                OR (?2 IS NOT NULL AND workstream_id = ?2)
             ORDER BY timestamp_ms DESC
             LIMIT 20",
        )
        .map_err(to_string)?;
    let rows = stmt
        .query_map(params![decision_id, workstream_id], |row| {
            let feedback_row = FeedbackEventRow {
                id: row.get(0)?,
                decision_id: row.get(1)?,
                selected_candidate_id: row.get(2)?,
                workstream_id: row.get(3)?,
                event_kind: row.get(4)?,
                observed_frame_id: row.get(5)?,
                target_artifact_id: row.get(6)?,
                chosen_artifact_id: row.get(7)?,
                target_artifact_stable_key: row.get(8)?,
                resume_work_target_artifact_id: row.get(9)?,
                timestamp_ms: row.get(10)?,
                confidence: row.get(11)?,
                reason: row.get(12)?,
                note: row.get(13)?,
                source: row.get(14)?,
            };
            Ok(feedback_event_result_from_row(feedback_row))
        })
        .map_err(to_string)?;
    rows.collect::<Result<Vec<_>, _>>().map_err(to_string)
}

fn load_continue_feedback_events_for_target_keys(
    conn: &Connection,
    target_keys: &[FeedbackTargetKey],
    limit: i64,
) -> Result<Vec<ContinueFeedbackEventResult>, String> {
    Ok(
        load_continue_feedback_event_rows_for_target_keys(conn, target_keys, limit)?
            .into_iter()
            .map(feedback_event_result_from_row)
            .collect::<Vec<_>>(),
    )
}

fn load_continue_feedback_event_rows_for_target_keys(
    conn: &Connection,
    target_keys: &[FeedbackTargetKey],
    limit: i64,
) -> Result<Vec<FeedbackEventRow>, String> {
    if target_keys.is_empty() {
        return Ok(Vec::new());
    }
    let mut stmt = conn
        .prepare(
            "SELECT id, decision_id, selected_candidate_id, workstream_id, event_kind,
                    observed_frame_id, target_artifact_id, chosen_artifact_id,
                    target_artifact_stable_key, resume_work_target_artifact_id,
                    timestamp_ms, confidence, reason, note, source
             FROM continue_feedback_events
             ORDER BY timestamp_ms DESC
             LIMIT ?1",
        )
        .map_err(to_string)?;
    let rows = stmt
        .query_map(params![limit.max(1)], |row| {
            Ok(FeedbackEventRow {
                id: row.get(0)?,
                decision_id: row.get(1)?,
                selected_candidate_id: row.get(2)?,
                workstream_id: row.get(3)?,
                event_kind: row.get(4)?,
                observed_frame_id: row.get(5)?,
                target_artifact_id: row.get(6)?,
                chosen_artifact_id: row.get(7)?,
                target_artifact_stable_key: row.get(8)?,
                resume_work_target_artifact_id: row.get(9)?,
                timestamp_ms: row.get(10)?,
                confidence: row.get(11)?,
                reason: row.get(12)?,
                note: row.get(13)?,
                source: row.get(14)?,
            })
        })
        .map_err(to_string)?;
    let target_key_set = target_keys.iter().collect::<HashSet<_>>();
    let mut matched = Vec::new();
    for row in rows {
        let row = row.map_err(to_string)?;
        let mapped = feedback_targets_for_feedback_event(&row);
        let row_targets = mapped
            .negative_targets
            .iter()
            .chain(mapped.positive_targets.iter())
            .chain(mapped.neutral_targets.iter());
        if row_targets
            .into_iter()
            .any(|key| target_key_set.contains(key))
        {
            matched.push(row);
        }
    }
    Ok(matched)
}

fn feedback_event_result_from_row(row: FeedbackEventRow) -> ContinueFeedbackEventResult {
    ContinueFeedbackEventResult {
        id: row.id,
        decision_id: row.decision_id,
        selected_candidate_id: row.selected_candidate_id,
        workstream_id: row.workstream_id,
        event_kind: row.event_kind,
        observed_frame_id: row.observed_frame_id,
        target_artifact_id: row.target_artifact_id,
        chosen_artifact_id: row.chosen_artifact_id,
        timestamp_ms: row.timestamp_ms,
        confidence: round_score(row.confidence),
        reason: row.reason,
        note: row.note,
        source: row.source,
    }
}

fn feedback_targets_for_scored_candidate_from_db(
    conn: &Connection,
    candidate: &ScoredContinueCandidate,
) -> Result<Vec<FeedbackTargetKey>, String> {
    let mut artifacts_by_id = HashMap::new();
    for artifact_id in [
        candidate
            .target_artifact
            .as_ref()
            .map(|artifact| artifact.id.as_str()),
        candidate
            .resume_work_target
            .as_ref()
            .map(|artifact| artifact.id.as_str()),
    ]
    .into_iter()
    .flatten()
    {
        if let Some(stable_key) = load_artifact_stable_key(conn, Some(artifact_id))? {
            artifacts_by_id.insert(
                artifact_id.to_string(),
                ContinueArtifact {
                    id: artifact_id.to_string(),
                    artifact_kind: ContinueArtifactKind::Unknown,
                    stable_key,
                    app_name: None,
                    bundle_id: None,
                    window_title: None,
                    browser_url: None,
                    document_path: None,
                    display_title: None,
                    first_seen_frame_id: None,
                    last_seen_frame_id: None,
                    first_seen_timestamp: 0,
                    last_seen_timestamp: 0,
                    identity_confidence: 0.0,
                    evidence_quality: ContinueEvidenceQuality::Unknown,
                    privacy_status: None,
                    openability: ContinueOpenability::Unknown,
                    created_at_ms: 0,
                    updated_at_ms: 0,
                },
            );
        }
    }
    Ok(feedback_targets_for_scored_candidate(
        candidate,
        &artifacts_by_id,
    ))
}

fn apply_feedback_obedience_to_candidates(
    conn: &Connection,
    candidates: &mut [ScoredContinueCandidate],
) -> Result<(), String> {
    let now_ms = current_time_millis();
    for candidate in candidates {
        let aggregate = feedback_aggregate_for_scored_candidate_at(conn, candidate, now_ms)?;
        let target_keys = feedback_targets_for_scored_candidate_from_db(conn, candidate)?;
        let reconfirming_evidence = if let Some(last_negative_ms) = aggregate.last_negative_ms {
            find_reconfirming_evidence_after(conn, candidate, &target_keys, last_negative_ms)?
        } else {
            None
        };
        let decision =
            compute_feedback_decision(&aggregate, reconfirming_evidence.as_ref(), now_ms);
        candidate.feedback_suppression_state = decision.state_label().to_string();
        candidate.feedback_negative_weight = decision.negative_weight_since_reconfirmation;
        candidate.feedback_positive_weight_after_last_negative =
            decision.positive_weight_after_last_negative;
        candidate.feedback_last_negative_ms = decision.last_negative_ms;
        candidate.feedback_last_positive_ms = decision.last_positive_ms;
        candidate.feedback_last_reconfirming_evidence_ms = decision.last_reconfirming_evidence_ms;
        candidate.feedback_score_cap = decision.score_cap;
        candidate.feedback_reason_codes = decision.reason_codes.clone();
        if aggregate.negative_count > 0 {
            push_string_once(
                &mut candidate.warnings,
                &format!("feedback_negative_count:{}", aggregate.negative_count),
            );
        }
        if aggregate.positive_count > 0 {
            push_string_once(
                &mut candidate.warnings,
                &format!("feedback_positive_count:{}", aggregate.positive_count),
            );
        }
        if let Some(last_negative_at_ms) = aggregate.last_negative_ms {
            push_string_once(
                &mut candidate.warnings,
                &format!("feedback_last_negative_at_ms:{}", last_negative_at_ms),
            );
        }
        for reason_code in &decision.reason_codes {
            push_string_once(&mut candidate.warnings, reason_code);
        }
        if let Some(score_cap) = decision.score_cap {
            candidate.score = round_score(f64::min(candidate.score, score_cap));
            push_string_once(
                &mut candidate.score_caps_applied,
                &format!("score_capped:{}", decision.state_label()),
            );
        }
        if decision.suppress_primary {
            let reason = decision
                .reason_codes
                .first()
                .map(|value| value.trim_start_matches("feedback:"))
                .unwrap_or("negative_feedback_without_reconfirmation");
            candidate.score = round_score(f64::min(candidate.score, 0.18));
            candidate.eligible_for_primary_selection = false;
            candidate.selection_demotion_reason =
                Some("repeated negative feedback without fresh reconfirmation".to_string());
            push_string_once(&mut candidate.risk_flags, "feedback_hard_suppressed");
            push_string_once(&mut candidate.risk_flags, reason);
            push_string_once(
                &mut candidate.score_caps_applied,
                "score_capped:feedback_hard_suppressed",
            );
            push_string_once(
                &mut candidate.warnings,
                &format!("feedback_hard_suppressed:{}", reason),
            );
            candidate.continuation_role = Some("suppressed".to_string());
        }
        candidate.risk_flags.sort();
        candidate.risk_flags.dedup();
        candidate.score_caps_applied.sort();
        candidate.score_caps_applied.dedup();
        candidate.warnings.sort();
        candidate.warnings.dedup();
    }
    Ok(())
}

fn feedback_aggregate_for_scored_candidate(
    conn: &Connection,
    candidate: &ScoredContinueCandidate,
) -> Result<FeedbackAggregate, String> {
    feedback_aggregate_for_scored_candidate_at(conn, candidate, current_time_millis())
}

fn feedback_aggregate_for_scored_candidate_at(
    conn: &Connection,
    candidate: &ScoredContinueCandidate,
    now_ms: i64,
) -> Result<FeedbackAggregate, String> {
    let keys = feedback_targets_for_scored_candidate_from_db(conn, candidate)?;
    feedback_aggregate_for_target_keys_at(conn, &keys, now_ms)
}

pub fn continue_feedback_suppression_for_target(
    conn: &Connection,
    selected_candidate_id: Option<&str>,
    workstream_id: Option<&str>,
    target_artifact_id: Option<&str>,
) -> Result<Option<String>, String> {
    ensure_continue_schema(conn)?;
    let mut keys = Vec::new();
    push_feedback_target(
        &mut keys,
        FeedbackTargetScope::Candidate,
        selected_candidate_id,
    );
    push_feedback_target(
        &mut keys,
        FeedbackTargetScope::TargetArtifact,
        target_artifact_id,
    );
    push_feedback_target(&mut keys, FeedbackTargetScope::Workstream, workstream_id);
    if let Some(stable_key) = load_artifact_stable_key(conn, target_artifact_id)? {
        push_feedback_target(
            &mut keys,
            FeedbackTargetScope::ArtifactStableKey,
            Some(stable_key.as_str()),
        );
    }
    let now_ms = current_time_millis();
    let aggregate = feedback_aggregate_for_target_keys_at(conn, &keys, now_ms)?;
    let reconfirming_evidence = if let Some(last_negative_ms) = aggregate.last_negative_ms {
        find_reconfirming_evidence_for_target_after(conn, target_artifact_id, last_negative_ms)?
    } else {
        None
    };
    let decision = compute_feedback_decision(&aggregate, reconfirming_evidence.as_ref(), now_ms);
    if decision.suppress_primary {
        Ok(Some(decision.reason_codes.first().cloned().unwrap_or_else(
            || "feedback:negative_feedback_without_reconfirmation".to_string(),
        )))
    } else {
        Ok(None)
    }
}

fn find_reconfirming_evidence_for_target_after(
    conn: &Connection,
    target_artifact_id: Option<&str>,
    after_ms: i64,
) -> Result<Option<ReconfirmingEvidence>, String> {
    let Some(target_artifact_id) = target_artifact_id else {
        return Ok(None);
    };
    let mut best = None;
    if let Some(evidence) =
        latest_direct_artifact_reconfirmation_after(conn, target_artifact_id, after_ms)?
    {
        set_newer_reconfirming_evidence(&mut best, evidence);
    }
    if let Some(evidence) =
        latest_meaningful_action_reconfirmation_after(conn, target_artifact_id, after_ms)?
    {
        set_newer_reconfirming_evidence(&mut best, evidence);
    }
    Ok(best)
}

fn feedback_aggregate_for_target_keys(
    conn: &Connection,
    target_keys: &[FeedbackTargetKey],
) -> Result<FeedbackAggregate, String> {
    feedback_aggregate_for_target_keys_at(conn, target_keys, current_time_millis())
}

fn feedback_aggregate_for_target_keys_at(
    conn: &Connection,
    target_keys: &[FeedbackTargetKey],
    now_ms: i64,
) -> Result<FeedbackAggregate, String> {
    let mut aggregate = FeedbackAggregate::default();
    let target_key_set = target_keys.iter().collect::<HashSet<_>>();
    let lookback_start_ms = now_ms.saturating_sub(FEEDBACK_NEGATIVE_LOOKBACK_MS);
    let mut rows = load_continue_feedback_event_rows_for_target_keys(conn, target_keys, 500)?;
    rows.sort_by_key(|row| row.timestamp_ms);
    for row in rows {
        let targets = feedback_targets_for_feedback_event(&row);
        if row.timestamp_ms < lookback_start_ms
            && feedback_event_is_negative_signal(&row.event_kind)
        {
            continue;
        }
        let positive_applies = feedback_positive_applies_to_candidate(&targets, &target_key_set);
        if positive_applies {
            let weight =
                feedback_positive_weight(&row.event_kind, row.source.as_deref().unwrap_or(""));
            if weight > 0 {
                aggregate.positive_count += 1;
                aggregate.last_positive_ms = Some(
                    aggregate
                        .last_positive_ms
                        .unwrap_or_default()
                        .max(row.timestamp_ms),
                );
                if aggregate
                    .last_negative_ms
                    .is_some_and(|last_negative_ms| row.timestamp_ms > last_negative_ms)
                {
                    aggregate.positive_weight_after_last_negative += weight;
                    aggregate.last_reconfirming_evidence_ms = Some(
                        aggregate
                            .last_reconfirming_evidence_ms
                            .unwrap_or_default()
                            .max(row.timestamp_ms),
                    );
                    push_string_once(
                        &mut aggregate.reason_codes,
                        "feedback:reconfirmed_by_positive_feedback_after_negative",
                    );
                }
            }
        }
        if feedback_negative_applies_to_candidate(&row, &targets, &target_key_set) {
            let reconfirmed_after_row = aggregate
                .last_reconfirming_evidence_ms
                .is_some_and(|last_reconfirming_ms| last_reconfirming_ms > row.timestamp_ms);
            let weight =
                feedback_negative_weight(&row.event_kind, row.source.as_deref().unwrap_or(""));
            if weight <= 0 || reconfirmed_after_row {
                continue;
            }
            aggregate.negative_count += 1;
            aggregate.negative_weight_since_reconfirmation += weight;
            aggregate.last_negative_ms = Some(
                aggregate
                    .last_negative_ms
                    .unwrap_or_default()
                    .max(row.timestamp_ms),
            );
            aggregate.last_negative_kind = Some(row.event_kind.clone());
            if row.timestamp_ms >= now_ms.saturating_sub(FEEDBACK_HARD_NEGATIVE_RECENT_MS) {
                aggregate.hard_negative_recent = true;
            }
            if row.event_kind == "ignored" {
                aggregate.ignored_count_since_reconfirmation += 1;
            }
            match row.event_kind.as_str() {
                "rejected" | "corrected" => {
                    aggregate.hard_negative_after_reconfirmation = true;
                    push_string_once(
                        &mut aggregate.reason_codes,
                        "feedback:explicit_rejected_after_last_positive",
                    );
                }
                "ignored_workstream" => {
                    aggregate.ignored_workstream_after_reconfirmation = true;
                    aggregate.hard_negative_after_reconfirmation = true;
                    push_string_once(&mut aggregate.reason_codes, "feedback:ignored_workstream");
                }
                "artifact_only_evidence" => {
                    aggregate.artifact_only_evidence_after_reconfirmation = true;
                    aggregate.hard_negative_after_reconfirmation = true;
                    push_string_once(
                        &mut aggregate.reason_codes,
                        "feedback:artifact_only_evidence_not_primary",
                    );
                }
                "ignored" if aggregate.ignored_count_since_reconfirmation >= 2 => {
                    push_string_once(
                        &mut aggregate.reason_codes,
                        "feedback:repeated_ignored_without_reconfirmation",
                    );
                }
                _ => {}
            }
        }
    }
    Ok(aggregate)
}

fn feedback_source_is_explicit(source: &str) -> bool {
    !matches!(source.trim(), "" | "inferred" | "auto" | "system")
}

fn feedback_negative_weight(kind: &str, source: &str) -> i32 {
    let explicit = feedback_source_is_explicit(source);
    match kind {
        "rejected" | "corrected" | "artifact_only_evidence" => {
            if explicit {
                3
            } else {
                2
            }
        }
        "ignored" => {
            if explicit {
                2
            } else {
                1
            }
        }
        "ignored_workstream" => {
            if explicit {
                4
            } else {
                3
            }
        }
        "accepted" | "auto_resumed" | "user_next_step_note" => 0,
        _ => 0,
    }
}

fn feedback_positive_weight(kind: &str, source: &str) -> i32 {
    let explicit = feedback_source_is_explicit(source);
    match kind {
        "accepted" | "corrected" => {
            if explicit {
                3
            } else {
                2
            }
        }
        "auto_resumed" => {
            if explicit {
                1
            } else {
                2
            }
        }
        "user_next_step_note" => 0,
        _ => 0,
    }
}

fn scored_candidate_feedback_artifact_ids(candidate: &ScoredContinueCandidate) -> Vec<String> {
    let mut ids = Vec::new();
    if let Some(id) = candidate
        .target_artifact
        .as_ref()
        .map(|artifact| artifact.id.clone())
    {
        push_string_once(&mut ids, &id);
    }
    if let Some(id) = candidate
        .resume_work_target
        .as_ref()
        .map(|artifact| artifact.id.clone())
    {
        push_string_once(&mut ids, &id);
    }
    ids
}

fn find_reconfirming_evidence_after(
    conn: &Connection,
    candidate: &ScoredContinueCandidate,
    target_keys: &[FeedbackTargetKey],
    after_ms: i64,
) -> Result<Option<ReconfirmingEvidence>, String> {
    let target_key_set = target_keys.iter().collect::<HashSet<_>>();
    let mut best: Option<ReconfirmingEvidence> = None;

    for row in load_continue_feedback_event_rows_for_target_keys(conn, target_keys, 500)? {
        if row.timestamp_ms <= after_ms {
            continue;
        }
        let targets = feedback_targets_for_feedback_event(&row);
        if !feedback_positive_applies_to_candidate(&targets, &target_key_set) {
            continue;
        }
        let weight = feedback_positive_weight(&row.event_kind, row.source.as_deref().unwrap_or(""));
        if weight <= 0 {
            continue;
        }
        set_newer_reconfirming_evidence(
            &mut best,
            ReconfirmingEvidence {
                evidence_kind: row.event_kind.clone(),
                evidence_id: row.id.clone(),
                timestamp_ms: row.timestamp_ms,
                weight,
                reason_code: if row.event_kind == "corrected" {
                    "feedback:reconfirmed_by_corrected_target_after_negative".to_string()
                } else {
                    "feedback:reconfirmed_by_positive_feedback_after_negative".to_string()
                },
            },
        );
    }

    for artifact_id in scored_candidate_feedback_artifact_ids(candidate) {
        if let Some(evidence) =
            latest_direct_artifact_reconfirmation_after(conn, &artifact_id, after_ms)?
        {
            set_newer_reconfirming_evidence(&mut best, evidence);
        }
        if let Some(evidence) =
            latest_meaningful_action_reconfirmation_after(conn, &artifact_id, after_ms)?
        {
            set_newer_reconfirming_evidence(&mut best, evidence);
        }
    }

    if let Some(action) = candidate
        .last_meaningful_action
        .as_ref()
        .filter(|action| action.created_at_ms > after_ms)
        .filter(|action| {
            action.artifact_id.as_deref().is_some_and(|artifact_id| {
                scored_candidate_feedback_artifact_ids(candidate)
                    .iter()
                    .any(|target_id| target_id == artifact_id)
            })
        })
        .filter(|action| action_kind_is_reconfirming(&action.action_kind, action.collapse_count))
        .filter(|action| matches!(action.action_role.as_str(), "primary" | "return"))
    {
        set_newer_reconfirming_evidence(
            &mut best,
            ReconfirmingEvidence {
                evidence_kind: "task_action".to_string(),
                evidence_id: action.id.clone(),
                timestamp_ms: action.created_at_ms,
                weight: 3,
                reason_code: "feedback:reconfirmed_by_direct_action_after_negative".to_string(),
            },
        );
    }

    Ok(best)
}

fn set_newer_reconfirming_evidence(
    best: &mut Option<ReconfirmingEvidence>,
    candidate: ReconfirmingEvidence,
) {
    if best
        .as_ref()
        .is_none_or(|current| candidate.timestamp_ms > current.timestamp_ms)
    {
        *best = Some(candidate);
    }
}

fn latest_direct_artifact_reconfirmation_after(
    conn: &Connection,
    artifact_id: &str,
    after_ms: i64,
) -> Result<Option<ReconfirmingEvidence>, String> {
    if !table_exists(conn, "continue_artifact_observations")? {
        return Ok(None);
    }
    conn.query_row(
        "SELECT id, timestamp_ms
         FROM continue_artifact_observations
         WHERE artifact_id = ?1
           AND timestamp_ms > ?2
         ORDER BY timestamp_ms DESC
         LIMIT 1",
        params![artifact_id, after_ms],
        |row| {
            Ok(ReconfirmingEvidence {
                evidence_kind: "artifact_observation".to_string(),
                evidence_id: row.get(0)?,
                timestamp_ms: row.get(1)?,
                weight: 2,
                reason_code: "feedback:reconfirmed_by_direct_artifact_observation_after_negative"
                    .to_string(),
            })
        },
    )
    .optional()
    .map_err(to_string)
}

fn latest_meaningful_action_reconfirmation_after(
    conn: &Connection,
    artifact_id: &str,
    after_ms: i64,
) -> Result<Option<ReconfirmingEvidence>, String> {
    if !table_exists(conn, "continue_task_actions")? {
        return Ok(None);
    }
    let mut stmt = conn
        .prepare(
            "SELECT id, action_kind, action_role, created_at_ms, collapse_count
             FROM continue_task_actions
             WHERE artifact_id = ?1
               AND created_at_ms > ?2
             ORDER BY created_at_ms DESC
             LIMIT 20",
        )
        .map_err(to_string)?;
    let rows = stmt
        .query_map(params![artifact_id, after_ms], |row| {
            Ok((
                row.get::<_, String>(0)?,
                row.get::<_, String>(1)?,
                row.get::<_, String>(2)?,
                row.get::<_, i64>(3)?,
                row.get::<_, i64>(4)?,
            ))
        })
        .map_err(to_string)?;
    for row in rows {
        let (id, action_kind, action_role, created_at_ms, collapse_count) =
            row.map_err(to_string)?;
        if !matches!(action_role.as_str(), "primary" | "return") {
            continue;
        }
        if !action_kind_is_reconfirming(&action_kind, collapse_count) {
            continue;
        }
        return Ok(Some(ReconfirmingEvidence {
            evidence_kind: "task_action".to_string(),
            evidence_id: id,
            timestamp_ms: created_at_ms,
            weight: 3,
            reason_code: "feedback:reconfirmed_by_direct_action_after_negative".to_string(),
        }));
    }
    Ok(None)
}

fn action_kind_is_reconfirming(action_kind: &str, collapse_count: i64) -> bool {
    matches!(
        action_kind,
        "editing"
            | "composing"
            | "running_command"
            | "observing_command_output"
            | "encountering_error"
            | "reviewing_output"
            | "copying_evidence"
            | "returning_to_origin"
    ) || (action_kind == "reading" && collapse_count >= 2)
}

fn compute_feedback_decision(
    aggregate: &FeedbackAggregate,
    reconfirming_evidence: Option<&ReconfirmingEvidence>,
    now_ms: i64,
) -> FeedbackDecision {
    let mut reason_codes = aggregate.reason_codes.clone();
    push_string_once(&mut reason_codes, FEEDBACK_POLICY_VERSION);
    let last_reconfirming_evidence_ms = [
        aggregate.last_reconfirming_evidence_ms,
        reconfirming_evidence.map(|evidence| evidence.timestamp_ms),
    ]
    .into_iter()
    .flatten()
    .max();
    let reconfirmed_after_negative = aggregate
        .last_negative_ms
        .zip(last_reconfirming_evidence_ms)
        .is_some_and(|(last_negative_ms, reconfirming_ms)| reconfirming_ms > last_negative_ms);
    if let Some(evidence) = reconfirming_evidence {
        push_string_once(&mut reason_codes, &evidence.reason_code);
    }

    if aggregate.last_negative_ms.is_none_or(|last_negative_ms| {
        last_negative_ms < now_ms.saturating_sub(FEEDBACK_NEGATIVE_LOOKBACK_MS)
    }) {
        return FeedbackDecision {
            state: FeedbackSuppressionState::None,
            negative_weight_since_reconfirmation: 0,
            positive_weight_after_last_negative: aggregate.positive_weight_after_last_negative,
            last_negative_ms: aggregate.last_negative_ms,
            last_positive_ms: aggregate.last_positive_ms,
            last_reconfirming_evidence_ms,
            suppress_primary: false,
            score_cap: None,
            reason_codes,
        };
    }

    if reconfirmed_after_negative {
        if reconfirming_evidence.is_some_and(|evidence| evidence.weight >= 3)
            || aggregate.positive_weight_after_last_negative >= 3
        {
            push_string_once(
                &mut reason_codes,
                "feedback:strong_reconfirmation_after_negative",
            );
            return FeedbackDecision {
                state: FeedbackSuppressionState::None,
                negative_weight_since_reconfirmation: 0,
                positive_weight_after_last_negative: aggregate.positive_weight_after_last_negative,
                last_negative_ms: aggregate.last_negative_ms,
                last_positive_ms: aggregate.last_positive_ms,
                last_reconfirming_evidence_ms,
                suppress_primary: false,
                score_cap: None,
                reason_codes,
            };
        }
        push_string_once(
            &mut reason_codes,
            "feedback:weak_reconfirmation_after_negative",
        );
        return FeedbackDecision {
            state: FeedbackSuppressionState::SoftPenalty,
            negative_weight_since_reconfirmation: 0,
            positive_weight_after_last_negative: aggregate.positive_weight_after_last_negative,
            last_negative_ms: aggregate.last_negative_ms,
            last_positive_ms: aggregate.last_positive_ms,
            last_reconfirming_evidence_ms,
            suppress_primary: false,
            score_cap: None,
            reason_codes,
        };
    }

    let hard_suppressed = aggregate.hard_negative_after_reconfirmation
        || aggregate.negative_weight_since_reconfirmation >= 3
        || aggregate.ignored_count_since_reconfirmation >= 2;
    if hard_suppressed {
        if aggregate.negative_weight_since_reconfirmation >= 3 {
            push_string_once(
                &mut reason_codes,
                "feedback:negative_weight_without_reconfirmation",
            );
        }
        return FeedbackDecision {
            state: FeedbackSuppressionState::HardSuppressed,
            negative_weight_since_reconfirmation: aggregate.negative_weight_since_reconfirmation,
            positive_weight_after_last_negative: aggregate.positive_weight_after_last_negative,
            last_negative_ms: aggregate.last_negative_ms,
            last_positive_ms: aggregate.last_positive_ms,
            last_reconfirming_evidence_ms,
            suppress_primary: true,
            score_cap: Some(0.18),
            reason_codes,
        };
    }

    if aggregate.negative_weight_since_reconfirmation >= 2 {
        push_string_once(
            &mut reason_codes,
            "feedback:soft_negative_without_reconfirmation",
        );
        return FeedbackDecision {
            state: FeedbackSuppressionState::ScoreCapped,
            negative_weight_since_reconfirmation: aggregate.negative_weight_since_reconfirmation,
            positive_weight_after_last_negative: aggregate.positive_weight_after_last_negative,
            last_negative_ms: aggregate.last_negative_ms,
            last_positive_ms: aggregate.last_positive_ms,
            last_reconfirming_evidence_ms,
            suppress_primary: false,
            score_cap: Some(FEEDBACK_SCORE_CAP_AFTER_SOFT_NEGATIVE),
            reason_codes,
        };
    }

    if aggregate.negative_weight_since_reconfirmation == 1 {
        push_string_once(
            &mut reason_codes,
            "feedback:single_soft_negative_without_reconfirmation",
        );
        return FeedbackDecision {
            state: FeedbackSuppressionState::SoftPenalty,
            negative_weight_since_reconfirmation: aggregate.negative_weight_since_reconfirmation,
            positive_weight_after_last_negative: aggregate.positive_weight_after_last_negative,
            last_negative_ms: aggregate.last_negative_ms,
            last_positive_ms: aggregate.last_positive_ms,
            last_reconfirming_evidence_ms,
            suppress_primary: false,
            score_cap: None,
            reason_codes,
        };
    }

    FeedbackDecision {
        state: FeedbackSuppressionState::None,
        negative_weight_since_reconfirmation: 0,
        positive_weight_after_last_negative: aggregate.positive_weight_after_last_negative,
        last_negative_ms: aggregate.last_negative_ms,
        last_positive_ms: aggregate.last_positive_ms,
        last_reconfirming_evidence_ms,
        suppress_primary: false,
        score_cap: None,
        reason_codes,
    }
}

fn feedback_negative_applies_to_candidate(
    row: &FeedbackEventRow,
    targets: &FeedbackEventTargets,
    target_key_set: &HashSet<&FeedbackTargetKey>,
) -> bool {
    targets.negative_targets.iter().any(|key| {
        target_key_set.contains(key)
            && (row.event_kind == "ignored_workstream"
                || key.scope != FeedbackTargetScope::Workstream)
    })
}

fn feedback_positive_applies_to_candidate(
    targets: &FeedbackEventTargets,
    target_key_set: &HashSet<&FeedbackTargetKey>,
) -> bool {
    targets
        .positive_targets
        .iter()
        .any(|key| target_key_set.contains(key))
}

fn feedback_candidate_has_fresh_reconfirmation(
    candidate: &ScoredContinueCandidate,
    last_negative_at_ms: Option<i64>,
) -> bool {
    let Some(last_negative_at_ms) = last_negative_at_ms else {
        return false;
    };
    let target_ids = [
        candidate
            .target_artifact
            .as_ref()
            .map(|artifact| artifact.id.as_str()),
        candidate
            .resume_work_target
            .as_ref()
            .map(|artifact| artifact.id.as_str()),
    ];
    let target_seen_after_negative = [
        candidate.target_artifact.as_ref(),
        candidate.resume_work_target.as_ref(),
    ]
    .into_iter()
    .flatten()
    .any(|artifact| artifact.last_seen_timestamp > last_negative_at_ms);
    let action_after_negative = candidate
        .last_meaningful_action
        .as_ref()
        .is_some_and(|action| {
            action.created_at_ms > last_negative_at_ms
                && target_ids
                    .iter()
                    .flatten()
                    .any(|target_id| action.artifact_id.as_deref() == Some(*target_id))
        });
    target_seen_after_negative || action_after_negative
}

fn candidate_feedback_hard_suppressed(candidate: &ScoredContinueCandidate) -> bool {
    candidate.feedback_suppression_state == FeedbackSuppressionState::HardSuppressed.as_str()
        || candidate
            .risk_flags
            .iter()
            .any(|flag| flag == "feedback_hard_suppressed")
}

fn candidate_feedback_reconfirmed_after_negative(candidate: &ScoredContinueCandidate) -> bool {
    match (
        candidate.feedback_last_negative_ms,
        candidate.feedback_last_reconfirming_evidence_ms,
    ) {
        (Some(last_negative_ms), Some(last_reconfirming_ms)) => {
            last_reconfirming_ms > last_negative_ms
        }
        _ => false,
    }
}

fn candidate_feedback_state_for_model(candidate: &ScoredContinueCandidate) -> String {
    match candidate.feedback_suppression_state.as_str() {
        "score_capped" => "score_capped",
        "soft_penalty" => "soft_penalty",
        "hard_suppressed" => "hard_suppressed",
        _ if candidate.feedback_negative_weight > 0 => "soft_penalty",
        _ => "none",
    }
    .to_string()
}

fn candidate_feedback_unreconfirmed_ignored_workstream(
    candidate: &ScoredContinueCandidate,
) -> bool {
    candidate
        .feedback_reason_codes
        .iter()
        .any(|code| code == "feedback:ignored_workstream")
        && !candidate_feedback_reconfirmed_after_negative(candidate)
}

fn candidate_primary_eligible_after_feedback_gate(candidate: &ScoredContinueCandidate) -> bool {
    candidate.eligible_for_primary_selection
        && !candidate_feedback_hard_suppressed(candidate)
        && !candidate_feedback_unreconfirmed_ignored_workstream(candidate)
        && !activity_role_is_suppressed(candidate.continuation_role.as_deref())
}

fn candidate_selectable_for_micro_inference(candidate: &ScoredContinueCandidate) -> bool {
    candidate_primary_eligible_after_feedback_gate(candidate)
        && candidate_branch_public_return_gate(candidate)
        && !branch_promotion_blocks_primary_selection(candidate)
}

fn candidate_available_after_feedback_gate(candidate: &ScoredContinueCandidate) -> bool {
    !candidate_feedback_hard_suppressed(candidate)
        && !candidate_feedback_unreconfirmed_ignored_workstream(candidate)
}

fn feedback_gate_suppressed_candidate_ids(candidates: &[ScoredContinueCandidate]) -> Vec<String> {
    candidates
        .iter()
        .filter(|candidate| !candidate_primary_eligible_after_feedback_gate(candidate))
        .map(|candidate| candidate.id.clone())
        .collect()
}

fn micro_inference_suppressed_candidate_ids(candidates: &[ScoredContinueCandidate]) -> Vec<String> {
    candidates
        .iter()
        .filter(|candidate| !candidate_selectable_for_micro_inference(candidate))
        .map(|candidate| candidate.id.clone())
        .collect()
}

fn branch_filter_excluded_candidate_ids(candidates: &[ScoredContinueCandidate]) -> Vec<String> {
    candidates
        .iter()
        .filter(|candidate| {
            candidate_primary_eligible_after_feedback_gate(candidate)
                && !candidate_selectable_for_micro_inference(candidate)
                && (branch_promotion_blocks_primary_selection(candidate)
                    || candidate.branch_public_return_eligible == Some(false)
                    || candidate_branch_promotion_state(candidate).is_some()
                    || candidate_is_support_evidence_for_model(candidate))
        })
        .map(|candidate| candidate.id.clone())
        .collect()
}

fn branch_filter_selectable_count_before(candidates: &[ScoredContinueCandidate]) -> usize {
    candidates
        .iter()
        .filter(|candidate| candidate_primary_eligible_after_feedback_gate(candidate))
        .count()
}

fn branch_validation_failures_from_failures(failures: &[String]) -> Vec<String> {
    failures
        .iter()
        .filter(|failure| failure.contains("branch") || failure.contains("interrupt") || failure.contains("diagnostic"))
        .cloned()
        .collect()
}

fn load_continue_breadcrumbs(
    conn: &Connection,
    workstream_id: &str,
) -> Result<Vec<ContinueBreadcrumbSummary>, String> {
    let mut stmt = conn
        .prepare(
            "SELECT id, workstream_id, text, source, created_at_ms
             FROM continue_breadcrumbs
             WHERE workstream_id = ?1
             ORDER BY created_at_ms DESC
             LIMIT 12",
        )
        .map_err(to_string)?;
    let rows = stmt
        .query_map(params![workstream_id], |row| {
            Ok(ContinueBreadcrumbSummary {
                id: row.get(0)?,
                workstream_id: row.get(1)?,
                text: row.get(2)?,
                source: row.get(3)?,
                created_at_ms: row.get(4)?,
            })
        })
        .map_err(to_string)?;
    rows.collect::<Result<Vec<_>, _>>().map_err(to_string)
}

fn workstream_detail_anchors(
    artifacts: &[ContinueWorkstreamArtifactDetail],
    episodes: &[ContinueWorkstreamEpisodeDetail],
    candidates: &[ContinueWorkstreamCandidateDetail],
) -> ContinueEvidenceAnchors {
    let mut frame_ids = Vec::new();
    let mut action_ids = Vec::new();
    let mut episode_ids = Vec::new();
    let mut artifact_ids = Vec::new();
    let mut seen_frames = HashSet::new();
    let mut seen_actions = HashSet::new();
    let mut seen_episodes = HashSet::new();
    let mut seen_artifacts = HashSet::new();

    for artifact in artifacts {
        if seen_artifacts.insert(artifact.artifact_id.clone()) {
            artifact_ids.push(artifact.artifact_id.clone());
        }
        for frame_id in [
            artifact.first_seen_frame_id.as_ref(),
            artifact.last_seen_frame_id.as_ref(),
        ]
        .into_iter()
        .flatten()
        {
            if seen_frames.insert(frame_id.clone()) {
                frame_ids.push(frame_id.clone());
            }
        }
    }
    for episode in episodes {
        if seen_episodes.insert(episode.id.clone()) {
            episode_ids.push(episode.id.clone());
        }
        for frame_id in [
            episode.start_frame_id.as_ref(),
            episode.end_frame_id.as_ref(),
        ]
        .into_iter()
        .flatten()
        {
            if seen_frames.insert(frame_id.clone()) {
                frame_ids.push(frame_id.clone());
            }
        }
        for action in &episode.actions {
            if seen_actions.insert(action.action_id.clone()) {
                action_ids.push(action.action_id.clone());
            }
            if seen_frames.insert(action.frame_id.clone()) {
                frame_ids.push(action.frame_id.clone());
            }
            if let Some(artifact_id) = &action.artifact_id {
                if seen_artifacts.insert(artifact_id.clone()) {
                    artifact_ids.push(artifact_id.clone());
                }
            }
        }
    }
    for candidate in candidates {
        if let Some(frame_id) = &candidate.evidence_frame_id {
            if seen_frames.insert(frame_id.clone()) {
                frame_ids.push(frame_id.clone());
            }
        }
        if let Some(action_id) = &candidate.last_meaningful_action_id {
            if seen_actions.insert(action_id.clone()) {
                action_ids.push(action_id.clone());
            }
        }
        if let Some(episode_id) = &candidate.supporting_episode_id {
            if seen_episodes.insert(episode_id.clone()) {
                episode_ids.push(episode_id.clone());
            }
        }
        if let Some(artifact_id) = &candidate.target_artifact_id {
            if seen_artifacts.insert(artifact_id.clone()) {
                artifact_ids.push(artifact_id.clone());
            }
        }
    }

    ContinueEvidenceAnchors {
        frame_ids: frame_ids.into_iter().take(24).collect(),
        action_ids: action_ids.into_iter().take(24).collect(),
        episode_ids: episode_ids.into_iter().take(24).collect(),
        artifact_ids: artifact_ids.into_iter().take(24).collect(),
    }
}

fn load_scorer_workstream_episodes(
    conn: &Connection,
    workstream_id: &str,
) -> Result<Vec<ScorerEpisode>, String> {
    let mut stmt = conn
        .prepare(
            "SELECT e.id, e.end_frame_id, COALESCE(e.end_timestamp_ms, e.start_timestamp_ms),
                    e.dominant_action_kind, e.evidence_quality
             FROM continue_workstream_episodes we
             JOIN continue_episodes e ON e.id = we.episode_id
             WHERE we.workstream_id = ?1
             ORDER BY we.order_index ASC",
        )
        .map_err(to_string)?;
    let rows = stmt
        .query_map(params![workstream_id], |row| {
            Ok(ScorerEpisode {
                id: row.get(0)?,
                end_frame_id: row.get(1)?,
                end_timestamp_ms: row.get(2)?,
                dominant_action_kind: row.get(3)?,
                evidence_quality: row.get(4)?,
            })
        })
        .map_err(to_string)?;
    rows.collect::<Result<Vec<_>, _>>().map_err(to_string)
}

fn load_last_meaningful_action(
    conn: &Connection,
    workstream_id: &str,
) -> Result<Option<ScorerAction>, String> {
    conn.query_row(
        "SELECT ta.id, ta.frame_id, ta.artifact_id, ta.secondary_artifact_id,
                ta.action_kind, ta.action_role, ta.confidence, ta.reason, ta.created_at_ms,
                ta.collapse_count, ta.first_frame_id, ta.last_frame_id, ta.strongest_frame_id,
                ta.semantic_delta_kind, ta.semantic_subject, ta.semantic_after_hint,
                ta.semantic_evidence_quote
         FROM continue_workstream_episodes we
         JOIN continue_episode_actions ea ON ea.episode_id = we.episode_id
         JOIN continue_task_actions ta ON ta.id = ea.action_id
         WHERE we.workstream_id = ?1
           AND ta.action_kind IN (
             'editing', 'composing', 'copying_evidence', 'running_command',
             'observing_command_output', 'reviewing_output', 'encountering_error',
             'returning_to_origin', 'branching_away', 'searching', 'idle_after_progress'
           )
         ORDER BY ta.created_at_ms DESC, CAST(ta.frame_id AS INTEGER) DESC
         LIMIT 1",
        params![workstream_id],
        |row| {
            Ok(ScorerAction {
                id: row.get(0)?,
                frame_id: row.get(1)?,
                artifact_id: row.get(2)?,
                secondary_artifact_id: row.get(3)?,
                action_kind: row.get(4)?,
                action_role: row.get(5)?,
                confidence: row.get(6)?,
                reason: row.get(7)?,
                created_at_ms: row.get(8)?,
                collapse_count: row.get::<_, i64>(9)?.max(1),
                first_frame_id: row.get(10)?,
                last_frame_id: row.get(11)?,
                strongest_frame_id: row.get(12)?,
                semantic_delta_kind: row.get(13)?,
                semantic_subject: row.get(14)?,
                semantic_after_hint: row.get(15)?,
                semantic_evidence_quote: row.get(16)?,
            })
        },
    )
    .optional()
    .map_err(to_string)
}

#[derive(Debug, Clone)]
struct ContinueMemoryCellRecord {
    id: String,
    workstream_id: Option<String>,
    artifact_id: Option<String>,
    episode_id: Option<String>,
    action_id: Option<String>,
    memory_type: String,
    summary: String,
    keywords: Vec<String>,
    tags: Vec<String>,
    source_anchor: Value,
    last_seen_at_ms: i64,
    confidence: f64,
    importance: f64,
    decay_score: f64,
    privacy_status: Option<String>,
    redaction_level: String,
    feedback_score: f64,
}

fn promote_continue_memory_cells(conn: &Connection, now_ms: i64) -> Result<usize, String> {
    let promoted = promote_workstream_artifact_memory_cells(conn, now_ms)?
        + promote_open_loop_memory_cells(conn, now_ms)?
        + promote_feedback_memory_cells(conn, now_ms)?
        + promote_breadcrumb_memory_cells(conn, now_ms)?;
    rebuild_continue_memory_edges(conn, now_ms)?;
    Ok(promoted)
}

fn promote_workstream_artifact_memory_cells(
    conn: &Connection,
    now_ms: i64,
) -> Result<usize, String> {
    let mut stmt = conn
        .prepare(
            "SELECT wa.workstream_id, wa.artifact_id, wa.durable_role,
                    wa.importance_score, wa.first_seen_frame_id, wa.last_seen_frame_id,
                    wa.reason, w.state, w.title_candidate, w.unresolved_signal,
                    w.last_active_timestamp_ms, a.artifact_kind, a.display_title,
                    a.browser_url, a.document_path, a.privacy_status, a.evidence_quality,
                    a.openability, a.last_seen_timestamp
             FROM continue_workstream_artifacts wa
             JOIN continue_workstreams w ON w.id = wa.workstream_id
             JOIN continue_artifacts a ON a.id = wa.artifact_id
             ORDER BY w.last_active_timestamp_ms DESC, wa.importance_score DESC
             LIMIT 500",
        )
        .map_err(to_string)?;
    let rows = stmt
        .query_map([], |row| {
            Ok((
                row.get::<_, String>(0)?,
                row.get::<_, String>(1)?,
                row.get::<_, String>(2)?,
                row.get::<_, f64>(3)?,
                row.get::<_, Option<String>>(4)?,
                row.get::<_, Option<String>>(5)?,
                row.get::<_, Option<String>>(6)?,
                row.get::<_, String>(7)?,
                row.get::<_, Option<String>>(8)?,
                row.get::<_, Option<String>>(9)?,
                row.get::<_, i64>(10)?,
                row.get::<_, String>(11)?,
                row.get::<_, Option<String>>(12)?,
                row.get::<_, Option<String>>(13)?,
                row.get::<_, Option<String>>(14)?,
                row.get::<_, Option<String>>(15)?,
                row.get::<_, String>(16)?,
                row.get::<_, String>(17)?,
                row.get::<_, i64>(18)?,
            ))
        })
        .map_err(to_string)?;
    let mut promoted = 0_usize;
    for row in rows {
        let (
            workstream_id,
            artifact_id,
            durable_role,
            importance_score,
            first_frame_id,
            last_frame_id,
            reason,
            state,
            title_candidate,
            unresolved_signal,
            last_active_ms,
            artifact_kind,
            display_title,
            browser_url,
            document_path,
            privacy_status,
            evidence_quality,
            openability,
            last_seen_timestamp,
        ) = row.map_err(to_string)?;
        if memory_surface_excluded(
            display_title.as_deref(),
            browser_url.as_deref(),
            document_path.as_deref(),
            privacy_status.as_deref(),
        ) {
            continue;
        }
        let Some(memory_type) =
            memory_type_for_durable_role(&durable_role, unresolved_signal.as_deref())
        else {
            continue;
        };
        let title = model_safe_label(
            first_non_empty([
                display_title.as_deref(),
                title_candidate.as_deref(),
                Some(artifact_kind.as_str()),
            ])
            .unwrap_or("work artifact"),
            120,
        );
        let summary = match memory_type {
            "origin_intent" => format!("Origin work target was {}.", title),
            "branch_evidence" => format!("Support evidence was opened for {}.", title),
            "unresolved_blocker" => format!("Unresolved blocker was associated with {}.", title),
            "verification_result" => {
                format!(
                    "Verification or output surface was associated with {}.",
                    title
                )
            }
            "active_edit" => format!("Active work continued on {}.", title),
            _ => format!("Work memory for {}.", title),
        };
        let mut keywords = memory_keywords(&[
            Some(workstream_id.as_str()),
            Some(artifact_id.as_str()),
            Some(memory_type),
            Some(durable_role.as_str()),
            Some(artifact_kind.as_str()),
            title_candidate.as_deref(),
            display_title.as_deref(),
            unresolved_signal.as_deref(),
            reason.as_deref(),
        ]);
        keywords.truncate(16);
        let tags = vec![durable_role.clone(), artifact_kind.clone(), state.clone()];
        let source_anchor = serde_json::json!({
            "kind": "workstream_artifact",
            "workstream_id": workstream_id,
            "artifact_id": artifact_id,
            "durable_role": durable_role,
            "first_frame_id": first_frame_id,
            "last_frame_id": last_frame_id,
            "evidence_quality": evidence_quality,
            "openability": openability,
        });
        let id = format!(
            "continue-memory-{}",
            stable_hash(
                format!(
                    "workstream_artifact:{}:{}:{}",
                    workstream_id, artifact_id, memory_type
                )
                .as_bytes()
            )
        );
        upsert_continue_memory_cell(
            conn,
            &id,
            Some(&workstream_id),
            Some(&artifact_id),
            None,
            None,
            memory_type,
            &summary,
            &keywords,
            &tags,
            &source_anchor,
            last_active_ms.min(last_seen_timestamp),
            last_active_ms.max(last_seen_timestamp),
            importance_score.clamp(0.1, 1.0),
            importance_score.clamp(0.1, 1.0),
            privacy_status.as_deref(),
            "summary_only",
            0.0,
            now_ms,
            "p3_workstream_artifact_promotion",
        )?;
        promoted += 1;
    }
    Ok(promoted)
}

fn promote_open_loop_memory_cells(conn: &Connection, now_ms: i64) -> Result<usize, String> {
    let mut stmt = conn
        .prepare(
            "SELECT id, workstream_id, boundary_kind, quality, confidence,
                    origin_artifact_id, primary_return_artifact_id, resume_work_artifact_id,
                    blocker_artifact_id, verification_artifact_id, objective_hint,
                    last_concrete_progress, unfinished_state, next_evidence_backed_action,
                    last_updated_at_ms
             FROM continue_open_loops
             ORDER BY last_updated_at_ms DESC
             LIMIT 300",
        )
        .map_err(to_string)?;
    let rows = stmt
        .query_map([], |row| {
            Ok((
                row.get::<_, String>(0)?,
                row.get::<_, String>(1)?,
                row.get::<_, String>(2)?,
                row.get::<_, String>(3)?,
                row.get::<_, f64>(4)?,
                row.get::<_, Option<String>>(5)?,
                row.get::<_, Option<String>>(6)?,
                row.get::<_, Option<String>>(7)?,
                row.get::<_, Option<String>>(8)?,
                row.get::<_, Option<String>>(9)?,
                row.get::<_, Option<String>>(10)?,
                row.get::<_, Option<String>>(11)?,
                row.get::<_, Option<String>>(12)?,
                row.get::<_, Option<String>>(13)?,
                row.get::<_, i64>(14)?,
            ))
        })
        .map_err(to_string)?;
    let mut promoted = 0_usize;
    for row in rows {
        let (
            open_loop_id,
            workstream_id,
            boundary_kind,
            quality,
            confidence,
            origin_artifact_id,
            primary_return_artifact_id,
            resume_work_artifact_id,
            blocker_artifact_id,
            verification_artifact_id,
            objective_hint,
            last_concrete_progress,
            unfinished_state,
            next_action,
            last_updated_at_ms,
        ) = row.map_err(to_string)?;
        let memory_type = match boundary_kind.as_str() {
            "error_without_resolution" => "unresolved_blocker",
            "draft_active" => "draft_state",
            "search_branch_without_return" => "return_to_origin",
            "verification_without_return" => "output_waiting",
            "completed_progress" => "completed_progress",
            _ => "resume_instruction",
        };
        let target_artifact_id = primary_return_artifact_id
            .as_ref()
            .or(resume_work_artifact_id.as_ref())
            .or(blocker_artifact_id.as_ref())
            .or(origin_artifact_id.as_ref());
        let summary = first_non_empty([
            unfinished_state.as_deref(),
            next_action.as_deref(),
            last_concrete_progress.as_deref(),
            objective_hint.as_deref(),
            Some(boundary_kind.as_str()),
        ])
        .map(|value| model_safe_label(value, 180))
        .unwrap_or_else(|| "Open continuation state was observed.".to_string());
        let keywords = memory_keywords(&[
            Some(workstream_id.as_str()),
            Some(open_loop_id.as_str()),
            Some(boundary_kind.as_str()),
            Some(quality.as_str()),
            objective_hint.as_deref(),
            unfinished_state.as_deref(),
            next_action.as_deref(),
        ]);
        let source_anchor = serde_json::json!({
            "kind": "open_loop",
            "open_loop_id": open_loop_id,
            "boundary_kind": boundary_kind,
            "quality": quality,
            "origin_artifact_id": origin_artifact_id,
            "primary_return_artifact_id": primary_return_artifact_id,
            "resume_work_artifact_id": resume_work_artifact_id,
            "blocker_artifact_id": blocker_artifact_id,
            "verification_artifact_id": verification_artifact_id,
        });
        let id = format!(
            "continue-memory-{}",
            stable_hash(format!("open_loop:{}:{}", open_loop_id, memory_type).as_bytes())
        );
        upsert_continue_memory_cell(
            conn,
            &id,
            Some(&workstream_id),
            target_artifact_id.map(String::as_str),
            None,
            None,
            memory_type,
            &summary,
            &keywords,
            &[boundary_kind.clone(), quality.clone()],
            &source_anchor,
            last_updated_at_ms,
            last_updated_at_ms,
            confidence.clamp(0.1, 1.0),
            confidence.clamp(0.1, 1.0),
            None,
            "summary_only",
            0.0,
            now_ms,
            "p3_open_loop_promotion",
        )?;
        promoted += 1;
    }
    Ok(promoted)
}

fn promote_feedback_memory_cells(conn: &Connection, now_ms: i64) -> Result<usize, String> {
    let mut stmt = conn
        .prepare(
            "SELECT id, decision_id, selected_candidate_id, workstream_id, event_kind,
                    target_artifact_id, chosen_artifact_id, timestamp_ms, confidence, source
             FROM continue_feedback_events
             ORDER BY timestamp_ms DESC
             LIMIT 300",
        )
        .map_err(to_string)?;
    let rows = stmt
        .query_map([], |row| {
            Ok((
                row.get::<_, String>(0)?,
                row.get::<_, Option<String>>(1)?,
                row.get::<_, Option<String>>(2)?,
                row.get::<_, Option<String>>(3)?,
                row.get::<_, String>(4)?,
                row.get::<_, Option<String>>(5)?,
                row.get::<_, Option<String>>(6)?,
                row.get::<_, i64>(7)?,
                row.get::<_, f64>(8)?,
                row.get::<_, Option<String>>(9)?,
            ))
        })
        .map_err(to_string)?;
    let mut promoted = 0_usize;
    for row in rows {
        let (
            feedback_id,
            decision_id,
            selected_candidate_id,
            workstream_id,
            event_kind,
            target_artifact_id,
            chosen_artifact_id,
            timestamp_ms,
            confidence,
            source,
        ) = row.map_err(to_string)?;
        let memory_type = match event_kind.as_str() {
            "accepted" | "inferred_acceptance" => "feedback_acceptance",
            "corrected" | "explicit_correction" => "feedback_correction",
            "rejected" | "ignored" | "inferred_rejection" => "feedback_rejection",
            _ => "feedback_rejection",
        };
        let artifact_id = chosen_artifact_id.as_ref().or(target_artifact_id.as_ref());
        let feedback_score = match memory_type {
            "feedback_acceptance" => 0.55,
            "feedback_correction" => 0.75,
            "feedback_rejection" => -0.55,
            _ => 0.0,
        };
        let summary = match memory_type {
            "feedback_acceptance" => "User behavior accepted this continuation target.",
            "feedback_correction" => "User corrected the continuation target.",
            "feedback_rejection" => "User behavior rejected or ignored this continuation target.",
            _ => "Feedback changed continuation prior.",
        };
        let keywords = memory_keywords(&[
            workstream_id.as_deref(),
            target_artifact_id.as_deref(),
            chosen_artifact_id.as_deref(),
            selected_candidate_id.as_deref(),
            Some(event_kind.as_str()),
            source.as_deref(),
        ]);
        let source_anchor = serde_json::json!({
            "kind": "feedback",
            "feedback_id": feedback_id,
            "decision_id": decision_id,
            "selected_candidate_id": selected_candidate_id,
            "event_kind": event_kind,
            "target_artifact_id": target_artifact_id,
            "chosen_artifact_id": chosen_artifact_id,
            "source": source,
        });
        let id = format!(
            "continue-memory-{}",
            stable_hash(format!("feedback:{}:{}", feedback_id, memory_type).as_bytes())
        );
        upsert_continue_memory_cell(
            conn,
            &id,
            workstream_id.as_deref(),
            artifact_id.map(String::as_str),
            None,
            None,
            memory_type,
            summary,
            &keywords,
            &[event_kind.clone()],
            &source_anchor,
            timestamp_ms,
            timestamp_ms,
            confidence.clamp(0.1, 1.0),
            0.9,
            None,
            "summary_only",
            feedback_score,
            now_ms,
            "p3_feedback_promotion",
        )?;
        promoted += 1;
    }
    Ok(promoted)
}

