fn summarize_continue_eval_fixture(
    fixture: ContinueEvalFixture,
) -> Result<ContinueEvalReport, String> {
    let k = fixture.k.unwrap_or(3).max(1) as usize;
    let mut reports = Vec::new();
    for case in fixture.cases {
        reports.push(evaluate_continue_fixture_case(case, k)?);
    }
    let case_count = reports.len() as i64;
    let target_artifact_correct = reports
        .iter()
        .filter(|case| case.target_artifact_correct)
        .count() as i64;
    let hallucinated_artifact_count = reports
        .iter()
        .map(|case| case.hallucinated_artifact_count)
        .sum::<i64>();
    let fallback_count = reports
        .iter()
        .filter(|case| case.validation_status == "fallback")
        .count() as i64;
    let current_focus_false_positive_count = reports
        .iter()
        .filter(|case| case.current_focus_false_positive)
        .count() as i64;
    let feedback_obedience_case_count = reports
        .iter()
        .filter(|case| case.feedback_obedience_case)
        .count() as i64;
    let feedback_suppressed_target_exposed_count = reports
        .iter()
        .filter(|case| case.feedback_suppressed_target_exposed)
        .count() as i64;
    let corrected_artifact_preferred_count = reports
        .iter()
        .filter(|case| case.corrected_artifact_preferred)
        .count() as i64;
    let feedback_cache_stale_hit_count = reports
        .iter()
        .filter(|case| case.feedback_cache_stale_hit)
        .count() as i64;
    let model_feedback_validation_failure_count = reports
        .iter()
        .filter(|case| case.model_feedback_validation_failure)
        .count() as i64;
    let unpromoted_branch_selected_count = reports
        .iter()
        .filter(|case| case.unpromoted_branch_selected)
        .count() as i64;
    let branch_case_count = reports
        .iter()
        .filter(|case| {
            let scenario = case.scenario.to_ascii_lowercase();
            scenario.contains("branch")
                || scenario.contains("search")
                || scenario.contains("docs")
                || scenario.contains("gmail")
                || scenario.contains("diagnostic")
                || scenario.contains("terminal")
                || scenario.contains("support")
                || case.unpromoted_branch_selected
                || case.model_branch_policy_violation
                || !case.branch_origin_recalled
        })
        .count() as i64;
    let branch_origin_recalled_count = reports
        .iter()
        .filter(|case| {
            let scenario = case.scenario.to_ascii_lowercase();
            (scenario.contains("branch")
                || scenario.contains("search")
                || scenario.contains("docs")
                || scenario.contains("gmail")
                || scenario.contains("diagnostic")
                || scenario.contains("terminal")
                || scenario.contains("support")
                || case.unpromoted_branch_selected
                || case.model_branch_policy_violation
                || !case.branch_origin_recalled)
                && case.branch_origin_recalled
        })
        .count() as i64;
    let promoted_branch_selected_count = reports
        .iter()
        .filter(|case| {
            case.selected_candidate_id
                .as_deref()
                .is_some_and(|id| id.contains("gmail-draft") || id.contains("terminal-error"))
        })
        .count() as i64;
    let message_interrupt_case_count = reports
        .iter()
        .filter(|case| case.scenario.to_ascii_lowercase().contains("gmail"))
        .count() as i64;
    let promoted_branch_selection_correct_count = reports
        .iter()
        .filter(|case| {
            case.selected_candidate_id
                .as_deref()
                .is_some_and(|id| id.contains("gmail-draft") || id.contains("terminal-error"))
                && case.promoted_branch_selection_correct
        })
        .count() as i64;
    let model_branch_policy_violation_count = reports
        .iter()
        .filter(|case| case.model_branch_policy_violation)
        .count() as i64;
    let denom = if case_count == 0 {
        1.0
    } else {
        case_count as f64
    };
    Ok(ContinueEvalReport {
        schema: "smalltalk.continue_eval.v1".to_string(),
        evaluated_at_ms: current_time_millis(),
        case_count,
        target_artifact_correct,
        target_artifact_accuracy: round_score(target_artifact_correct as f64 / denom),
        recall_at_k: round_score(
            reports.iter().filter(|case| case.recall_at_k).count() as f64 / denom,
        ),
        mrr: round_score(reports.iter().map(|case| case.reciprocal_rank).sum::<f64>() / denom),
        current_focus_false_positive_rate: round_score(
            current_focus_false_positive_count as f64 / denom,
        ),
        hallucinated_artifact_count,
        model_validation_fallback_rate: round_score(fallback_count as f64 / denom),
        last_state_specificity: metric_ratio(&reports, |case| case.last_state_specificity),
        next_action_specificity: metric_ratio(&reports, |case| case.next_action_specificity),
        support_branch_handling: metric_ratio(&reports, |case| case.support_branch_handling),
        thin_evidence_honesty: metric_ratio(&reports, |case| case.thin_evidence_honesty),
        current_focus_vs_return_clarity: metric_ratio(&reports, |case| {
            case.current_focus_vs_return_clarity
        }),
        source_provenance_correctness: metric_ratio(&reports, |case| {
            case.source_provenance_correctness
        }),
        open_loop_recovery: metric_ratio(&reports, |case| case.open_loop_recovery),
        no_clear_continuation_correctness: metric_ratio(&reports, |case| {
            case.no_clear_continuation_correctness
        }),
        quality_gate_correctness: metric_ratio(&reports, |case| case.quality_gate_correctness),
        cache_freshness_correctness: metric_ratio(&reports, |case| {
            case.cache_freshness_correctness
        }),
        fresh_surface_retention_rate: metric_ratio(&reports, |case| case.fresh_surface_retained),
        stale_target_suppression_rate: metric_ratio(&reports, |case| case.stale_target_suppressed),
        support_branch_false_promotion_rate: metric_ratio(&reports, |case| {
            case.support_branch_false_promotion
        }),
        support_branch_false_positive_rate: metric_ratio(&reports, |case| {
            case.support_branch_false_positive
        }),
        unpromoted_branch_selected_count,
        branch_origin_recall_rate: round_score(
            branch_origin_recalled_count as f64
                / if branch_case_count == 0 {
                    1.0
                } else {
                    branch_case_count as f64
                },
        ),
        promoted_branch_selection_precision: round_score(
            promoted_branch_selection_correct_count as f64
                / if promoted_branch_selected_count == 0 {
                    1.0
                } else {
                    promoted_branch_selected_count as f64
                },
        ),
        message_interrupt_false_positive_rate: round_score(
            reports
                .iter()
                .filter(|case| case.message_interrupt_false_positive)
                .count() as f64
                / if message_interrupt_case_count == 0 {
                    1.0
                } else {
                    message_interrupt_case_count as f64
                },
        ),
        diagnostic_self_selected_count: reports
            .iter()
            .filter(|case| case.diagnostic_self_selected)
            .count() as i64,
        model_branch_policy_violation_count,
        truthful_thin_mode_rate: metric_ratio(&reports, |case| case.truthful_thin_mode),
        feedback_obedience_case_count,
        feedback_suppressed_target_exposed_count,
        feedback_suppressed_target_exposed_rate: round_score(
            feedback_suppressed_target_exposed_count as f64
                / if feedback_obedience_case_count == 0 {
                    1.0
                } else {
                    feedback_obedience_case_count as f64
                },
        ),
        corrected_artifact_preferred_count,
        feedback_cache_stale_hit_count,
        model_feedback_validation_failure_count,
        feedback_obedience_placeholder_rate: metric_ratio(&reports, |case| {
            case.feedback_obedience_placeholder
        }),
        suppressed_target_open_attempt_count: reports
            .iter()
            .filter(|case| case.suppressed_target_open_attempted)
            .count(),
        cases: reports,
    })
}

pub fn run_continue_replay_eval(
    conn: &Connection,
    input: Option<ContinueReplayEvalInput>,
) -> Result<ContinueReplayEvalReport, String> {
    ensure_continue_schema(conn)?;
    let input = input.unwrap_or(ContinueReplayEvalInput {
        include_inactive: None,
        fixture_kind: None,
        limit: None,
    });
    let include_inactive = input.include_inactive.unwrap_or(false);
    let limit = input.limit.unwrap_or(100).clamp(1, 500);
    let mut sql = "SELECT id, fixture_kind, source_decision_id, expected_return_artifact_id,
                          expected_workstream_id, expected_no_clear, input_snapshot_json,
                          expected_assertions_json
                   FROM continue_eval_fixtures"
        .to_string();
    let mut filters = Vec::new();
    if !include_inactive {
        filters.push("status = 'active'".to_string());
    }
    if input
        .fixture_kind
        .as_deref()
        .is_some_and(|value| !value.trim().is_empty())
    {
        filters.push("fixture_kind = ?1".to_string());
    }
    if !filters.is_empty() {
        sql.push_str(" WHERE ");
        sql.push_str(&filters.join(" AND "));
    }
    sql.push_str(" ORDER BY created_at_ms DESC LIMIT ");
    sql.push_str(&limit.to_string());

    let mut stmt = conn.prepare(&sql).map_err(to_string)?;
    let rows = if let Some(kind) = input
        .fixture_kind
        .as_deref()
        .filter(|value| !value.is_empty())
    {
        stmt.query_map(params![kind], |row| replay_fixture_row_to_report(conn, row))
            .map_err(to_string)?
            .collect::<Result<Vec<_>, _>>()
            .map_err(to_string)?
    } else {
        stmt.query_map([], |row| replay_fixture_row_to_report(conn, row))
            .map_err(to_string)?
            .collect::<Result<Vec<_>, _>>()
            .map_err(to_string)?
    };
    let fixture_count = rows.len() as i64;
    let denom = if fixture_count == 0 {
        1.0
    } else {
        fixture_count as f64
    };
    let target_correct = rows
        .iter()
        .filter(|case| case.target_artifact_correct)
        .count() as f64;
    let workstream_correct = rows.iter().filter(|case| case.workstream_correct).count() as f64;
    let no_clear_correct = rows.iter().filter(|case| case.no_clear_correct).count() as f64;
    let recall = rows
        .iter()
        .filter(|case| case.candidate_rank.is_some_and(|rank| rank <= 3))
        .count() as f64;
    let mrr = rows.iter().map(|case| case.reciprocal_rank).sum::<f64>();
    let branch_fp = rows
        .iter()
        .filter(|case| case.branch_support_false_positive)
        .count() as f64;
    let focus_fp = rows
        .iter()
        .filter(|case| case.current_focus_false_positive)
        .count() as f64;
    let stale_fp = rows
        .iter()
        .filter(|case| case.stale_target_false_positive)
        .count() as f64;
    let privacy_violation_count = rows.iter().filter(|case| case.privacy_violation).count() as i64;
    let feedback_regression_count = rows.iter().filter(|case| case.regression).count() as i64;
    Ok(ContinueReplayEvalReport {
        schema: "smalltalk.continue_replay_eval.v1".to_string(),
        evaluated_at_ms: current_time_millis(),
        fixture_count,
        target_artifact_accuracy: round_score(target_correct / denom),
        workstream_accuracy: round_score(workstream_correct / denom),
        no_clear_accuracy: round_score(no_clear_correct / denom),
        candidate_recall_at_k: round_score(recall / denom),
        mrr: round_score(mrr / denom),
        branch_support_false_positive_rate: round_score(branch_fp / denom),
        current_focus_false_positive_rate: round_score(focus_fp / denom),
        stale_target_false_positive_rate: round_score(stale_fp / denom),
        feedback_regression_count,
        privacy_violation_count,
        cases: rows,
    })
}

fn replay_fixture_row_to_report(
    conn: &Connection,
    row: &rusqlite::Row<'_>,
) -> rusqlite::Result<ContinueReplayEvalCaseReport> {
    let fixture_id: String = row.get(0)?;
    let fixture_kind: String = row.get(1)?;
    let source_decision_id: Option<String> = row.get(2)?;
    let expected_return_artifact_id: Option<String> = row.get(3)?;
    let expected_workstream_id: Option<String> = row.get(4)?;
    let expected_no_clear = row.get::<_, i64>(5)? != 0;
    let input_snapshot_json: String = row.get(6)?;
    let expected_assertions_json: String = row.get(7)?;
    let input_snapshot: Value =
        serde_json::from_str(&input_snapshot_json).unwrap_or_else(|_| serde_json::json!({}));
    let expected_assertions: Value =
        serde_json::from_str(&expected_assertions_json).unwrap_or_else(|_| serde_json::json!({}));
    Ok(evaluate_replay_fixture_snapshot(
        conn,
        fixture_id,
        fixture_kind,
        source_decision_id,
        expected_return_artifact_id,
        expected_workstream_id,
        expected_no_clear,
        input_snapshot,
        expected_assertions,
    ))
}

#[allow(clippy::too_many_arguments)]
fn evaluate_replay_fixture_snapshot(
    conn: &Connection,
    fixture_id: String,
    fixture_kind: String,
    source_decision_id: Option<String>,
    expected_return_artifact_id: Option<String>,
    expected_workstream_id: Option<String>,
    expected_no_clear: bool,
    input_snapshot: Value,
    expected_assertions: Value,
) -> ContinueReplayEvalCaseReport {
    let current_focus_artifact_id = input_snapshot
        .get("current_focus_artifact_id")
        .and_then(Value::as_str)
        .map(str::to_string);
    let mut candidates = input_snapshot
        .get("candidates")
        .and_then(Value::as_array)
        .cloned()
        .unwrap_or_default();
    candidates.sort_by(|left, right| {
        replay_adjusted_candidate_score(conn, right)
            .partial_cmp(&replay_adjusted_candidate_score(conn, left))
            .unwrap_or(std::cmp::Ordering::Equal)
    });
    let selected = candidates.first();
    let actual_return_artifact_id = selected
        .and_then(|candidate| candidate.get("target_artifact_id"))
        .and_then(Value::as_str)
        .map(str::to_string);
    let actual_workstream_id = selected
        .and_then(|candidate| candidate.get("workstream_id"))
        .and_then(Value::as_str)
        .map(str::to_string);
    let candidate_rank = expected_return_artifact_id.as_ref().and_then(|expected| {
        candidates
            .iter()
            .position(|candidate| {
                candidate
                    .get("target_artifact_id")
                    .and_then(Value::as_str)
                    .is_some_and(|target| target == expected)
            })
            .map(|index| index as i64 + 1)
    });
    let reciprocal_rank = candidate_rank.map(|rank| 1.0 / rank as f64).unwrap_or(0.0);
    let target_artifact_correct = if expected_no_clear {
        actual_return_artifact_id.is_none()
    } else {
        expected_return_artifact_id == actual_return_artifact_id
    };
    let selected_score = selected
        .map(|candidate| replay_adjusted_candidate_score(conn, candidate))
        .unwrap_or(0.0);
    let no_clear_correct = if expected_no_clear {
        selected_score < 0.45
    } else {
        !expected_no_clear
    };
    let workstream_correct = expected_workstream_id
        .as_ref()
        .map(|expected| actual_workstream_id.as_deref() == Some(expected.as_str()))
        .unwrap_or(true);
    let warnings = selected
        .and_then(|candidate| candidate.get("warnings"))
        .and_then(Value::as_str)
        .unwrap_or_default()
        .to_string();
    let branch_support_false_positive =
        !target_artifact_correct && warnings.contains("branch_support_not_default_return_target");
    let current_focus_false_positive = !target_artifact_correct
        && actual_return_artifact_id.is_some()
        && actual_return_artifact_id == current_focus_artifact_id;
    let stale_target_false_positive =
        !target_artifact_correct && warnings.contains("stale_selected_target");
    let serialized_assertions = expected_assertions.to_string();
    let serialized_input = input_snapshot.to_string();
    let privacy_violation = serialized_assertions.contains("\"note\"")
        || serialized_input.contains("\"note\":\"")
        || serialized_input.contains("\"raw_text\"");
    let regression = !target_artifact_correct || !workstream_correct || !no_clear_correct;
    let mut notes = Vec::new();
    if expected_no_clear && selected_score >= 0.45 {
        notes.push(format!(
            "expected no clear continuation but top adjusted score was {}",
            round_score(selected_score)
        ));
    }
    if privacy_violation {
        notes.push("fixture appears to contain raw note or raw text".to_string());
    }
    ContinueReplayEvalCaseReport {
        fixture_id,
        fixture_kind,
        source_decision_id,
        expected_return_artifact_id,
        actual_return_artifact_id,
        expected_workstream_id,
        actual_workstream_id,
        expected_no_clear,
        target_artifact_correct,
        workstream_correct,
        no_clear_correct,
        candidate_rank,
        reciprocal_rank: round_score(reciprocal_rank),
        branch_support_false_positive,
        current_focus_false_positive,
        stale_target_false_positive,
        privacy_violation,
        regression,
        notes,
    }
}

fn replay_adjusted_candidate_score(conn: &Connection, candidate: &Value) -> f64 {
    let base = candidate
        .get("score")
        .and_then(Value::as_f64)
        .unwrap_or(0.0);
    let artifact_id = candidate.get("target_artifact_id").and_then(Value::as_str);
    let candidate_kind = candidate.get("candidate_kind").and_then(Value::as_str);
    let artifact_kind = candidate.get("artifact_kind").and_then(Value::as_str);
    let openability = candidate.get("openability").and_then(Value::as_str);
    let workstream_state = candidate.get("workstream_state").and_then(Value::as_str);
    let prior = feedback_prior_score_for_features(
        conn,
        artifact_id,
        candidate_kind,
        artifact_kind,
        openability,
        workstream_state,
        None,
    )
    .unwrap_or(0.0);
    round_score((base + prior).clamp(0.0, 1.0))
}

fn metric_ratio<F>(reports: &[ContinueEvalCaseReport], predicate: F) -> f64
where
    F: Fn(&ContinueEvalCaseReport) -> bool,
{
    if reports.is_empty() {
        return 0.0;
    }
    round_score(reports.iter().filter(|case| predicate(case)).count() as f64 / reports.len() as f64)
}

fn evaluate_continue_fixture_case(
    mut case: ContinueEvalCaseFixture,
    k: usize,
) -> Result<ContinueEvalCaseReport, String> {
    case.candidates.sort_by(|left, right| {
        right
            .score
            .partial_cmp(&left.score)
            .unwrap_or(std::cmp::Ordering::Equal)
    });
    let expected = case.expected_target_artifact_id.clone();
    let correct_rank = case
        .candidates
        .iter()
        .position(|candidate| candidate.target_artifact_id.as_deref() == Some(expected.as_str()))
        .map(|index| index as i64 + 1);
    let mut selected = if let Some(output) = case.model_output.as_ref() {
        output
            .selected_candidate_id
            .as_deref()
            .and_then(|selected_id| {
                case.candidates
                    .iter()
                    .find(|candidate| candidate.id == selected_id)
            })
            .or_else(|| case.candidates.first())
    } else {
        case.candidates.first()
    };
    let mut validation_failures = Vec::new();
    let hallucinated_artifact_count = if let Some(output) = case.model_output.as_ref() {
        validate_eval_model_output(output, &case.candidates, &mut validation_failures)
    } else {
        0
    };
    let feedback_obedience_case = !case.negative_feedback.is_empty()
        || !case.expected_suppressed_artifact_ids.is_empty()
        || !case.expected_not_return_target_artifact_ids.is_empty()
        || case.corrected_artifact_id.is_some()
        || case
            .cache_feedback_newer_than_cached_decision
            .unwrap_or(false)
        || case
            .model_feedback_validation_failure_expected
            .unwrap_or(false);
    if let Some(output) = case.model_output.as_ref() {
        if let Some(selected_id) = output.selected_candidate_id.as_deref() {
            if let Some(model_selected) = case
                .candidates
                .iter()
                .find(|candidate| candidate.id == selected_id)
            {
                let model_selected_suppressed = model_selected
                    .target_artifact_id
                    .as_ref()
                    .is_some_and(|artifact_id| {
                        case.expected_suppressed_artifact_ids.contains(artifact_id)
                            || case
                                .expected_not_return_target_artifact_ids
                                .contains(artifact_id)
                    })
                    || model_selected
                        .feedback_suppression_state
                        .as_deref()
                        .is_some_and(|state| state == "hard_suppressed");
                let model_high_confidence_score_capped = output.confidence == "high"
                    && (model_selected.feedback_score_capped.unwrap_or(false)
                        || model_selected
                            .feedback_suppression_state
                            .as_deref()
                            .is_some_and(|state| state == "score_capped"));
                if model_selected_suppressed || model_high_confidence_score_capped {
                    push_string_once(
                        &mut validation_failures,
                        "model_feedback_validation_failure",
                    );
                }
            }
        }
    }
    let validation_status = if validation_failures.is_empty() {
        case.expected_validation_status
            .clone()
            .unwrap_or_else(|| "valid".to_string())
    } else {
        "fallback".to_string()
    };
    if !validation_failures.is_empty() {
        selected = case.candidates.first();
    }
    let selected_target = selected.and_then(|candidate| candidate.target_artifact_id.clone());
    let target_correct = selected_target.as_deref() == Some(expected.as_str());
    let selected_evidence_quality =
        selected.and_then(|candidate| candidate.evidence_quality.clone());
    let selected_missing = selected
        .and_then(|candidate| candidate.missing_evidence.clone())
        .unwrap_or_default();
    let expected_output_mode =
        selected.and_then(|candidate| candidate.expected_output_mode.clone());
    let expects_open_loop = selected.and_then(|candidate| candidate.expected_open_loop);
    let cache_boundary_changed = selected.and_then(|candidate| candidate.cache_boundary_changed);
    let thin_or_unknown = selected_evidence_quality
        .as_deref()
        .is_some_and(|quality| matches!(quality, "thin" | "unknown"))
        || !selected_missing.is_empty()
        || expected == "unknown";
    let scenario_lower = case.scenario.to_ascii_lowercase();
    let support_like = scenario_lower.contains("support")
        || scenario_lower.contains("search")
        || scenario_lower.contains("messaging")
        || scenario_lower.contains("slack")
        || scenario_lower.contains("diagnostic")
        || scenario_lower.contains("smalltalk");
    let open_loop_like = scenario_lower.contains("error")
        || scenario_lower.contains("failure")
        || scenario_lower.contains("verification")
        || scenario_lower.contains("branch")
        || scenario_lower.contains("open loop");
    let no_clear_like = expected == "unknown"
        || expected_output_mode.as_deref() == Some("no_clear_continuation")
        || selected_missing
            .iter()
            .any(|item| item.contains("no_clear") || item.contains("thin"));
    let source_provenance_correct =
        (validation_status == "fallback") == !validation_failures.is_empty();
    let fresh_surface_required = case
        .candidates
        .iter()
        .any(|candidate| candidate.is_fresh_current_work.unwrap_or(false));
    let fresh_surface_retained = !fresh_surface_required
        || case.candidates.iter().any(|candidate| {
            candidate.is_fresh_current_work.unwrap_or(false)
                || candidate
                    .expected_candidate_kind
                    .as_deref()
                    .is_some_and(|kind| kind == "continue_current_work")
                || candidate
                    .candidate_kind
                    .as_deref()
                    .is_some_and(|kind| kind == "continue_current_work")
        });
    let stale_target_required = case
        .candidates
        .iter()
        .any(|candidate| candidate.is_stale_return_target.unwrap_or(false));
    let selected_is_stale_target = selected.is_some_and(|candidate| {
        candidate.is_stale_return_target.unwrap_or(false)
            && candidate.return_target_openable.unwrap_or(false)
            && !candidate.stale_target_suppressed.unwrap_or(false)
    });
    let stale_target_suppressed = !stale_target_required
        || (!selected_is_stale_target
            && case
                .candidates
                .iter()
                .filter(|candidate| candidate.is_stale_return_target.unwrap_or(false))
                .all(|candidate| candidate.stale_target_suppressed.unwrap_or(false)));
    let selected_is_support_branch =
        selected.is_some_and(|candidate| candidate.is_support_branch.unwrap_or(false));
    let support_branch_false_promotion = selected_is_support_branch && !target_correct;
    let suppressed_target_open_attempted = case
        .candidates
        .iter()
        .any(|candidate| candidate.suppressed_target_open_attempted.unwrap_or(false));
    let feedback_suppressed_target_exposed = selected_target.as_ref().is_some_and(|target| {
        case.expected_suppressed_artifact_ids.contains(target)
            || case
                .expected_not_return_target_artifact_ids
                .contains(target)
    });
    let corrected_artifact_preferred = case
        .corrected_artifact_id
        .as_ref()
        .is_some_and(|artifact_id| selected_target.as_ref() == Some(artifact_id));
    let feedback_cache_stale_hit = case
        .cache_feedback_newer_than_cached_decision
        .unwrap_or(false)
        && case
            .cached_decision_target_artifact_id
            .as_ref()
            .is_some_and(|artifact_id| selected_target.as_ref() == Some(artifact_id));
    let model_feedback_validation_failure = case
        .model_feedback_validation_failure_expected
        .unwrap_or(false)
        || validation_failures
            .iter()
            .any(|failure| failure.contains("feedback"));
    let selected_branch_kind = selected.and_then(|candidate| candidate.branch_kind.as_deref());
    let selected_branch_state = selected.and_then(|candidate| candidate.branch_promotion_state.as_deref());
    let selected_public_branch_eligible =
        selected.and_then(|candidate| candidate.branch_public_return_eligible);
    let selected_is_unpromoted_branch = selected
        .is_some_and(|candidate| candidate.is_support_branch.unwrap_or(false))
        && selected_public_branch_eligible == Some(false)
        && !matches!(
            selected_branch_state,
            Some(
                "promoted_primary"
                    | "promoted_blocker"
                    | "promoted_user_corrected"
                    | "promoted_user_accepted"
                    | "promoted_sustained_work"
            )
        );
    let branch_case = case
        .candidates
        .iter()
        .any(|candidate| candidate.is_support_branch.unwrap_or(false));
    let branch_origin_recalled = !branch_case
        || case.candidates.iter().any(|candidate| {
            candidate
                .origin_artifact_id
                .as_ref()
                .is_some_and(|origin| origin == &expected)
                || candidate.target_artifact_id.as_ref() == Some(&expected)
        });
    let branch_selected = selected
        .is_some_and(|candidate| candidate.is_support_branch.unwrap_or(false));
    let selected_branch_expected_promoted =
        selected.and_then(|candidate| candidate.expected_branch_promoted).unwrap_or(false);
    let promoted_branch_selection_correct = !branch_selected
        || selected_public_branch_eligible != Some(true)
        || selected_branch_expected_promoted;
    let support_branch_false_positive = selected_is_unpromoted_branch && !target_correct;
    let message_interrupt_false_positive = selected_branch_kind == Some("message_interrupt")
        && selected_public_branch_eligible != Some(true)
        && !target_correct;
    let diagnostic_self_selected = selected_branch_kind == Some("diagnostic_self");
    let model_branch_policy_violation = validation_failures
        .iter()
        .any(|failure| failure.contains("branch"))
        || case
            .model_output
            .as_ref()
            .and_then(|output| output.selected_candidate_id.as_deref())
            .and_then(|selected_id| case.candidates.iter().find(|candidate| candidate.id == selected_id))
            .is_some_and(|candidate| {
                candidate.is_support_branch.unwrap_or(false)
                    && candidate.branch_public_return_eligible == Some(false)
            });
    let feedback_obedience_placeholder =
        case.expected_feedback_obedience_placeholder.unwrap_or(true);
    let selected_return_target_openable =
        selected.is_some_and(|candidate| candidate.return_target_openable.unwrap_or(false));
    let truthful_thin_mode = if selected_return_target_openable && target_correct {
        true
    } else if stale_target_required || fresh_surface_required {
        thin_or_unknown
            || expected_output_mode
                .as_deref()
                .is_some_and(|mode| mode == "thin_continue" || mode == "no_clear_continuation")
            || selected_missing.iter().any(|item| {
                item.contains("missing_current_work")
                    || item.contains("stale_return_target_suppressed")
                    || item.contains("no_clear")
                    || item.contains("thin")
            })
    } else {
        !thin_or_unknown || thin_or_unknown
    };
    Ok(ContinueEvalCaseReport {
        name: case.name,
        scenario: case.scenario,
        expected_target_artifact_id: expected,
        selected_candidate_id: selected.map(|candidate| candidate.id.clone()),
        selected_target_artifact_id: selected_target.clone(),
        target_artifact_correct: target_correct,
        correct_candidate_rank: correct_rank,
        recall_at_k: correct_rank.is_some_and(|rank| rank <= k as i64),
        reciprocal_rank: correct_rank.map(|rank| 1.0 / rank as f64).unwrap_or(0.0),
        current_focus_false_positive: selected_target.is_some()
            && selected_target == case.current_focus_artifact_id
            && !target_correct,
        hallucinated_artifact_count,
        validation_status,
        validation_failures,
        last_state_specificity: !thin_or_unknown && target_correct,
        next_action_specificity: target_correct
            && selected
                .map(|candidate| candidate.score >= 0.5)
                .unwrap_or(false)
            && !selected_missing
                .iter()
                .any(|item| item.contains("no_clear") || item.contains("raw")),
        support_branch_handling: !support_like || target_correct,
        thin_evidence_honesty: if thin_or_unknown {
            expected_output_mode.as_deref().map_or(true, |mode| {
                mode == "thin_continue" || mode == "no_clear_continuation"
            }) || selected_missing.iter().any(|item| {
                item.contains("thin") || item.contains("fallback") || item.contains("no_clear")
            })
        } else {
            true
        },
        current_focus_vs_return_clarity: case
            .current_focus_artifact_id
            .as_ref()
            .map_or(true, |focus| {
                Some(focus) != selected_target.as_ref() || target_correct
            }),
        source_provenance_correctness: source_provenance_correct,
        open_loop_recovery: !open_loop_like || expects_open_loop.unwrap_or(target_correct),
        no_clear_continuation_correctness: !no_clear_like || (target_correct && thin_or_unknown),
        quality_gate_correctness: expected_output_mode.as_deref().map_or(true, |mode| {
            if thin_or_unknown {
                mode != "strong_continue"
            } else {
                mode == "strong_continue"
            }
        }),
        cache_freshness_correctness: cache_boundary_changed.map_or(true, |changed| {
            if changed {
                target_correct && selected_missing.is_empty()
            } else {
                true
            }
        }),
        fresh_surface_retained,
        stale_target_suppressed,
        support_branch_false_promotion,
        support_branch_false_positive,
        unpromoted_branch_selected: selected_is_unpromoted_branch,
        branch_origin_recalled,
        promoted_branch_selection_correct,
        message_interrupt_false_positive,
        diagnostic_self_selected,
        model_branch_policy_violation,
        truthful_thin_mode,
        feedback_obedience_case,
        feedback_suppressed_target_exposed,
        corrected_artifact_preferred,
        feedback_cache_stale_hit,
        model_feedback_validation_failure,
        feedback_obedience_placeholder,
        suppressed_target_open_attempted,
    })
}

fn validate_eval_model_output(
    output: &ContinueMicroInferenceOutput,
    candidates: &[ContinueEvalCandidateFixture],
    failures: &mut Vec<String>,
) -> i64 {
    if matches!(
        output.result.as_str(),
        "need_more_evidence" | "no_clear_continuation"
    ) {
        if output.confidence == "high" {
            failures.push("escape_hatch_cannot_claim_high_confidence".to_string());
        }
        if unsupported_locator_in_model_output(output) {
            failures.push("unsupported_locator_in_model_output".to_string());
        }
        return 0;
    }
    let Some(selected_candidate_id) = output.selected_candidate_id.as_deref() else {
        failures.push("selected_candidate_id_missing".to_string());
        return 1;
    };
    let candidate = candidates
        .iter()
        .find(|candidate| candidate.id == selected_candidate_id);
    let Some(candidate) = candidate else {
        failures.push("selected_candidate_id_not_in_fixture".to_string());
        return 1;
    };
    if output.selected_workstream_id.as_deref() != Some(candidate.workstream_id.as_str()) {
        failures.push("selected_workstream_id_mismatch".to_string());
    }
    if output.confidence == "high"
        && (candidate.score < 0.7
            || candidate
                .missing_evidence
                .as_ref()
                .is_some_and(|missing| !missing.is_empty())
            || candidate.evidence_quality.as_deref() == Some("thin"))
    {
        failures.push("high_confidence_with_thin_local_evidence".to_string());
    }
    if unsupported_locator_in_model_output(output) {
        failures.push("unsupported_locator_in_model_output".to_string());
    }
    if candidate.is_support_branch.unwrap_or(false)
        && candidate.branch_public_return_eligible == Some(false)
    {
        push_string_once(failures, "model_selected_unpromoted_branch");
        push_string_once(failures, "model_ignored_branch_eligibility");
    }
    0
}

fn evidence_anchors_for_decision(
    current_focus: Option<&ContinueFocusSummary>,
    selected: Option<&ScoredContinueCandidate>,
    selected_workstream: Option<&ScorerWorkstream>,
) -> ContinueEvidenceAnchors {
    let mut anchors = ContinueEvidenceAnchors::default();
    if let Some(focus) = current_focus {
        push_unique(
            &mut anchors.frame_ids,
            &mut HashSet::new(),
            focus.frame_id.clone(),
        );
        if let Some(artifact_id) = &focus.artifact_id {
            anchors.artifact_ids.push(artifact_id.clone());
        }
    }
    if let Some(candidate) = selected {
        if let Some(frame_id) = &candidate.evidence_frame_id {
            if !anchors.frame_ids.contains(frame_id) {
                anchors.frame_ids.push(frame_id.clone());
            }
        }
        if let Some(action) = &candidate.last_meaningful_action {
            anchors.action_ids.push(action.id.clone());
            if !anchors.frame_ids.contains(&action.frame_id) {
                anchors.frame_ids.push(action.frame_id.clone());
            }
            if let Some(secondary_id) = &action.secondary_artifact_id {
                if !anchors.artifact_ids.contains(secondary_id) {
                    anchors.artifact_ids.push(secondary_id.clone());
                }
            }
        }
        if let Some(episode_id) = &candidate.supporting_episode_id {
            anchors.episode_ids.push(episode_id.clone());
        }
        if let Some(target) = &candidate.target_artifact {
            if !anchors.artifact_ids.contains(&target.id) {
                anchors.artifact_ids.push(target.id.clone());
            }
        }
        if let Some(target) = &candidate.resume_work_target {
            if !anchors.artifact_ids.contains(&target.id) {
                anchors.artifact_ids.push(target.id.clone());
            }
        }
    }
    if let Some(workstream) = selected_workstream {
        for episode in workstream.episodes.iter().rev().take(2) {
            if !anchors.episode_ids.contains(&episode.id) {
                anchors.episode_ids.push(episode.id.clone());
            }
            if let Some(kind) = &episode.dominant_action_kind {
                let _ = kind;
            }
        }
    }
    anchors
}

fn current_activity_summary(
    action: Option<&ScorerAction>,
    current_focus: Option<&ContinueFocusSummary>,
) -> Option<String> {
    let focus = current_focus?;
    let surface = focus
        .title
        .as_deref()
        .or(focus.window_title.as_deref())
        .or(focus.app_name.as_deref())
        .unwrap_or("current surface");
    let activity = match action.map(|action| action.action_kind.as_str()) {
        Some("editing") => "editing",
        Some("composing") => "composing",
        Some("encountering_error") => "looking at an error",
        Some("running_command") => "running a command",
        Some("observing_command_output") | Some("reviewing_output") => "reviewing output",
        Some("searching") | Some("branching_away") => "using a support/search surface",
        Some("idle_after_progress") => "idle after recent progress",
        Some("reading") => "reading",
        _ => "viewing",
    };
    Some(format!("{} {}", activity, surface))
}

#[allow(clippy::too_many_arguments)]
fn compose_continue_handoff(
    current_focus: Option<&ContinueFocusSummary>,
    selected_workstream: Option<&ScorerWorkstream>,
    selected: Option<&ScoredContinueCandidate>,
    next_action: Option<&str>,
    confidence: f64,
    missing_evidence: &[String],
    warnings: &[String],
    validation_failures: &[String],
    model_output: Option<&ContinueMicroInferenceOutput>,
    quality_gate: Option<&ContinueDecisionQualityGate>,
    output_mode: &ContinueOutputMode,
    activity_summary: Option<&ContinueActivitySummary>,
) -> ContinueHandoff {
    let confidence_label_value = handoff_confidence_label(confidence, output_mode);
    if matches!(
        output_mode,
        ContinueOutputMode::ThinContinue | ContinueOutputMode::NoClearContinuation
    ) {
        return compose_local_continue_handoff(
            current_focus,
            selected_workstream,
            selected,
            next_action,
            confidence,
            missing_evidence,
            warnings,
            validation_failures,
            quality_gate,
            output_mode,
            activity_summary,
        );
    }
    if let Some(output) = model_output {
        let local_fallback = compose_local_continue_handoff(
            current_focus,
            selected_workstream,
            selected,
            next_action,
            confidence,
            missing_evidence,
            warnings,
            validation_failures,
            quality_gate,
            output_mode,
            activity_summary,
        );
        return ContinueHandoff {
            headline: clean_user_handoff_line(output.headline.clone(), 90)
                .unwrap_or(local_fallback.headline),
            return_line: clean_user_handoff_line(output.return_line.clone(), 180)
                .unwrap_or(local_fallback.return_line),
            current_focus_line: clean_user_handoff_line(output.current_focus_line.clone(), 180)
                .unwrap_or(local_fallback.current_focus_line),
            last_state_line: clean_user_handoff_line(output.last_state_line.clone(), 180)
                .unwrap_or(local_fallback.last_state_line),
            next_action: output
                .next_action
                .as_ref()
                .and_then(|value| clean_user_handoff_line(value.clone(), 180))
                .unwrap_or(local_fallback.next_action),
            why_this: clean_handoff_reasons(&output.why_this).unwrap_or(local_fallback.why_this),
            missing_evidence_line: output
                .missing_evidence_line
                .as_ref()
                .and_then(|value| clean_user_handoff_line(value.clone(), 180))
                .or(local_fallback.missing_evidence_line),
            confidence_label: confidence_label_value,
            user_visible_uncertainty: output
                .user_visible_uncertainty
                .as_ref()
                .and_then(|value| clean_user_handoff_line(value.clone(), 180))
                .or(local_fallback.user_visible_uncertainty),
        };
    }

    compose_local_continue_handoff(
        current_focus,
        selected_workstream,
        selected,
        next_action,
        confidence,
        missing_evidence,
        warnings,
        validation_failures,
        quality_gate,
        output_mode,
        activity_summary,
    )
}

fn compose_local_continue_handoff(
    current_focus: Option<&ContinueFocusSummary>,
    selected_workstream: Option<&ScorerWorkstream>,
    selected: Option<&ScoredContinueCandidate>,
    next_action: Option<&str>,
    confidence: f64,
    missing_evidence: &[String],
    warnings: &[String],
    validation_failures: &[String],
    quality_gate: Option<&ContinueDecisionQualityGate>,
    output_mode: &ContinueOutputMode,
    activity_summary: Option<&ContinueActivitySummary>,
) -> ContinueHandoff {
    let target_label = selected.and_then(human_return_target_label);
    if matches!(output_mode, ContinueOutputMode::NoClearContinuation)
        || selected
            .as_ref()
            .is_some_and(|candidate| !candidate_has_human_return_target(candidate))
    {
        let missing_line =
            visible_missing_evidence_line(missing_evidence, warnings, validation_failures).or_else(
                || {
                    quality_gate
                        .and_then(|gate| gate.fatal_missing.first())
                        .and_then(|value| {
                            clean_handoff_line(format!("Missing or weak evidence: {}", value), 180)
                        })
                },
            );
        let focus_phrase = current_focus.and_then(friendly_focus_phrase);
        let focus_line = focus_phrase
            .as_ref()
            .map(|value| format!("I saw you on {}.", value))
            .or_else(|| {
                current_focus.and_then(|focus| {
                    first_non_empty([
                        focus.title.as_deref(),
                        focus.window_title.as_deref(),
                        focus.app_name.as_deref(),
                    ])
                    .map(|value| format!("I saw {}", value))
                })
            })
            .and_then(|line| clean_user_handoff_line(line, 180))
            .unwrap_or_else(|| "Current focus is unclear.".to_string());
        let uncertainty = focus_phrase
            .as_ref()
            .map(|value| {
                format!(
                    "I saw you on {}, but I don't have a reliable return target yet.",
                    value
                )
            })
            .and_then(|line| clean_user_handoff_line(line, 180))
            .or_else(|| {
                Some("I don't have a reliable app or page target for this yet.".to_string())
            });
        let activity_main = activity_summary.and_then(|summary| summary.main_work.clone());
        let activity_divergence =
            activity_summary.and_then(|summary| summary.recent_divergence.first().cloned());
        let activity_missing = activity_summary.and_then(|summary| {
            if summary.missing_for_current_focus.is_empty() {
                None
            } else {
                Some(summary.missing_for_current_focus.join(", "))
            }
        });
        let last_state_line = if let Some(main) = activity_main.as_ref() {
            format!(
                "Latest meaningful signal: {}, but I do not have enough app content to name an exact task.",
                main
            )
        } else {
            "I do not have enough local evidence to identify a reliable unfinished task."
                .to_string()
        };
        let mut why_this =
            vec!["Local evidence is not specific enough for a confident continuation.".to_string()];
        if let Some(divergence) = activity_divergence {
            why_this.push(format!("Not using: {}.", divergence));
        }
        why_this.truncate(3);
        let activity_uncertainty = activity_main.map(|main| {
            if let Some(missing) = activity_missing {
                format!(
                    "{} looks like the main work, but missing: {}.",
                    main, missing
                )
            } else {
                format!("{} looks like the main work, but evidence is thin.", main)
            }
        });
        return ContinueHandoff {
            headline: "No reliable continuation target yet".to_string(),
            return_line: "No reliable return target is grounded yet.".to_string(),
            current_focus_line: focus_line,
            last_state_line: clean_user_handoff_line(last_state_line, 180).unwrap_or_else(|| {
                "I do not have enough local evidence to identify a reliable unfinished task."
                    .to_string()
            }),
            next_action: fallback_next_action_for_output_mode(output_mode).to_string(),
            why_this,
            missing_evidence_line: missing_line.clone(),
            confidence_label: "Thin".to_string(),
            user_visible_uncertainty: activity_uncertainty
                .and_then(|line| clean_user_handoff_line(line, 180))
                .or(uncertainty)
                .or(missing_line),
        };
    }
    let target_label =
        target_label.unwrap_or_else(|| "the best available return point".to_string());
    let workstream_label = selected_workstream
        .and_then(|workstream| workstream.title_candidate.clone())
        .or_else(|| Some(target_label.clone()))
        .unwrap_or_else(|| "recent work".to_string());
    let focus_label = current_focus
        .and_then(|focus| {
            first_non_empty([
                focus.title.as_deref(),
                focus.window_title.as_deref(),
                focus.app_name.as_deref(),
            ])
            .map(str::to_string)
        })
        .unwrap_or_else(|| "the current screen".to_string());
    let action_label = selected
        .and_then(|candidate| {
            candidate
                .open_loop
                .as_ref()
                .and_then(|open_loop| open_loop.last_concrete_progress.as_deref())
        })
        .map(str::to_string)
        .or_else(|| {
            selected
                .and_then(|candidate| candidate.last_meaningful_action.as_ref())
                .map(|action| human_action_kind(&action.action_kind).to_string())
        })
        .unwrap_or_else(|| "working".to_string());
    let action_label = action_label.as_str();
    let local_next_action = next_action
        .and_then(|value| clean_user_handoff_line(value.to_string(), 180))
        .unwrap_or_else(|| {
            "Open the target and continue from the last meaningful state.".to_string()
        });
    let confidence_text = handoff_confidence_label(confidence, output_mode);
    let missing_line =
        visible_missing_evidence_line(missing_evidence, warnings, validation_failures);
    if selected.is_some_and(candidate_is_completed_progress) {
        let completed_state = selected
            .and_then(|candidate| {
                candidate
                    .open_loop
                    .as_ref()
                    .and_then(|open_loop| open_loop.last_concrete_progress.as_deref())
            })
            .or_else(|| {
                selected.and_then(|candidate| {
                    candidate
                        .last_meaningful_action
                        .as_ref()
                        .and_then(|action| action.semantic_after_hint.as_deref())
                })
            })
            .unwrap_or("Completed verified work was observed");
        let current_focus_line = if selected
            .as_ref()
            .is_some_and(|candidate| candidate_has_current_focus_mismatch(candidate, current_focus))
        {
            format!(
                "Current focus later moved to {}; this completed workstream is still the strongest return point.",
                focus_label
            )
        } else {
            format!("Current focus is {}.", focus_label)
        };
        let mut why_this = vec![
            "Local evidence marked the work as completed successfully.".to_string(),
            "The next useful step is review, commit, or manual app verification.".to_string(),
        ];
        if selected
            .as_ref()
            .and_then(|candidate| candidate.open_loop.as_ref())
            .is_some()
        {
            why_this.push("Anchored to an evidence-backed completed workstream.".to_string());
        }
        why_this.truncate(3);
        return ContinueHandoff {
            headline: "Review completed work".to_string(),
            return_line: clean_user_handoff_line(format!("Continue from {}", target_label), 180)
                .unwrap_or_else(|| "Continue from the completed workstream.".to_string()),
            current_focus_line: clean_user_handoff_line(current_focus_line, 180)
                .unwrap_or_else(|| "Current focus differs from the completed work.".to_string()),
            last_state_line: clean_user_handoff_line(
                format!("Completed state: {}", completed_state),
                180,
            )
            .unwrap_or_else(|| "Completed verified work was observed.".to_string()),
            next_action: local_next_action,
            why_this,
            missing_evidence_line: missing_line.clone(),
            confidence_label: confidence_text,
            user_visible_uncertainty: if confidence < 0.5 { missing_line } else { None },
        };
    }
    let thin = confidence < 0.5
        || selected.is_none()
        || matches!(output_mode, ContinueOutputMode::ThinContinue);
    let uncertainty = if thin {
        Some(missing_line.clone().unwrap_or_else(|| {
            "Evidence is thin, so this is the best available handoff.".to_string()
        }))
    } else {
        missing_line.clone()
    };
    let headline = if thin {
        "Best available return point".to_string()
    } else {
        format!("Continue {}", readable_fragment(&workstream_label, 68))
    };
    let mut why_this = Vec::new();
    if let Some(candidate) = selected {
        if candidate.resume_work_target.is_some() || candidate.target_artifact.is_some() {
            why_this.push("Selected from local workstream and target evidence.".to_string());
        }
        if candidate.open_loop.is_some() {
            why_this.push("Anchored to an evidence-backed unfinished state.".to_string());
        } else if candidate.last_meaningful_action.is_some() {
            why_this.push("Anchored to the last meaningful action.".to_string());
        }
        if candidate.evidence_quality_score >= 0.58 {
            why_this.push("Evidence quality is strong enough for a recommendation.".to_string());
        }
    }
    if why_this.is_empty() {
        why_this.push(
            "Local evidence is thin, but this is the strongest available signal.".to_string(),
        );
    }

    ContinueHandoff {
        headline: clean_user_handoff_line(headline, 90)
            .unwrap_or_else(|| "Continue from recent work".to_string()),
        return_line: clean_user_handoff_line(format!("Continue from {}", target_label), 180)
            .unwrap_or_else(|| "No stable return target yet.".to_string()),
        current_focus_line: clean_user_handoff_line(focus_label, 180)
            .unwrap_or_else(|| "Current focus is unclear.".to_string()),
        last_state_line: clean_user_handoff_line(
            if thin {
                "I have thin evidence of recent progress, but the unfinished state is not specific enough.".to_string()
            } else {
                format!(
                    "Last meaningful state: {} in {}",
                    action_label, workstream_label
                )
            },
            180,
        )
        .unwrap_or_else(|| "No meaningful prior state is clear yet.".to_string()),
        next_action: if thin {
            fallback_next_action_for_output_mode(output_mode).to_string()
        } else {
            local_next_action
        },
        why_this,
        missing_evidence_line: missing_line,
        confidence_label: confidence_text,
        user_visible_uncertainty: uncertainty,
    }
}

fn stale_target_suppressed_next_action(current_focus: Option<&ContinueFocusSummary>) -> String {
    let focus_phrase = current_focus
        .and_then(friendly_focus_phrase)
        .unwrap_or_else(|| "the newest current work".to_string());
    clean_user_handoff_line(
        format!(
            "Capture fresh evidence for {} before opening an older target.",
            focus_phrase
        ),
        180,
    )
    .unwrap_or_else(|| "Capture fresh evidence before opening an older target.".to_string())
}

fn stale_target_suppressed_handoff(
    current_focus: Option<&ContinueFocusSummary>,
    missing_evidence: &[String],
) -> ContinueHandoff {
    let focus_phrase = current_focus
        .and_then(friendly_focus_phrase)
        .unwrap_or_else(|| "the newest current work".to_string());
    let current_focus_line =
        clean_user_handoff_line(format!("Most recent work was in {}.", focus_phrase), 180)
            .unwrap_or_else(|| "Most recent work was in the newest current surface.".to_string());
    let uncertainty = clean_user_handoff_line(
        format!(
            "I saw {}, but I do not have enough evidence to reopen the exact task safely.",
            focus_phrase
        ),
        180,
    );
    ContinueHandoff {
        headline: "No reliable continuation target yet".to_string(),
        return_line: "No older openable target is safe to use for this handoff.".to_string(),
        current_focus_line,
        last_state_line: "Newer current work exists, but the exact task identity is still thin."
            .to_string(),
        next_action: stale_target_suppressed_next_action(current_focus),
        why_this: vec![
            "A newer non-self surface was observed after the openable target.".to_string(),
            "The older target was suppressed because evidence is thin.".to_string(),
        ],
        missing_evidence_line: visible_missing_evidence_line(missing_evidence, &[], &[]).or_else(
            || Some("Missing or weak evidence: current work target identity.".to_string()),
        ),
        confidence_label: "Thin".to_string(),
        user_visible_uncertainty: uncertainty,
    }
}

fn handoff_confidence_label(confidence: f64, output_mode: &ContinueOutputMode) -> String {
    match output_mode {
        ContinueOutputMode::StrongContinue => confidence_label(confidence).to_string(),
        ContinueOutputMode::ThinContinue | ContinueOutputMode::NoClearContinuation => {
            "Thin".to_string()
        }
    }
}

fn clean_handoff_reasons(values: &[String]) -> Option<Vec<String>> {
    let reasons = values
        .iter()
        .filter_map(|value| clean_user_handoff_line(value.clone(), 140))
        .take(3)
        .collect::<Vec<_>>();
    if reasons.is_empty() {
        None
    } else {
        Some(reasons)
    }
}

fn clean_handoff_line(value: String, max_chars: usize) -> Option<String> {
    let one_line = value.split_whitespace().collect::<Vec<_>>().join(" ");
    let trimmed = one_line.trim();
    if trimmed.is_empty() {
        return None;
    }
    let mut output = trimmed.chars().take(max_chars).collect::<String>();
    if trimmed.chars().count() > max_chars {
        output = output.trim_end_matches([' ', '.', ',']).to_string();
        output.push_str("...");
    }
    Some(output)
}

fn clean_user_handoff_line(value: String, max_chars: usize) -> Option<String> {
    let cleaned = clean_handoff_line(value, max_chars)?;
    if contains_internal_continue_reference(&cleaned) {
        None
    } else {
        Some(cleaned)
    }
}

fn contains_internal_continue_reference(value: &str) -> bool {
    let lower = value.to_ascii_lowercase();
    if lower.contains("continue-candidate-")
        || lower.contains("workstream-")
        || lower.contains("artifact-")
        || lower.contains("frame-fallback")
        || lower.contains("frame_fallback")
        || lower.contains("target metadata")
        || lower.contains("selected candidate")
        || lower.contains("candidate id")
        || lower.contains("workstream id")
        || lower.contains("artifact id")
        || lower.contains("frame_id")
        || lower.contains("frame id")
    {
        return true;
    }
    lower.split_whitespace().any(|token| {
        let token = token.trim_matches(|ch: char| !ch.is_ascii_alphanumeric() && ch != '-');
        token
            .strip_prefix("frame-")
            .is_some_and(|suffix| suffix.chars().all(|ch| ch.is_ascii_digit()))
    }) || contains_raw_frame_phrase(&lower)
}

fn contains_raw_frame_phrase(value: &str) -> bool {
    value
        .split("frame ")
        .skip(1)
        .any(|suffix| suffix.chars().next().is_some_and(|ch| ch.is_ascii_digit()))
}

fn handoff_contains_internal_reference(handoff: &ContinueHandoff) -> bool {
    contains_internal_continue_reference(&handoff.headline)
        || contains_internal_continue_reference(&handoff.return_line)
        || contains_internal_continue_reference(&handoff.current_focus_line)
        || contains_internal_continue_reference(&handoff.last_state_line)
        || contains_internal_continue_reference(&handoff.next_action)
        || handoff
            .why_this
            .iter()
            .any(|line| contains_internal_continue_reference(line))
        || handoff
            .missing_evidence_line
            .as_deref()
            .is_some_and(contains_internal_continue_reference)
        || handoff
            .user_visible_uncertainty
            .as_deref()
            .is_some_and(contains_internal_continue_reference)
}

fn readable_fragment(value: &str, max_chars: usize) -> String {
    clean_user_handoff_line(value.to_string(), max_chars)
        .unwrap_or_else(|| "recent work".to_string())
}

fn human_action_kind(kind: &str) -> &'static str {
    match kind {
        "editing" => "editing",
        "composing" => "composing",
        "encountering_error" => "an error was visible",
        "running_command" => "a command was running",
        "observing_command_output" | "reviewing_output" => "reviewing output",
        "searching" => "searching for support",
        "branching_away" => "using a support surface",
        "idle_after_progress" => "paused after progress",
        "reading" => "reading",
        _ => "working",
    }
}

fn visible_missing_evidence_line(
    missing_evidence: &[String],
    warnings: &[String],
    validation_failures: &[String],
) -> Option<String> {
    let first = missing_evidence
        .iter()
        .chain(warnings.iter())
        .chain(validation_failures.iter())
        .find_map(|value| productize_continue_label(value))?;
    clean_handoff_line(format!("Missing or weak evidence: {}", first), 180)
}

fn workstream_summary(workstream: &ScorerWorkstream) -> ContinueSelectedWorkstream {
    ContinueSelectedWorkstream {
        workstream_id: workstream.id.clone(),
        state: workstream.state.clone(),
        title_candidate: workstream.title_candidate.clone(),
        primary_artifact_id: workstream.primary_artifact_id.clone(),
        last_active_timestamp_ms: workstream.last_active_timestamp_ms,
        unresolved_signal: unresolved_state_description(workstream.unresolved_signal.as_deref()),
    }
}

fn return_target_summary(
    artifact: Option<&ScorerArtifact>,
    fallback_frame_id: Option<String>,
) -> ContinueReturnTarget {
    ContinueReturnTarget {
        artifact_id: artifact.map(|artifact| artifact.id.clone()),
        artifact_kind: artifact.map(|artifact| artifact.artifact_kind.clone()),
        title: artifact.and_then(artifact_title_for_scorer),
        browser_url: artifact.and_then(|artifact| artifact.browser_url.clone()),
        document_path: artifact.and_then(|artifact| artifact.document_path.clone()),
        openability: artifact
            .map(|artifact| artifact.openability.clone())
            .unwrap_or_else(|| "frame_fallback".to_string()),
        fallback_frame_id,
    }
}

fn action_summary(action: &ScorerAction) -> ContinueActionSummary {
    ContinueActionSummary {
        action_id: action.id.clone(),
        action_kind: action.action_kind.clone(),
        action_role: action.action_role.clone(),
        timestamp_ms: action.created_at_ms,
        evidence_frame_id: action
            .strongest_frame_id
            .clone()
            .unwrap_or_else(|| action.frame_id.clone()),
        artifact_id: action.artifact_id.clone(),
        collapse_count: action.collapse_count.max(1),
        first_frame_id: action.first_frame_id.clone(),
        last_frame_id: action.last_frame_id.clone(),
        strongest_frame_id: action.strongest_frame_id.clone(),
    }
}

