fn candidate_score_trace(candidate: &ScoredContinueCandidate) -> ContinueCandidateScoreTrace {
    ContinueCandidateScoreTrace {
        fresh_current_work_score: round_score(candidate.fresh_current_work_score),
        stale_mismatch_cap_applied: candidate.score_caps_applied.iter().any(|cap| {
            cap == "score_capped:stale_mismatched_openable_current_work"
                || cap == "score_capped:stale_openable_target"
        }),
        openability_score: round_score(candidate.openability_score),
        recency_score: round_score(candidate.recency_score),
        evidence_quality_score: round_score(candidate.evidence_quality_score),
        feedback_suppression_state: candidate.feedback_suppression_state.clone(),
        feedback_negative_weight: candidate.feedback_negative_weight,
        feedback_last_negative_ms: candidate.feedback_last_negative_ms,
        feedback_last_reconfirming_evidence_ms: candidate.feedback_last_reconfirming_evidence_ms,
        feedback_reason_codes: candidate.feedback_reason_codes.clone(),
    }
}

fn artifact_title_for_scorer(artifact: &ScorerArtifact) -> Option<String> {
    first_non_empty([
        artifact.display_title.as_deref(),
        artifact.document_path.as_deref(),
        artifact.browser_url.as_deref(),
    ])
    .map(str::to_string)
}

fn candidate_has_human_return_target(candidate: &ScoredContinueCandidate) -> bool {
    human_return_target_label(candidate).is_some()
}

fn candidate_exposes_public_return_target(
    candidate: &ScoredContinueCandidate,
    output_mode: &ContinueOutputMode,
) -> bool {
    matches!(
        output_mode,
        ContinueOutputMode::StrongContinue | ContinueOutputMode::ThinContinue
    ) && candidate.eligible_for_primary_selection
        && !activity_role_is_suppressed(candidate.continuation_role.as_deref())
        && candidate_branch_public_return_gate(candidate)
        && candidate_has_human_return_target(candidate)
}

fn candidate_branch_public_return_gate(candidate: &ScoredContinueCandidate) -> bool {
    let explicit_public_return = candidate.branch_public_return_eligible.or_else(|| {
        candidate
            .target_artifact
            .as_ref()
            .and_then(|artifact| artifact.branch_public_return_eligible)
    });
    if explicit_public_return == Some(false) {
        return false;
    }
    if explicit_public_return == Some(true) {
        return true;
    }
    match candidate.branch_promotion_state.as_deref() {
        Some("promoted_primary")
        | Some("promoted_blocker")
        | Some("promoted_user_corrected")
        | Some("promoted_user_accepted")
        | Some("promoted_sustained_work") => true,
        Some("unpromoted")
        | Some("blocked_diagnostic_self")
        | Some("blocked_feedback_suppressed")
        | Some("blocked_thin_current_focus") => false,
        Some(_) => false,
        None => true,
    }
}

fn human_return_target_label(candidate: &ScoredContinueCandidate) -> Option<String> {
    candidate
        .resume_work_target
        .as_ref()
        .or(candidate.target_artifact.as_ref())
        .and_then(human_artifact_label)
}

fn human_artifact_label(artifact: &ScorerArtifact) -> Option<String> {
    if let Some(title) = artifact
        .display_title
        .as_deref()
        .and_then(|value| human_label_text(value, 90))
    {
        return Some(title);
    }
    if let Some(path) = artifact.document_path.as_deref() {
        if let Some(name) = Path::new(path)
            .file_name()
            .and_then(|value| value.to_str())
            .and_then(|value| human_label_text(value, 90))
        {
            return Some(name);
        }
    }
    if let Some(host) = artifact
        .browser_url
        .as_deref()
        .and_then(browser_url_host_label)
        .and_then(|value| human_label_text(&value, 90))
    {
        return Some(host);
    }
    None
}

fn human_label_text(value: &str, max_chars: usize) -> Option<String> {
    let cleaned = clean_user_handoff_line(value.to_string(), max_chars)?;
    let lower = cleaned.to_ascii_lowercase();
    if lower == "unknown"
        || lower == "untitled"
        || lower == "the best available return point"
        || lower.contains("target metadata")
    {
        None
    } else {
        Some(cleaned)
    }
}

fn browser_url_host_label(url: &str) -> Option<String> {
    let after_scheme = url.split_once("://").map(|(_, rest)| rest).unwrap_or(url);
    after_scheme
        .split('/')
        .next()
        .and_then(|host| non_empty(host.trim().trim_start_matches("www.").to_string()))
}

fn friendly_focus_phrase(focus: &ContinueFocusSummary) -> Option<String> {
    let label = first_non_empty([
        focus.title.as_deref(),
        focus.window_title.as_deref(),
        focus.app_name.as_deref(),
    ])?;
    let lower = label.to_ascii_lowercase();
    if lower.contains("gemini") {
        return Some("the Gemini chat".to_string());
    }
    if lower.contains("chatgpt") || lower.contains("gpt") {
        return Some("the ChatGPT chat".to_string());
    }
    if lower.contains("claude") {
        return Some("the Claude chat".to_string());
    }
    if lower.contains("helium") || matches!(focus.artifact_kind.as_deref(), Some("browser_tab")) {
        return clean_user_handoff_line(format!("the browser tab \"{}\"", label), 120);
    }
    clean_user_handoff_line(label.to_string(), 120)
}

fn confidence_label(score: f64) -> &'static str {
    if score >= 0.72 {
        "high"
    } else if score >= 0.5 {
        "medium"
    } else if score >= 0.32 {
        "low"
    } else {
        "thin"
    }
}

fn round_score(score: f64) -> f64 {
    (score.clamp(0.0, 1.0) * 100.0).round() / 100.0
}

fn round_signed_score(score: f64) -> f64 {
    (score.clamp(-1.0, 1.0) * 100.0).round() / 100.0
}

fn load_evidence_frames(
    conn: &Connection,
    request: &ContinueSecondLayerRebuildRequest,
) -> Result<Vec<EvidenceFrame>, String> {
    let limit = request.limit.unwrap_or(300).clamp(1, 2_000);
    let max_captured_at = request.lookback_ms.and_then(|lookback| {
        if lookback > 0 {
            conn.query_row("SELECT MAX(captured_at) FROM frames", [], |row| {
                row.get::<_, Option<i64>>(0)
            })
            .ok()
            .flatten()
            .map(|max_ts| max_ts - lookback)
        } else {
            None
        }
    });

    let rows = if let Some(session_id) = &request.session_id {
        query_evidence_frame_rows(
            conn,
            "WHERE (?1 IS NULL OR f.id >= ?1)
               AND (?2 IS NULL OR f.id <= ?2)
               AND (?3 IS NULL OR f.captured_at >= ?3)
               AND f.session_id = ?4",
            &[
                &request.start_frame_id as &dyn rusqlite::ToSql,
                &request.end_frame_id,
                &max_captured_at,
                session_id,
                &limit,
            ],
        )?
    } else {
        query_evidence_frame_rows(
            conn,
            "WHERE (?1 IS NULL OR f.id >= ?1)
               AND (?2 IS NULL OR f.id <= ?2)
               AND (?3 IS NULL OR f.captured_at >= ?3)",
            &[
                &request.start_frame_id as &dyn rusqlite::ToSql,
                &request.end_frame_id,
                &max_captured_at,
                &limit,
            ],
        )?
    };

    let mut frames = Vec::with_capacity(rows.len());
    for mut frame in rows {
        load_frame_capture_attribution(conn, &mut frame)?;
        frame.app_contexts = load_frame_app_contexts(conn, &frame.id)?;
        frame.content_units = load_frame_content_units(conn, &frame.id)?;
        frame.ocr_spans = load_frame_ocr_spans(conn, &frame.id)?;
        frame.visible_windows = load_frame_visible_windows(conn, &frame.id)?;
        frame.trigger = load_frame_trigger(conn, &frame.id)?;
        frame.ui_events = load_frame_ui_events(conn, &frame)?;
        frame.transition = load_frame_transition(conn, &frame.id)?;
        frame.frame_diff = load_frame_diff(conn, &frame.id)?;
        frame.typing_bursts = load_frame_typing_bursts(conn, &frame.id, frame.captured_at)?;
        frame.clipboard_events = load_frame_clipboard_events(conn, &frame.id, frame.captured_at)?;
        frame.focused_node_evidence = has_focused_node(conn, &frame.id)?;
        frame.selected_text_present = has_selected_text(conn, &frame.id)?
            || frame.app_contexts.iter().any(|context| {
                context
                    .selected_text
                    .as_deref()
                    .map(|value| !value.trim().is_empty())
                    .unwrap_or(false)
            });
        frames.push(frame);
    }
    if frames.len() <= 1 {
        frames.extend(load_event_evidence_frames(conn, request, frames.last())?);
    }
    frames.sort_by_key(|frame| {
        (
            frame.captured_at,
            frame.id.parse::<i64>().unwrap_or(i64::MAX),
        )
    });
    Ok(frames)
}

#[derive(Debug)]
struct EventEvidenceRow {
    id: String,
    ts_ms: i64,
    event_type: String,
    key_category: Option<String>,
    app_name: Option<String>,
    app_bundle_id: Option<String>,
    window_title: Option<String>,
}

fn load_event_evidence_frames(
    conn: &Connection,
    request: &ContinueSecondLayerRebuildRequest,
    latest_frame: Option<&EvidenceFrame>,
) -> Result<Vec<EvidenceFrame>, String> {
    if !table_exists(conn, "ui_events")? {
        return Ok(Vec::new());
    }
    let has_app_name = column_exists(conn, "ui_events", "app_name")?;
    let has_app_bundle_id = column_exists(conn, "ui_events", "app_bundle_id")?;
    let has_window_title = column_exists(conn, "ui_events", "window_title")?;
    let app_expr = if has_app_name { "app_name" } else { "NULL" };
    let bundle_expr = if has_app_bundle_id {
        "app_bundle_id"
    } else {
        "NULL"
    };
    let window_expr = if has_window_title {
        "window_title"
    } else {
        "NULL"
    };
    let limit = request.limit.unwrap_or(300).clamp(1, 2_000);
    let max_ts_cutoff = request.lookback_ms.and_then(|lookback| {
        if lookback > 0 {
            conn.query_row("SELECT MAX(ts_ms) FROM ui_events", [], |row| {
                row.get::<_, Option<i64>>(0)
            })
            .ok()
            .flatten()
            .map(|max_ts| max_ts - lookback)
        } else {
            None
        }
    });
    let sql = format!(
        "SELECT id, ts_ms, event_type, key_category, {}, {}, {}
         FROM (
           SELECT id, ts_ms, event_type, key_category, {}, {}, {}
           FROM ui_events
           WHERE (?1 IS NULL OR session_id = ?1)
             AND (?2 IS NULL OR ts_ms >= ?2)
           ORDER BY ts_ms DESC
           LIMIT ?3
         )
         ORDER BY ts_ms ASC",
        app_expr, bundle_expr, window_expr, app_expr, bundle_expr, window_expr
    );
    let mut stmt = conn.prepare(&sql).map_err(to_string)?;
    let rows = stmt
        .query_map(
            params![request.session_id.as_deref(), max_ts_cutoff, limit],
            |row| {
                Ok(EventEvidenceRow {
                    id: row.get(0)?,
                    ts_ms: row.get(1)?,
                    event_type: row.get(2)?,
                    key_category: row.get(3)?,
                    app_name: row.get(4)?,
                    app_bundle_id: row.get(5)?,
                    window_title: row.get(6)?,
                })
            },
        )
        .map_err(to_string)?;
    let rows = rows.collect::<Result<Vec<_>, _>>().map_err(to_string)?;
    Ok(event_rows_to_evidence_frames(
        &rows,
        request.session_id.clone(),
        latest_frame,
    ))
}

fn event_rows_to_evidence_frames(
    rows: &[EventEvidenceRow],
    session_id: Option<String>,
    latest_frame: Option<&EvidenceFrame>,
) -> Vec<EvidenceFrame> {
    let mut frames = Vec::new();
    let mut previous_bucket: Option<(String, String, String, i64)> = None;
    let mut previous_frame_id = latest_frame.map(|frame| frame.id.clone());
    for row in rows {
        let signal = event_signal_kind(&row.event_type, row.key_category.as_deref());
        if signal == "noise" {
            continue;
        }
        let app = clean_event_label(row.app_name.as_deref());
        let window = clean_event_label(row.window_title.as_deref());
        let same_bucket = previous_bucket
            .as_ref()
            .map(|(prev_signal, prev_app, prev_window, prev_ts)| {
                prev_signal == &signal
                    && prev_app.eq_ignore_ascii_case(&app)
                    && prev_window.eq_ignore_ascii_case(&window)
                    && row.ts_ms.saturating_sub(*prev_ts) <= 30_000
            })
            .unwrap_or(false);
        if same_bucket {
            previous_bucket = Some((signal, app, window, row.ts_ms));
            continue;
        }
        let id_seed = format!(
            "{}:{}:{}:{}:{}",
            session_id.as_deref().unwrap_or(""),
            row.ts_ms,
            row.id,
            signal,
            app
        );
        let id = format!("event-{}", stable_hash(id_seed.as_bytes()));
        let summary = event_evidence_summary(&signal, &app, &window);
        let content_hash = stable_hash(summary.as_bytes());
        frames.push(EvidenceFrame {
            id: id.clone(),
            captured_at: row.ts_ms,
            app_name: if app.is_empty() {
                None
            } else {
                Some(app.clone())
            },
            window_name: if window.is_empty() {
                None
            } else {
                Some(window.clone())
            },
            browser_url: None,
            document_path: None,
            capture_trigger: format!("event_signal_{}", signal),
            text_source: Some("event".to_string()),
            scope: None,
            window_id: None,
            active_window_crop_path: None,
            full_text: Some(summary),
            active_text: None,
            background_text: None,
            full_text_quality: None,
            text_quality_flags: Vec::new(),
            content_hash: Some(content_hash),
            image_hash: None,
            privacy_status: None,
            app_bundle_id: row.app_bundle_id.clone(),
            previous_frame_id,
            session_id: session_id.clone(),
            app_contexts: Vec::new(),
            content_units: Vec::new(),
            ocr_spans: Vec::new(),
            visible_windows: Vec::new(),
            ui_events: vec![EvidenceUiEvent {
                id: row.id.clone(),
                ts_ms: Some(row.ts_ms),
                event_type: row.event_type.clone(),
                key_category: row.key_category.clone(),
            }],
            trigger: Some(EvidenceTrigger {
                id: format!("event-trigger-{}", stable_hash(row.id.as_bytes())),
                trigger_type: format!("event_signal_{}", signal),
                caused_by_event_ids: vec![row.id.clone()],
            }),
            transition: None,
            frame_diff: None,
            typing_bursts: Vec::new(),
            clipboard_events: Vec::new(),
            focused_node_evidence: false,
            selected_text_present: false,
        });
        previous_frame_id = Some(id);
        previous_bucket = Some((signal, app, window, row.ts_ms));
        if frames.len() >= 64 {
            break;
        }
    }
    frames
}

fn event_signal_kind(event_type: &str, key_category: Option<&str>) -> String {
    match event_type {
        "key_down" => match key_category.unwrap_or("") {
            "character" => "typing".to_string(),
            "enter" | "return" => "commit_key".to_string(),
            "shortcut" => "shortcut".to_string(),
            other if !other.trim().is_empty() => format!("key_{}", normalize_token(other)),
            _ => "key_down".to_string(),
        },
        "scroll" => "scroll".to_string(),
        "click" => "click".to_string(),
        "app_switch" => "app_switch".to_string(),
        "ax_notification" => "accessibility".to_string(),
        other if other.trim().is_empty() => "noise".to_string(),
        other => normalize_token(other),
    }
}

fn clean_event_label(value: Option<&str>) -> String {
    value
        .unwrap_or("")
        .split_whitespace()
        .collect::<Vec<_>>()
        .join(" ")
}

fn event_evidence_summary(signal: &str, app: &str, window: &str) -> String {
    let surface = [app, window]
        .into_iter()
        .filter(|value| !value.trim().is_empty())
        .collect::<Vec<_>>()
        .join(" / ");
    if surface.is_empty() {
        format!("Local event signal: {}", signal)
    } else {
        format!("Local event signal: {} in {}", signal, surface)
    }
}

fn query_evidence_frame_rows(
    conn: &Connection,
    where_clause: &str,
    values: &[&dyn rusqlite::ToSql],
) -> Result<Vec<EvidenceFrame>, String> {
    let sql = format!(
        "SELECT * FROM (
            SELECT f.id, f.captured_at, f.app_name, f.window_name, f.browser_url,
                   f.document_path, f.capture_trigger, f.text_source, f.full_text,
                   f.content_hash, f.image_hash, f.privacy_status, f.app_bundle_id,
                   f.previous_frame_id, f.session_id
            FROM frames f
            {}
            ORDER BY f.captured_at DESC, f.id DESC
            LIMIT ?{}
         ) recent
         ORDER BY captured_at ASC, id ASC",
        where_clause,
        values.len()
    );
    let bind_values = values.to_vec();
    let mut stmt = conn.prepare(&sql).map_err(to_string)?;
    let rows = stmt
        .query_map(&bind_values[..], evidence_frame_from_row)
        .map_err(to_string)?;
    rows.collect::<Result<Vec<_>, _>>().map_err(to_string)
}

fn evidence_frame_from_row(row: &Row<'_>) -> rusqlite::Result<EvidenceFrame> {
    let id: i64 = row.get(0)?;
    Ok(EvidenceFrame {
        id: id.to_string(),
        captured_at: row.get(1)?,
        app_name: row.get(2)?,
        window_name: row.get(3)?,
        browser_url: row.get(4)?,
        document_path: row.get(5)?,
        capture_trigger: row.get(6)?,
        text_source: row.get(7)?,
        scope: None,
        window_id: None,
        active_window_crop_path: None,
        full_text: row.get(8)?,
        active_text: None,
        background_text: None,
        full_text_quality: None,
        text_quality_flags: Vec::new(),
        content_hash: row.get(9)?,
        image_hash: row.get(10)?,
        privacy_status: row.get(11)?,
        app_bundle_id: row.get(12)?,
        previous_frame_id: row.get(13)?,
        session_id: row.get(14)?,
        app_contexts: Vec::new(),
        content_units: Vec::new(),
        ocr_spans: Vec::new(),
        visible_windows: Vec::new(),
        ui_events: Vec::new(),
        trigger: None,
        transition: None,
        frame_diff: None,
        typing_bursts: Vec::new(),
        clipboard_events: Vec::new(),
        focused_node_evidence: false,
        selected_text_present: false,
    })
}

fn load_frame_capture_attribution(
    conn: &Connection,
    frame: &mut EvidenceFrame,
) -> Result<(), String> {
    if column_exists(conn, "frames", "scope")? {
        frame.scope = conn
            .query_row(
                "SELECT scope FROM frames WHERE CAST(id AS TEXT) = ?1",
                params![frame.id],
                |row| row.get(0),
            )
            .optional()
            .map_err(to_string)?
            .flatten();
    }
    if column_exists(conn, "frames", "window_id")? {
        frame.window_id = conn
            .query_row(
                "SELECT window_id FROM frames WHERE CAST(id AS TEXT) = ?1",
                params![frame.id],
                |row| row.get(0),
            )
            .optional()
            .map_err(to_string)?
            .flatten();
    }
    if column_exists(conn, "frames", "active_window_crop_path")? {
        frame.active_window_crop_path = conn
            .query_row(
                "SELECT active_window_crop_path FROM frames WHERE CAST(id AS TEXT) = ?1",
                params![frame.id],
                |row| row.get(0),
            )
            .optional()
            .map_err(to_string)?
            .flatten();
    }
    if table_exists(conn, "frame_text_resolutions")? {
        if let Some((active_text, background_text, full_text_quality, quality_flags_json)) = conn
            .query_row(
                "SELECT active_text, background_text, full_text_quality, quality_flags_json
                 FROM frame_text_resolutions
                 WHERE frame_id = ?1",
                params![frame.id],
                |row| {
                    Ok((
                        row.get::<_, Option<String>>(0)?,
                        row.get::<_, Option<String>>(1)?,
                        row.get::<_, Option<String>>(2)?,
                        row.get::<_, Option<String>>(3)?,
                    ))
                },
            )
            .optional()
            .map_err(to_string)?
        {
            frame.active_text = active_text;
            frame.background_text = background_text;
            frame.full_text_quality = full_text_quality;
            frame.text_quality_flags =
                parse_string_array(quality_flags_json.as_deref().unwrap_or("[]"));
        }
    }
    Ok(())
}

