    #[test]
    fn stale_frame_fallback_without_direct_opener_cannot_be_primary() {
        let mut stale_target = test_artifact("artifact-stale", "finder", "Downloads");
        stale_target.document_path = None;
        stale_target.browser_url = None;
        stale_target.openability = "frame_fallback".to_string();
        stale_target.last_seen_timestamp = 1_000;
        let mut fresh_target = test_artifact("artifact-fresh", "code_editor", "lib.rs");
        fresh_target.last_seen_timestamp = 25 * 60 * 1000;
        let stale_action = test_action(&stale_target.id, "encountering_error");
        let fresh_action = test_action(&fresh_target.id, "editing");
        let mut stale_workstream = test_workstream(
            stale_target.clone(),
            "primary_target",
            Some(stale_action.clone()),
            None,
        );
        stale_workstream.id = "workstream-stale".to_string();
        stale_workstream.last_active_timestamp_ms = 1_000;
        stale_workstream.unresolved_signal = Some("visible_error_or_failure".to_string());
        let mut fresh_workstream = test_workstream(
            fresh_target.clone(),
            "primary_target",
            Some(fresh_action.clone()),
            None,
        );
        fresh_workstream.id = "workstream-fresh".to_string();
        fresh_workstream.last_active_timestamp_ms = 25 * 60 * 1000;
        fresh_workstream.unresolved_signal = None;
        let focus = ContinueFocusSummary {
            frame_id: "25".to_string(),
            artifact_id: Some(fresh_target.id.clone()),
            artifact_kind: Some("code_editor".to_string()),
            app_name: Some("Cursor".to_string()),
            window_title: Some("lib.rs".to_string()),
            title: Some("lib.rs".to_string()),
            browser_url: None,
            document_path: fresh_target.document_path.clone(),
            captured_at_ms: 25 * 60 * 1000,
        };
        let mut stale_candidate = test_candidate(
            "resolve_error",
            Some(stale_target),
            Some(stale_action),
            None,
        );
        stale_candidate.id = "candidate-stale".to_string();
        stale_candidate.workstream_id = "workstream-stale".to_string();
        let mut fresh_candidate = test_candidate(
            "continue_edit",
            Some(fresh_target),
            Some(fresh_action),
            None,
        );
        fresh_candidate.id = "candidate-fresh".to_string();
        fresh_candidate.workstream_id = "workstream-fresh".to_string();
        let mut candidates = vec![stale_candidate, fresh_candidate];

        score_continue_candidates(
            &mut candidates,
            &[stale_workstream, fresh_workstream],
            Some(&focus),
            None,
        );

        let stale = candidates
            .iter()
            .find(|candidate| candidate.id == "candidate-stale")
            .unwrap();
        assert!(!stale.eligible_for_primary_selection);
        assert!(stale.score <= 0.40);
        assert!(stale
            .score_caps_applied
            .contains(&"score_capped:stale_frame_fallback_no_direct_target".to_string()));
    }

    #[test]
    fn strong_evidence_passes_quality_gate() {
        let target = test_artifact("artifact-main", "code_editor", "continuation.rs");
        let action = test_action(&target.id, "editing");
        let open_loop = test_open_loop(&target.id, "search_branch_without_return");
        let workstream = test_workstream(
            target.clone(),
            "primary_target",
            Some(action.clone()),
            Some(open_loop.clone()),
        );
        let candidate = test_candidate(
            "return_to_primary_artifact",
            Some(target),
            Some(action),
            Some(open_loop),
        );

        let gate = quality_gate_for_test(&candidate, Some(&workstream));

        assert!(matches!(
            gate.output_mode,
            ContinueOutputMode::StrongContinue | ContinueOutputMode::ThinContinue
        ));
        if gate.output_mode == ContinueOutputMode::StrongContinue {
            assert!(gate.last_state_specific);
            assert!(gate.next_action_specific);
        }
        assert!(gate.target_grounded);
        assert!(gate.evidence_has_content_delta);
    }

    #[test]
    fn weak_evidence_cannot_produce_confident_next_action() {
        let candidate = test_candidate("evidence_only", None, None, None);

        let gate = quality_gate_for_test(&candidate, None);

        assert_eq!(gate.output_mode, ContinueOutputMode::NoClearContinuation);
        assert!(!gate.next_action_specific);
        let handoff = compose_continue_handoff(
            None,
            None,
            Some(&candidate),
            Some("Return and continue editing confidently."),
            0.8,
            &candidate.missing_evidence,
            &candidate.warnings,
            &[],
            None,
            Some(&gate),
            &gate.output_mode,
            None,
        );
        assert_eq!(handoff.confidence_label, "Thin");
        assert!(handoff
            .last_state_line
            .contains("not have enough local evidence"));
    }

    #[test]
    fn thin_gemini_focus_handoff_does_not_expose_candidate_id() {
        let mut candidate = test_candidate("resolve_error", None, None, None);
        candidate.id = "continue-candidate-6afa36c62303d2af".to_string();
        candidate.score = 0.39;
        candidate.evidence_quality_score = 0.2;
        candidate.missing_evidence = vec!["frame_fallback".to_string()];
        let focus = ContinueFocusSummary {
            frame_id: "1658".to_string(),
            artifact_id: Some("artifact-focus".to_string()),
            artifact_kind: Some("browser_tab".to_string()),
            app_name: Some("Helium".to_string()),
            window_title: Some(
                "Napoleon's Fearful Presence on Battlefield - Google Gemini - Helium".to_string(),
            ),
            title: Some(
                "Napoleon's Fearful Presence on Battlefield - Google Gemini - Helium".to_string(),
            ),
            browser_url: None,
            document_path: None,
            captured_at_ms: 1_658,
        };

        let handoff = compose_continue_handoff(
            Some(&focus),
            None,
            Some(&candidate),
            Some("Inspect the smalltalk target and address the visible failure."),
            0.39,
            &candidate.missing_evidence,
            &candidate.warnings,
            &[],
            None,
            None,
            &ContinueOutputMode::ThinContinue,
            None,
        );

        let joined = format!(
            "{} {} {} {} {}",
            handoff.headline,
            handoff.return_line,
            handoff.current_focus_line,
            handoff.last_state_line,
            handoff.user_visible_uncertainty.clone().unwrap_or_default()
        );
        assert!(!joined.contains("continue-candidate-"));
        assert!(!joined.to_lowercase().contains("target metadata"));
        assert!(handoff.return_line.contains("No reliable return target"));
        assert!(handoff
            .user_visible_uncertainty
            .as_deref()
            .unwrap_or("")
            .contains("Gemini chat"));
    }

