    #[test]
    fn evidence_pack_v2_redacts_urls_paths_and_sensitive_tokens() {
        let mut target = test_artifact(
            "artifact-main",
            "code_editor",
            "https://example.com/private /Users/me/project/src/lib.rs sk-test-token",
        );
        target.browser_url = Some("https://example.com/private?token=secret".to_string());
        target.document_path = Some("/Users/me/project/src/lib.rs".to_string());
        let mut action = test_action(&target.id, "editing");
        action.semantic_evidence_quote = Some(
            "Edited /Users/me/project/src/lib.rs after reading https://example.com/private sk-test"
                .to_string(),
        );
        let candidate = test_candidate("continue_edit", Some(target), Some(action), None);

        let pack = build_candidate_evidence_pack_v2(&candidate, None, None);
        let serialized = serde_json::to_string(&pack).unwrap();

        assert!(pack.schema.ends_with(".v2"));
        assert!(!serialized.contains("https://example.com/private"));
        assert!(!serialized.contains("/Users/me/project"));
        assert!(!serialized.contains("sk-test"));
        assert!(serialized.contains("[locator]"));
        assert!(serialized.contains("[redacted]"));
    }

    fn init_evidence_schema(conn: &Connection) {
        conn.execute_batch(
            "
            CREATE TABLE frames (
              id INTEGER PRIMARY KEY,
              session_id TEXT,
              captured_at INTEGER NOT NULL,
              snapshot_path TEXT NOT NULL,
              app_name TEXT,
              window_name TEXT,
              browser_url TEXT,
              document_path TEXT,
              focused INTEGER NOT NULL DEFAULT 1,
              capture_trigger TEXT NOT NULL,
              text_source TEXT,
              scope TEXT,
              window_id INTEGER,
              accessibility_text TEXT,
              accessibility_tree_json TEXT,
              full_text TEXT,
              content_hash TEXT,
              image_hash TEXT,
              created_at INTEGER NOT NULL,
              app_bundle_id TEXT,
              privacy_status TEXT,
              previous_frame_id TEXT,
              active_window_crop_path TEXT
            );
            CREATE TABLE app_contexts (
              id TEXT PRIMARY KEY,
              frame_id TEXT NOT NULL,
              adapter_id TEXT NOT NULL,
              object_type TEXT NOT NULL,
              primary_id TEXT,
              title TEXT,
              url TEXT,
              file_path TEXT,
              repo_path TEXT,
              selected_text TEXT,
              focused_object TEXT,
              confidence REAL
            );
            CREATE TABLE content_units (
              id TEXT PRIMARY KEY,
              frame_id TEXT NOT NULL,
              window_id INTEGER,
              source TEXT NOT NULL,
              unit_type TEXT NOT NULL,
              semantic_role TEXT,
              text TEXT,
              text_hash TEXT,
              ocr_span_ids TEXT,
              bounds_x REAL,
              bounds_y REAL,
              bounds_w REAL,
              bounds_h REAL,
              confidence REAL,
              created_at_ms INTEGER NOT NULL
            );
            CREATE TABLE ocr_spans (
              id TEXT PRIMARY KEY,
              frame_id TEXT NOT NULL,
              engine TEXT NOT NULL,
              text TEXT NOT NULL,
              confidence REAL,
              line_index INTEGER,
              word_index INTEGER,
              bounds_x REAL NOT NULL,
              bounds_y REAL NOT NULL,
              bounds_w REAL NOT NULL,
              bounds_h REAL NOT NULL
            );
            CREATE TABLE window_snapshots (
              id TEXT PRIMARY KEY,
              frame_id TEXT,
              ts_ms INTEGER NOT NULL,
              active_window_id INTEGER,
              active_app_bundle_id TEXT,
              screen_count INTEGER
            );
            CREATE TABLE windows (
              id TEXT PRIMARY KEY,
              window_snapshot_id TEXT NOT NULL,
              cg_window_id INTEGER,
              owner_name TEXT,
              bundle_id TEXT,
              window_title TEXT,
              layer INTEGER,
              alpha REAL,
              is_onscreen INTEGER,
              is_active INTEGER,
              bounds_x REAL,
              bounds_y REAL,
              bounds_w REAL,
              bounds_h REAL
            );
            CREATE TABLE ui_events (
              id TEXT PRIMARY KEY,
              session_id TEXT,
              ts_ms INTEGER NOT NULL,
              event_type TEXT NOT NULL,
              app_bundle_id TEXT,
              app_name TEXT,
              window_title TEXT,
              key_category TEXT,
              created_at_ms INTEGER NOT NULL
            );
            CREATE TABLE ax_nodes (
              id TEXT PRIMARY KEY,
              frame_id TEXT NOT NULL,
              focused INTEGER,
              selected_text TEXT
            );
            CREATE TABLE capture_triggers (
              id TEXT PRIMARY KEY,
              session_id TEXT,
              ts_ms INTEGER NOT NULL,
              trigger_type TEXT NOT NULL,
              caused_by_event_ids TEXT NOT NULL,
              pre_frame_id TEXT,
              post_frame_id TEXT,
              status TEXT
            );
            CREATE TABLE event_transitions (
              id TEXT PRIMARY KEY,
              session_id TEXT,
              trigger_id TEXT NOT NULL,
              primary_event_id TEXT,
              pre_frame_id TEXT,
              post_frame_id TEXT,
              ts_start_ms INTEGER NOT NULL,
              ts_end_ms INTEGER NOT NULL,
              transition_type TEXT,
              confidence REAL,
              summary TEXT
            );
            CREATE TABLE frame_diffs (
              id TEXT PRIMARY KEY,
              session_id TEXT,
              from_frame_id TEXT NOT NULL,
              to_frame_id TEXT NOT NULL,
              ts_ms INTEGER NOT NULL,
              added_text_hashes TEXT,
              removed_text_hashes TEXT,
              diff_type TEXT,
              summary TEXT
            );
            CREATE TABLE typing_bursts (
              id TEXT PRIMARY KEY,
              session_id TEXT,
              started_at_ms INTEGER NOT NULL,
              ended_at_ms INTEGER NOT NULL,
              enter_count INTEGER DEFAULT 0,
              paste_count INTEGER DEFAULT 0,
              committed INTEGER DEFAULT 0,
              commit_signal TEXT,
              pre_frame_id TEXT,
              post_frame_id TEXT
            );
            CREATE TABLE clipboard_events (
              id TEXT PRIMARY KEY,
              session_id TEXT,
              ts_ms INTEGER NOT NULL,
              change_count INTEGER NOT NULL,
              content_type TEXT NOT NULL,
              text_hash TEXT,
              redacted_preview TEXT,
              source_frame_id TEXT,
              target_frame_id TEXT
            );
            ",
        )
        .unwrap();
        ensure_continue_schema(conn).unwrap();
    }

    #[allow(clippy::too_many_arguments)]
    fn insert_frame(
        conn: &Connection,
        id: i64,
        app_name: &str,
        window_name: &str,
        browser_url: Option<&str>,
        document_path: Option<&str>,
        trigger: &str,
        full_text: &str,
        bundle_id: Option<&str>,
        previous_frame_id: Option<i64>,
    ) {
        conn.execute(
            "INSERT INTO frames (
                id, session_id, captured_at, snapshot_path, app_name, window_name,
                browser_url, document_path, capture_trigger, text_source, full_text,
                content_hash, image_hash, created_at, app_bundle_id, privacy_status,
                previous_frame_id, scope, window_id, active_window_crop_path
             ) VALUES (?1, 'session-a', ?2, '/tmp/frame.jpg', ?3, ?4, ?5, ?6,
                       ?7, 'accessibility', ?8, ?9, ?10, ?2, ?11, 'normal', ?12,
                       'active_window', ?13, '/tmp/active-window.jpg')",
            params![
                id,
                id * 1000,
                app_name,
                window_name,
                browser_url,
                document_path,
                trigger,
                full_text,
                stable_hash(full_text.as_bytes()),
                format!("image-{}", id),
                bundle_id,
                previous_frame_id.map(|value| value.to_string()),
                id,
            ],
        )
        .unwrap();
        conn.execute(
            "INSERT INTO ax_nodes (id, frame_id, focused, selected_text)
             VALUES (?1, ?2, 1, NULL)",
            params![format!("ax-{}", id), id.to_string()],
        )
        .unwrap();
    }

