    #[test]
    fn codex_goal_achieved_output_becomes_review_completed_work() {
        let conn = Connection::open_in_memory().unwrap();
        init_evidence_schema(&conn);
        insert_frame(
            &conn,
            1,
            "Codex",
            "Smalltalk Continue implementation",
            None,
            None,
            "manual",
            "Implemented observe_before_decide. Edited 3 files. cargo check passed. cargo test continue passed. npm run build built. Goal achieved.",
            Some("com.openai.codex"),
            None,
        );
        insert_context(&conn, 1, "chat_conversation", "Codex", None, None, None);
        insert_unit(
            &conn,
            1,
            "output",
            "terminal_output",
            "cargo check passed. cargo test continue passed. npm run build built. Goal achieved.",
        );

        rebuild_second_and_third(&conn);

        let (state, boundary, progress): (String, String, String) = conn
            .query_row(
                "SELECT state, boundary_kind, COALESCE(last_concrete_progress, '')
                 FROM continue_open_loops
                 LIMIT 1",
                [],
                |row| Ok((row.get(0)?, row.get(1)?, row.get(2)?)),
            )
            .unwrap();
        assert_eq!(state, "resolved");
        assert_eq!(boundary, "completed_progress");
        assert!(progress.contains("Goal achieved") || progress.contains("Tests passed"));

        let decision = generate_local_decision(&conn);
        assert_eq!(
            decision.candidate_kind.as_deref(),
            Some("review_completed_changes")
        );
        assert!(decision
            .next_action
            .as_deref()
            .unwrap_or_default()
            .contains("Review the completed changes"));
        assert_eq!(decision.handoff.headline, "Review completed work");
    }

    fn distinct_episode_count_for_frames(conn: &Connection, frame_ids: &[&str]) -> i64 {
        let quoted = frame_ids
            .iter()
            .map(|frame_id| format!("'{}'", frame_id))
            .collect::<Vec<_>>()
            .join(",");
        conn.query_row(
            &format!(
                "SELECT COUNT(DISTINCT ea.episode_id)
                 FROM continue_episode_actions ea
                 JOIN continue_task_actions ta ON ta.id = ea.action_id
                 WHERE ta.frame_id IN ({})",
                quoted
            ),
            [],
            |row| row.get(0),
        )
        .unwrap()
    }

    #[test]
    fn continue_rebuild_uses_event_only_moments_without_new_frames() {
        let conn = Connection::open_in_memory().unwrap();
        init_evidence_schema(&conn);
        for (index, (ts, event_type, app, bundle, window, key_category)) in [
            (
                1_000,
                "app_switch",
                "Helium",
                "app.helium",
                "Smalltalk direction",
                None,
            ),
            (
                1_500,
                "scroll",
                "Helium",
                "app.helium",
                "Smalltalk direction",
                None,
            ),
            (
                40_000,
                "key_down",
                "Codex",
                "com.openai.codex",
                "smalltalk",
                Some("character"),
            ),
            (
                80_000,
                "click",
                "smalltalk",
                "com.smalltalk.app",
                "smalltalk",
                None,
            ),
        ]
        .into_iter()
        .enumerate()
        {
            conn.execute(
                "INSERT INTO ui_events (
                    id, session_id, ts_ms, event_type, app_bundle_id, app_name,
                    window_title, key_category, created_at_ms
                 ) VALUES (?1, 'session-events', ?2, ?3, ?4, ?5, ?6, ?7, ?2)",
                params![
                    format!("evt-event-only-{}", index),
                    ts,
                    event_type,
                    bundle,
                    app,
                    window,
                    key_category,
                ],
            )
            .unwrap();
        }

        let result = rebuild_continue_second_layer(
            &conn,
            ContinueSecondLayerRebuildRequest {
                session_id: Some("session-events".to_string()),
                limit: Some(50),
                ..Default::default()
            },
        )
        .unwrap();

        let frame_rows: i64 = conn
            .query_row("SELECT COUNT(*) FROM frames", [], |row| row.get(0))
            .unwrap();
        let event_observations: i64 = conn
            .query_row(
                "SELECT COUNT(*)
                 FROM continue_artifact_observations
                 WHERE frame_id LIKE 'event-%'",
                [],
                |row| row.get(0),
            )
            .unwrap();
        let event_actions: i64 = conn
            .query_row(
                "SELECT COUNT(*)
                 FROM continue_task_actions
                 WHERE frame_id LIKE 'event-%'",
                [],
                |row| row.get(0),
            )
            .unwrap();

        assert_eq!(frame_rows, 0);
        assert!(result.processed_frames > 1, "{:?}", result);
        assert_eq!(event_observations, result.observation_count);
        assert!(event_actions > 0);
    }

