    #[test]
    fn normal_continue_mode_reuses_cached_decision_without_growth() {
        let conn = Connection::open_in_memory().unwrap();
        init_evidence_schema(&conn);

        insert_frame(
            &conn,
            1,
            "Cursor",
            "lib.rs - smalltalk",
            None,
            Some("/Users/me/project/src/lib.rs"),
            "typing_pause",
            "fn continue_work() { changed(); }",
            Some("com.todesktop.230313mzl4w4u92"),
            None,
        );
        insert_context(
            &conn,
            1,
            "code_editor",
            "lib.rs",
            None,
            Some("/Users/me/project/src/lib.rs"),
            None,
        );
        insert_typing(&conn, 1, 0, 0);

        let rebuild = get_continue_decision(
            &conn,
            ContinueDecisionRequest {
                session_id: Some("session-a".to_string()),
                mode: Some("rebuild".to_string()),
                rebuild_layers: Some(false),
                micro_inference_enabled: Some(false),
                ..Default::default()
            },
        )
        .unwrap();
        assert_eq!(rebuild.mode, "rebuild");
        assert!(!rebuild.cache_hit);

        let normal = get_continue_decision(
            &conn,
            ContinueDecisionRequest {
                session_id: Some("session-a".to_string()),
                mode: Some("normal".to_string()),
                rebuild_layers: Some(false),
                micro_inference_enabled: Some(false),
                ..Default::default()
            },
        )
        .unwrap();
        assert_eq!(normal.mode, "normal");
        assert!(normal.cache_hit);
        assert_eq!(normal.decision_id, rebuild.decision_id);

        let persisted: i64 = conn
            .query_row("SELECT COUNT(*) FROM continue_decisions", [], |row| {
                row.get(0)
            })
            .unwrap();
        assert_eq!(persisted, 1);
        let (watermark_json, watermark_hash, boundary_revision): (
            Option<String>,
            Option<String>,
            Option<i64>,
        ) = conn
            .query_row(
                "SELECT evidence_watermark_json, evidence_watermark_hash,
                        latest_boundary_revision
                 FROM continue_decisions
                 WHERE id = ?1",
                params![normal.decision_id],
                |row| Ok((row.get(0)?, row.get(1)?, row.get(2)?)),
            )
            .unwrap();
        assert!(watermark_json.is_some());
        assert_eq!(
            watermark_hash.as_deref(),
            Some(normal.evidence_watermark_hash.as_str())
        );
        assert_eq!(boundary_revision, normal.latest_boundary_revision);

        let cached_requested_at: i64 = conn
            .query_row(
                "SELECT requested_at_ms FROM continue_decisions WHERE id = ?1",
                params![normal.decision_id],
                |row| row.get(0),
            )
            .unwrap();
        conn.execute(
            "INSERT INTO continue_semantic_moments (
                id, started_at_ms, ended_at_ms, dominant_event_type,
                ordered_event_ids_json, causal_chain_json, boundary_kind,
                should_invalidate_continue, should_force_semantic_snapshot,
                evidence_quality, created_at_ms
             ) VALUES (
                'semantic-moment-cache-invalidator', ?1, ?2, 'typing',
                '[]', '[\"typing\"]', 'same_surface_progress',
                1, 1, 'medium', ?2
             )",
            params![cached_requested_at, cached_requested_at + 1],
        )
        .unwrap();

        let invalidated = get_continue_decision(
            &conn,
            ContinueDecisionRequest {
                session_id: Some("session-a".to_string()),
                mode: Some("normal".to_string()),
                rebuild_layers: Some(false),
                micro_inference_enabled: Some(false),
                ..Default::default()
            },
        )
        .unwrap();
        assert!(!invalidated.cache_hit);
    }

    #[test]
    fn default_micro_inference_missing_key_falls_back_and_caches() {
        if continue_openai_config(None)
            .unwrap()
            .api_key
            .as_deref()
            .is_some()
        {
            return;
        }

        let conn = Connection::open_in_memory().unwrap();
        init_evidence_schema(&conn);

        insert_frame(
            &conn,
            1,
            "Cursor",
            "lib.rs - smalltalk",
            None,
            Some("/Users/me/project/src/lib.rs"),
            "typing_pause",
            "fn continue_work() { changed(); }",
            Some("com.todesktop.230313mzl4w4u92"),
            None,
        );
        insert_context(
            &conn,
            1,
            "code_editor",
            "lib.rs",
            None,
            Some("/Users/me/project/src/lib.rs"),
            None,
        );
        insert_typing(&conn, 1, 0, 0);

        let first = get_continue_decision(
            &conn,
            ContinueDecisionRequest {
                session_id: Some("session-a".to_string()),
                mode: Some("rebuild".to_string()),
                rebuild_layers: Some(false),
                ..Default::default()
            },
        )
        .unwrap();
        assert!(!first.cache_hit);
        assert_eq!(first.source, "local_fallback");
        assert!(first.response_id.is_none());
        assert!(first
            .validation_failures
            .iter()
            .any(|failure| failure == "OPENAI_API_KEY is not set"));

        let cached = get_continue_decision(
            &conn,
            ContinueDecisionRequest {
                session_id: Some("session-a".to_string()),
                mode: Some("normal".to_string()),
                rebuild_layers: Some(false),
                ..Default::default()
            },
        )
        .unwrap();
        assert!(cached.cache_hit);
        assert_eq!(cached.decision_id, first.decision_id);
        assert_eq!(cached.source, "local_fallback");
        assert_eq!(cached.model, first.model);
        assert_eq!(cached.response_id, first.response_id);
        assert_eq!(cached.validation_status, first.validation_status);
        assert_eq!(cached.handoff.headline, first.handoff.headline);

        let persisted: i64 = conn
            .query_row("SELECT COUNT(*) FROM continue_decisions", [], |row| {
                row.get(0)
            })
            .unwrap();
        assert_eq!(persisted, 1);
    }

