    #[test]
    fn continue_decision_uses_evidence_only_for_thin_unknown_surface() {
        let conn = Connection::open_in_memory().unwrap();
        init_evidence_schema(&conn);

        insert_frame(
            &conn,
            1,
            "GenericApp",
            "Unknown",
            None,
            None,
            "manual",
            "",
            None,
            None,
        );

        let decision = get_continue_decision(
            &conn,
            ContinueDecisionRequest {
                session_id: Some("session-a".to_string()),
                lookback_ms: None,
                limit: Some(20),
                rebuild_layers: Some(true),
                micro_inference_enabled: Some(false),
                ..Default::default()
            },
        )
        .unwrap();

        assert_eq!(decision.candidate_kind.as_deref(), Some("evidence_only"));
        assert_eq!(decision.validation_status, "fallback");
        assert!(decision
            .missing_evidence
            .iter()
            .any(|item| item == "no_last_meaningful_action"));
        assert!(decision
            .warnings
            .iter()
            .any(|warning| warning == "thin_evidence"));
    }

    #[test]
    fn continue_eval_default_fixture_reports_required_metrics() {
        let report = run_continue_eval(None).unwrap();

        assert_eq!(report.schema, "smalltalk.continue_eval.v1");
        assert_eq!(report.case_count, 46);
        assert_eq!(report.target_artifact_correct, 46);
        assert_eq!(report.recall_at_k, 1.0);
        assert_eq!(report.mrr, 1.0);
        assert_eq!(report.hallucinated_artifact_count, 1);
        assert_eq!(report.model_validation_fallback_rate, 0.07);
        assert_eq!(report.fresh_surface_retention_rate, 1.0);
        assert_eq!(report.stale_target_suppression_rate, 1.0);
        assert_eq!(report.support_branch_false_promotion_rate, 0.0);
        assert_eq!(report.support_branch_false_positive_rate, 0.0);
        assert_eq!(report.unpromoted_branch_selected_count, 0);
        assert_eq!(report.branch_origin_recall_rate, 1.0);
        assert_eq!(report.promoted_branch_selection_precision, 1.0);
        assert_eq!(report.message_interrupt_false_positive_rate, 0.0);
        assert_eq!(report.diagnostic_self_selected_count, 0);
        assert_eq!(report.model_branch_policy_violation_count, 1);
        assert_eq!(report.truthful_thin_mode_rate, 1.0);
        assert_eq!(report.feedback_obedience_case_count, 7);
        assert_eq!(report.feedback_suppressed_target_exposed_count, 0);
        assert_eq!(report.feedback_suppressed_target_exposed_rate, 0.0);
        assert_eq!(report.corrected_artifact_preferred_count, 1);
        assert_eq!(report.feedback_cache_stale_hit_count, 0);
        assert_eq!(report.model_feedback_validation_failure_count, 1);
        assert_eq!(report.feedback_obedience_placeholder_rate, 1.0);
        assert_eq!(report.suppressed_target_open_attempt_count, 0);
        assert!(report.last_state_specificity > 0.0);
        assert!(report.next_action_specificity > 0.0);
        assert!(report.source_provenance_correctness > 0.0);
        assert!(report.cache_freshness_correctness > 0.0);
        assert!(report
            .cases
            .iter()
            .any(|case| case.scenario == "AI Chat as support"));
        assert!(report
            .cases
            .iter()
            .any(|case| case.scenario == "Nested dependent task"));
        assert!(report.cases.iter().any(|case| case.name
            == "p1_event_only_boundary_invalidates_cache"
            && case.cache_freshness_correctness));
        assert!(report.cases.iter().any(|case| case.name
            == "p1_micro_inference_fallback_invalid_candidate"
            && case.validation_status == "fallback"));
        assert!(report.cases.iter().any(|case| case.name
            == "p2_model_selects_unpromoted_branch_rejected"
            && case.validation_status == "fallback"
            && case.model_branch_policy_violation));
        assert!(report.cases.iter().any(|case| case.name
            == "p2_gmail_compose_promoted"
            && case.promoted_branch_selection_correct));
    }

    #[test]
    fn continue_eval_rejects_hallucinated_model_candidate() {
        let fixture = ContinueEvalFixture {
            k: Some(2),
            cases: vec![ContinueEvalCaseFixture {
                name: "bad_model".to_string(),
                scenario: "Thin OCR-only evidence".to_string(),
                expected_target_artifact_id: "known".to_string(),
                current_focus_artifact_id: Some("unknown".to_string()),
                candidates: vec![eval_candidate(
                    "known-candidate",
                    "w",
                    Some("known"),
                    0.72,
                    "strong",
                )],
                model_output: Some(ContinueMicroInferenceOutput {
                    result: "selected_candidate".to_string(),
                    selected_candidate_id: Some("invented-candidate".to_string()),
                    selected_workstream_id: Some("w".to_string()),
                    intent_label: "Invented".to_string(),
                    headline: "Continue an invented target".to_string(),
                    return_line: "Continue from https://invented.example/path".to_string(),
                    current_focus_line: "Current focus is unknown".to_string(),
                    last_state_line: "Last meaningful state is unsupported".to_string(),
                    next_action: Some("Open https://invented.example/path".to_string()),
                    why_this: vec!["Unsupported invented target".to_string()],
                    missing_evidence_line: None,
                    reason: "Unsupported invented target".to_string(),
                    confidence: "high".to_string(),
                    user_visible_uncertainty: None,
                    uncertainty_notes: None,
                    missing_evidence: Vec::new(),
                    recommended_local_capture: None,
                }),
                expected_feedback_obedience_placeholder: None,
                negative_feedback: Vec::new(),
                expected_suppressed_artifact_ids: Vec::new(),
                expected_not_return_target_artifact_ids: Vec::new(),
                expected_feedback_return_target_artifact_id: None,
                expected_validation_status: None,
                corrected_artifact_id: None,
                cached_decision_target_artifact_id: None,
                cache_feedback_newer_than_cached_decision: None,
                model_feedback_validation_failure_expected: None,
            }],
        };

        let report = summarize_continue_eval_fixture(fixture).unwrap();

        assert_eq!(report.hallucinated_artifact_count, 1);
        assert_eq!(report.model_validation_fallback_rate, 1.0);
        assert!(report.cases[0]
            .validation_failures
            .contains(&"selected_candidate_id_not_in_fixture".to_string()));
    }

